-- 자동 생성 파일 (scripts/generate-seed-sql.ts). 06/08
-- 001_ingredients.sql을 먼저 실행한 뒤 순서대로 실행하세요.
insert into public.recipes_cache
  (id, name, category, raw_ingredients_text, parsed_ingredients, matched_ingredient_ids, cooking_steps, image_url,
   nutrition_kcal, nutrition_carb, nutrition_protein, nutrition_fat, nutrition_sodium)
values
  ('913', '대추죽', '일품', '좁쌀 15g, 대추 10g, 깐밤 5g, 찹쌀가루 10g, 물 70g, 소금적당량', '["좁쌀","대추","깐밤","찹쌀가루","물","소금"]'::jsonb, ARRAY['b371c5d2-f12b-47ee-9a87-26efd09db09d','4cb11562-015f-4ab5-969f-0ea8483a0b42','94786475-832c-4f97-aab7-bf6fbbe2236b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"좁쌀을 씻어 불린다.","imageUrl":null},{"step":2,"text":"대추와 깐 밤을 냄비에 넣고 물 4컵을 넣고 대추가 무르도록 삶는다.","imageUrl":null},{"step":3,"text":"삶은 대추를 손으로 주물러 대추 속살이 나오도록 한 뒤 밤과 함께 체에 거른다.","imageUrl":null},{"step":4,"text":"좁쌀은 5배의 물을 부어 저어가면서 익힌다.","imageUrl":null},{"step":5,"text":"3을 4에 넣어 잘 섞은 뒤 찹쌀물을 넣어 농도가 나도록 끓인다.","imageUrl":null},{"step":6,"text":"소금으로 간을 맞추고 준비한 그릇에 담아낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053551_1416213351482.jpg', 132, 29.4, 3, 0.8, 2),
  ('914', '돼지고기 토마토 두부볶음', '반찬', '돼지고기목살 30g, 두부 30g, 토마토 50g, 생강다진것 5g, 파다진것 5g, 땅콩기름 5g, 간장 5g, 닭육수 10g, 물전분 10g, 소금적당량', '["돼지고기목살","두부","토마토","생강다진것","파다진것","땅콩기름","간장","닭육수","물전분","소금"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','f175019d-5a93-4cd4-aabc-e7e79445f15a','a4c37075-c03b-47bb-8aed-5e907620f5d2','6613d1d9-80a2-4ce4-9d3d-647203197e53','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"돼지고기는 깨끗이 손질한 뒤 잘게다진다.","imageUrl":null},{"step":2,"text":"두부는 1cm 정사각형 모양으로 썬다","imageUrl":null},{"step":3,"text":"토마토는 껍질과 씨를 제거한 뒤 두부와 같은 크기로 썬다.","imageUrl":null},{"step":4,"text":"기름을 두른 팬에 파와 생강을 넣고 볶아 향이 나면 1을 넣고 볶은 뒤 따로 담아둔다.","imageUrl":null},{"step":5,"text":"기름을 두른 팬에 토마토, 두부, 고기를 넣고 볶다가 육수를 자작하게 부은 뒤 간장, 소금으로 간을 한다.","imageUrl":null},{"step":6,"text":"소스가 졸아들면 두부를 넣고 물 전분을 넣어 소스 농도를 맞춘다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053552_1416213352435.jpg', 157, 8, 10.1, 9.8, 294),
  ('915', '멜론스프', '일품', '멜론 110g, 오렌지 30g, 레몬 5g, 탄산수 30g, 레몬껍질 2g, 전분 3g, 설탕 5g 멜론,자두,생크림,민트', '["멜론","오렌지","레몬","탄산수","레몬껍질","전분","설탕","자두","생크림","민트"]'::jsonb, ARRAY['19eb37dc-2b1c-4e89-a931-31a38ae60561','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','20a151f5-d44f-48d8-bd67-958886b649d6','6613d1d9-80a2-4ce4-9d3d-647203197e53','06e6f3e7-0293-469d-a338-11a610f3e71b','af187077-b7f6-4b0e-9e99-f844f6359ac2','eb4621c9-6ade-40ba-966c-32edd1754669']::uuid[], '[{"step":1,"text":"메론은 적당한 크기로 잘라 믹서에 간다.","imageUrl":null},{"step":2,"text":"오렌지와 레몬은 과육만 잘라내 믹서에 각각 갈아 주스형태로 만든다.","imageUrl":null},{"step":3,"text":"2에 탄산수, 오렌지껍질, 레몬껍질을 넣어 향이 우러나도록 끓인다.","imageUrl":null},{"step":4,"text":"3에 전분을 넣어 농도를 맞춘 뒤 덩어리지지 않게 체에 걸러 차갑게 식힌다.","imageUrl":null},{"step":5,"text":"1에 4를 넣고 잘 섞은 뒤 설탕으로 맛을 낸다.","imageUrl":null},{"step":6,"text":"생크림을 휘핑해 올리고 자두, 메론, 민트로 장식한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053554_1416213354184.jpg', 86, 21.9, 1.9, 0.2, 22),
  ('916', '미니버거', '일품', '양파다진것 3g, 브로컬리다진것 3g, 당근다진것 3g, 바질다진것 1g, 달걀 6g, 쇠고기다진것 25g, 돼지고기갈은것 10g, 빵가루 5g, 마요네즈 1g, 토마토케첩 1g, 미니,버거빵 12g, 양상추 2g, 토마토 8g, 후추 적당량', '["양파다진것","브로컬리다진것","당근다진것","바질다진것","달걀","쇠고기다진것","돼지고기갈은것","빵가루","마요네즈","토마토케첩","미니","버거빵","양상추","토마토","후추"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','9bf64924-ce53-42bb-849e-7294416e95d6','e38c12a7-43cb-421a-a36e-7ef0d32517fa','ba9e5a79-cab3-4af0-942b-0b35fd745150','c7d438a6-34d6-423f-905d-446b839e2f39','1c49d1f4-5781-474d-818d-bd7002a4dc0b','45080597-55fa-42dc-aa65-12d7694e4b7e','549c7365-28e9-491f-9040-412558f93a5c','0136fc6a-3a80-4f4c-8057-10bbf34ea572','1389717e-81e4-4350-96d4-d627d851aa10','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"바질과 양파, 브로콜리, 당근은 곱게 다진다.","imageUrl":null},{"step":2,"text":"소고기와 돼지고기는 곱게 간다.","imageUrl":null},{"step":3,"text":"2를 1:1 비율로 섞고 1과 달걀, 케첩, 후추, 빵가루와 섞어 패티를 만든다.","imageUrl":null},{"step":4,"text":"미니버거빵의 안쪽 면에 버터를 바른 후 팬에서 살짝 구워준다.","imageUrl":null},{"step":5,"text":"3을 팬에서 갈색이 나도록 익혀준다.","imageUrl":null},{"step":6,"text":"4에 마요네즈를 바르고 양상추, 패티, 케첩, 토마토, 양상추 순으로 올리고 마요네즈를 바른 빵으로 덮는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053555_1416213355495.jpg', 123, 8.4, 10.2, 5.5, 226),
  ('917', '바질 고구마 옥수수빵(플렌타)', '후식', '시금치 10g, 바질 3g, 고구마 30g, 옥수수가루플렌타가루 15g, 파마산치즈 10g, 모짜렐라 치즈 10g', '["시금치","바질","고구마","옥수수가루플렌타가루","파마산치즈","모짜렐라 치즈"]'::jsonb, ARRAY['9a7f4da6-531b-4478-89ff-d73beafcad1b','ba9e5a79-cab3-4af0-942b-0b35fd745150','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c']::uuid[], '[{"step":1,"text":"시금치와 바질을 팬에서 볶다가 소금, 후추로 간한 뒤 모짜렐라 치즈를 넣어 식히고 고구마는 삶아 껍질을 벗긴 뒤 1cm 주사위 모양으로 자른다.","imageUrl":null},{"step":2,"text":"소스팬에 물 2컵반을 넣고 끓이다가 찬물 1컵에 소금을 넣고 섞은 옥수수 가루를 천천히 넣어준다.","imageUrl":null},{"step":3,"text":"다시 끓어오를 때까지 천천히 젓다가 낮은 온도에서 아주 되직해질 때까지 익힌 뒤 파마산 치즈를 넣고 섞는다.","imageUrl":null},{"step":4,"text":"버터를 바른 사기그릇에 3을 절반가량 넣고 그위에 1과 2를 올리고, 남은 반죽을 올려 그릇을 채워 냉장고에서 식힌다.","imageUrl":null},{"step":5,"text":"4가 완전히 굳으면 176℃의 오븐에서 윗면에 갈색이 나도록 40분정도 굽는다.","imageUrl":null},{"step":6,"text":"5를 적당한 크기로 잘라 접시에 담고 기호에 따라 토마토케첩을 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053556_1416213356807.jpg', 161, 23.3, 7.8, 4.6, 229),
  ('918', '밥스틱', '밥', '당근다진것 10g, 양파다진것 15g, 홍피망다진것 10g, 청피망다진것 10g, 햄다진것 10g, 밥 10g, 카레가루 2g, 춘권피 30g, 치즈 5g, 튀김기름 3g, 소금적당량, 후춧가루 적당량', '["당근다진것","양파다진것","홍피망다진것","청피망다진것","햄다진것","밥","카레가루","춘권피","치즈","튀김기름","소금","후춧가루"]'::jsonb, ARRAY['e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','df459e6f-3515-45d5-8c9a-9d37b6249379','ecb35816-34ae-4c4c-867a-e3f84db92755','495b9f1e-aa3b-4506-9bb8-feb0a493901e','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','a7a59e81-de3d-4893-b56a-b2218732a25b','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"당근, 양파, 청피망, 홍피망, 햄은 곱게 다진다.","imageUrl":null},{"step":2,"text":"달군 팬에 1을 넣고 볶는다.","imageUrl":null},{"step":3,"text":"2에 밥을 넣고 볶으면서 카레가루와 소금, 후춧가루로 간을 맞춘다.","imageUrl":null},{"step":4,"text":"치즈는 적당한 크기로 잘라준다.","imageUrl":null},{"step":5,"text":"춘권피에 3과 4를 넣고 스틱 모양으로 만든다.","imageUrl":null},{"step":6,"text":"팬에 기름을 넉넉히 두르고 5를 튀겨준다","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053557_1416213357993.jpg', 219.2, 32.8, 6.1, 7.6, 227),
  ('919', '버섯 리조또', '밥', '쌀 70g, 양송이버섯 15g, 마늘다진것 2g, 닭육수 180g, 파슬리다진것 2g, 타임다진것 0.5, 올리브오일 1.5g, 파마산치즈 3g, 버터 1g, 소금적당량, 후추적당량', '["쌀","양송이버섯","마늘다진것","닭육수","파슬리다진것","타임다진것","올리브오일","파마산치즈","버터","소금","후추"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','fc6e31ce-388e-45cd-956b-b238b9134eb1','a4c37075-c03b-47bb-8aed-5e907620f5d2','4362c386-a37c-44cd-9254-fafd74712a09','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','7aabd532-361f-4240-aa33-6bfa1be4bc4e','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"마늘은 잘게 다지고 양송이 버섯은 2mm 두께로 썬다.","imageUrl":null},{"step":2,"text":"팬에 기름을 두르고 다진 마늘을 볶다가 양송이버섯을 넣고 볶아 접시에 담아둔다.","imageUrl":null},{"step":3,"text":"2의 팬에 쌀을 넣고 볶는다.","imageUrl":null},{"step":4,"text":"3에 닭육수를 넣고 수분을 흡수 할 때까지 잘 젓는다.","imageUrl":null},{"step":5,"text":"쌀이 어느 정도 익으면 2를 넣고 쌀이 완전히 익을 때까지 조리한다.","imageUrl":null},{"step":6,"text":"파마산치즈, 소금, 후추, 다진 타임, 다진 파슬리를 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053339_1416213219624.jpg', 325, 59, 807, 4.9, 125),
  ('920', '버섯 참치 무른밥', '밥', '불린 쌀 30g, 물 92g, 참치살 10g, 표고버섯 5g, 무 5g, 양파 5g, 참기름 2g, 통깨 1g, 소금적당량', '["불린 쌀","물","참치살","표고버섯","무","양파","참기름","통깨","소금"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','94786475-832c-4f97-aab7-bf6fbbe2236b','66458b1b-c92f-43fa-8eba-e428892ce88a','f80c9a7d-1510-44e2-a82b-28b9f684e191','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"불린 쌀은 믹서나 절구를 이용하여 간다.","imageUrl":null},{"step":2,"text":"참치 살, 표고버섯, 무, 양파는 곱게 다진다.","imageUrl":null},{"step":3,"text":"팬에 참기름을 두르고 1과 다진 표고버섯, 무, 양파를 볶는다.","imageUrl":null},{"step":4,"text":"3에 물을 넣어 무른 밥을 짓는다.","imageUrl":null},{"step":5,"text":"4의 밥이 끓어오르면 다진 참치 살을 넣고 저어가며 끓인다.","imageUrl":null},{"step":6,"text":"참치 살이 다 익으면 통깨를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053600_1416213360850.jpg', 145, 23.3, 5.4, 3, 1),
  ('922', '송이 미역국', '국&찌개', '불린 쌀 30g, 양송이버섯 10g, 당근 10g, 양파 3g, 마른미역 5g, 참기름 2g, 물 90g', '["불린 쌀","양송이버섯","당근","양파","마른미역","참기름","물"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','0c0ade94-cfd8-4104-b44c-40e942cac482','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"쌀은 깨끗하게 씻어 불린다.","imageUrl":null},{"step":2,"text":"1을 분쇄기로 살짝 간다.","imageUrl":null},{"step":3,"text":"양송이버섯과 채소를 잘게 다진다.","imageUrl":null},{"step":4,"text":"마른 미역은 30분 정도 불렸다가 잘게 다진다.","imageUrl":null},{"step":5,"text":"냄비에 참기름을 두르고 2를 볶다가 3, 4를 넣고 한번 더 볶는다.","imageUrl":null},{"step":6,"text":"5에 물을 넣은 뒤 쌀알이 퍼지도록 끓인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053603_1416213363580.jpg', 136, 25.7, 4.3, 2.4, 309),
  ('923', '시금치 배 미음', '밥', '불린쌀 30g, 물 90g, 배 25g, 시금치 20g, 꿀 5g', '["불린쌀","물","배","시금치","꿀"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','94786475-832c-4f97-aab7-bf6fbbe2236b','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','9a7f4da6-531b-4478-89ff-d73beafcad1b','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"쌀은 깨끗하게 씻어 불린다.","imageUrl":null},{"step":2,"text":"2를 믹서나 절구로 곱게 갈아 냄비에 물과 함께 넣고 끓인다.","imageUrl":null},{"step":3,"text":"배는 껍질과 씨를 제거하고 강판에 간다.","imageUrl":null},{"step":4,"text":"시금치는 끓는 물에 데친 후 물기를 꼭 짜서 곱게 다진다.","imageUrl":null},{"step":5,"text":"2가 끓어오르면 3,4를 넣고 끓인다.","imageUrl":null},{"step":6,"text":"입맛에 맞게 꿀로 간한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053604_1416213364610.jpg', 137, 30.1, 3.5, 0.4, 12),
  ('925', '어린이 스시', '밥', '밥 120g, 달걀 삶은것 20g, 슬라이스햄 5g, 슬라이스치즈 5g, 양파 3g, 샐러리 3g, 캔참치 3g, 칵테일새우 5g, 날치알 3g, 마요네즈 5g 식초 5g, 설탕 3g, 소금적당량', '["밥","달걀 삶은것","슬라이스햄","슬라이스치즈","양파","샐러리","캔참치","칵테일새우","날치알","마요네즈","설탕","소금"]'::jsonb, ARRAY['ecb35816-34ae-4c4c-867a-e3f84db92755','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','12d2d4c9-705a-47f1-b628-30e042a970f8','6f10b4ad-53a2-4a07-ba89-19a6b074373d','549c7365-28e9-491f-9040-412558f93a5c','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"초대리 재료를 분량대로 섞어 설탕, 소금이 녹을 정도로만 가열해 초대리를 만들어 고슬고슬하게 지은 따듯한 밥에 넣고 섞어 식힌다.","imageUrl":null},{"step":2,"text":"달걀은 삶아 흰자와 노른자로 따로 체에 내려 가루를 만들어 놓는다.","imageUrl":null},{"step":3,"text":"햄, 치즈는 원하는 모양틀로 찍는다.","imageUrl":null},{"step":4,"text":"기름을 제거한 참치에 다진 양파와 셀러리, 마요네즈를 섞는다.","imageUrl":null},{"step":5,"text":"칵테일 새우는 데쳐서 식힌다.","imageUrl":null},{"step":6,"text":"모양틀에 밥을 찍어내고 그 위에 준비한 재료들을 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053608_1416213368763.jpg', 135, 11.3, 6.7, 6.4, 200),
  ('926', '에멘탈 치즈 퐁듀', '후식', '에멘탈 치즈 20g, 마늘 2g, 넉맥약간, 닭육수 30g,물전분 2g, 바케트빵 6g, 방울토마토 30g, 키위 20g, 소금적당량, 후추 적당량', '["에멘탈 치즈","마늘","넉맥","닭육수","물전분","바케트빵","방울토마토","키위","소금","후추"]'::jsonb, ARRAY['fc6e31ce-388e-45cd-956b-b238b9134eb1','a4c37075-c03b-47bb-8aed-5e907620f5d2','6613d1d9-80a2-4ce4-9d3d-647203197e53','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','e748d9a5-9c62-4d33-918a-b1b8e9a1f00b','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"바닥이 두꺼운 팬의 표면에 마늘을 문질러 마늘 즙을 골고루 묻힌다.","imageUrl":null},{"step":2,"text":"1을 가열한 뒤 버터를 녹인다.","imageUrl":null},{"step":3,"text":"팬에 닭육수와 물전분을 넣고 약한 불에서 덩어리가 생기지 않도록 저어가며 끓인다.","imageUrl":null},{"step":4,"text":"자른 에멘탈치즈를 넣고 나무 주걱을 이용하여 한 방향으로 젓는다.","imageUrl":null},{"step":5,"text":"치즈가 다 녹으면 기호에 맞게 넉맥, 소금, 후추를 넣는다.","imageUrl":null},{"step":6,"text":"바케트, 방울토마토, 키위 등을 적당한 크기로 잘라 꼬치에 꼿아 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053610_1416213370153.jpg', 109, 10.1, 6.9, 5, 106),
  ('2987', '두부구이, 버섯소스', '반찬', '두부 100g, 느타리버섯 10g, 발사믹크림 5g, 올리브유 5g, 올리고당 5g, 쪽파 1g, 간장 5g', '["두부","느타리버섯","발사믹크림","올리브유","올리고당","쪽파","간장"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','7c91e298-5ace-4242-8619-cdcc80587cd7','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','4b410642-7bf9-45ad-9055-e7d9a34edaa1','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"두부를 1.5cm 두께로 잘라 물기를 뺀다.","imageUrl":null},{"step":2,"text":"프라이팬에 올리브유를 두르고 두부를 굽는다.","imageUrl":null},{"step":3,"text":"느타리버섯을 먹기 좋은 크기로 찢는다.","imageUrl":null},{"step":4,"text":"느타리버섯을 올리브유에 살짝 볶는다.","imageUrl":null},{"step":5,"text":"4에 발사믹크림, 올리고당을 넣어 졸인다.","imageUrl":null},{"step":6,"text":"두부구이 위에 소스를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409033713_1554791833052.jpg', 91.12, 2.85, 7.02, 5.74, 1.97),
  ('2990', '고구마 김치', '반찬', '고구마 35g, 미나리 3g, 홍고추 1g, 고춧가루 0.8g, 올리고당 0.5g, 마늘 1g, 젓갈 0.5g, 참깨 0.5g', '["고구마","미나리","홍고추","고춧가루","올리고당","마늘","젓갈","참깨"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','dc7b2b73-74de-4fb8-9274-a5967ca444f9','30b5d53c-d247-4f04-9b50-c0f728e65cf9','84104c49-0af4-4323-a56b-b67002a422d9','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','fc6e31ce-388e-45cd-956b-b238b9134eb1','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"고구마를 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":2,"text":"고구마를 젓갈에 절인다.","imageUrl":null},{"step":3,"text":"미나리, 홍고추를 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":4,"text":"양념 재료를 모두 섞는다.","imageUrl":null},{"step":5,"text":"절인 고구마와 썰어둔 미나리, 홍고추, 양념을 섞어 무친다.","imageUrl":null},{"step":6,"text":"참깨를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409040208_1554793328976.jpg', 95.86, 22.44, 0.91, 0.27, 1.44),
  ('3076', '담양식떡갈비&야채쌈', '반찬', '우육(분쇄육) 60g, 돈육(분쇄육) 30g, 두부 30g, 양파 5g, 대파 5g, 상추 30g, 깻잎 10g, 해바라기씨 2g, 간장 0.5g, 설탕 5g, 쌈장 5g', '["우육","돈육","두부","양파","대파","상추","깻잎","해바라기씨","간장","설탕","쌈장"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','70e914d4-0d03-4202-8b66-81bd8499aa08','4566cac5-9166-4c0d-906a-bfc7360f8f5b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','1389717e-81e4-4350-96d4-d627d851aa10','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"분쇄 우육과 돈육은 해동 후 핏물을 제거한다.","imageUrl":null},{"step":2,"text":"두부는 끓는 물에 데쳐낸 후 으깬다.","imageUrl":null},{"step":3,"text":"우육, 돈육, 다진양파, 다진대파, 으깬 두부(15g)에 간장과 설탕으로 간을 한 후 여러번 치댄다.","imageUrl":null},{"step":4,"text":"점성이 생긴 고기를 동그랗게 성형한 후 팬에 구워낸다.","imageUrl":null},{"step":5,"text":"쌈장에 으깬 두부(15g)와 해바라기 씨를 넣어 섞는다.","imageUrl":null},{"step":6,"text":"떡갈비와 양념장, 야채쌈을 함께 제공한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313112428_1584066268285.JPG', 200.4, 3.9, 23.9, 8.9, 197.1),
  ('3172', '단감피클', '반찬', '단감 60g, 식초 15g, 설탕 25g, 물 15ml', '["단감","식초","설탕","물"]'::jsonb, ARRAY['2db5cf59-b4ac-4d7b-8e13-68d143e5f34a','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"단감의 껍질과 씨를 제거한다.","imageUrl":null},{"step":2,"text":"단감을 깍둑썰기 한다.","imageUrl":null},{"step":3,"text":"식초와 설탕과 물을 섞어 단촛물을 만든다.","imageUrl":null},{"step":4,"text":"단촛물을 끓인다.","imageUrl":null},{"step":5,"text":"단촛물을 식혀 단감에 부워 절인다.","imageUrl":null},{"step":6,"text":"30분 정도 숙성시켜 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054056_1611823256080.jpg', 148.51, 36.44, 0.25, 0.19, 5.24),
  ('3219', '들깨 삼계면', '일품', '삼계탕용 닭(250g), 우유(500㎖), 삼계탕 티백(70g), 메밀면(100g), 깻잎(5장), 바질(5장), 삼계탕 육수(100㎖), 사과식초(30g), 홍고추(2개), 사과(½개), 삼계탕 육수(30㎖), 들깻가루(20g), 소금(2g)', '["삼계탕용 닭","우유","삼계탕 티백","메밀면","깻잎","바질","삼계탕 육수","사과식초","홍고추","사과","들깻가루","소금"]'::jsonb, ARRAY['e937397f-54e2-49df-997a-f393c58360be','b85df3ba-e324-47fa-b25d-d5bb552b8590','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','ba9e5a79-cab3-4af0-942b-0b35fd745150','6c285c60-022a-4a00-b172-87df97f16a2f','30b5d53c-d247-4f04-9b50-c0f728e65cf9','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','184687ba-0cba-4fec-bb21-33fe300c2073','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"닭은 우유에 담가 20분간 재운다.","imageUrl":null},{"step":2,"text":"냄비에 물(1.5L)과 닭, 삼계탕 티백, 소금을 넣어 30분간 삶아 건진 뒤 살을 발라 한입 크기로 찢는다.","imageUrl":null},{"step":3,"text":"끓는 삼계탕 육수(800㎖)에 메밀면을 4분간 삶아 건져 얼음에 비벼 식힌 뒤 돌돌 말아준다.","imageUrl":null},{"step":4,"text":"끓는 물(500㎖)에 깻잎을 넣어 1분간 살짝 데쳐 건진 뒤 펼쳐 찢은 닭고기, 들깨소스, 바질을 얹어 돌돌 말아준다.","imageUrl":null},{"step":5,"text":"믹서에 국물 재료를 넣어 간 뒤 체에 거른다.","imageUrl":null},{"step":6,"text":"그릇에 메밀면과 깻잎말이를 담은 뒤 국물을 부어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308052649_1615192009692.jpg', 448.5, 69.9, 27.4, 6.6, 214.4),
  ('3275', '골뱅이무침과 삼겹살수육', '반찬', ' 삼겹살(900g), 파채(100g), 월계수잎(3~5장), 맛술(3Ts), 설탕(1Ts), 고춧가루(1.5Ts), 간장(1Ts), 고추장(3Ts), 다진 마늘(1Ts), 레몬즙(1Ts), 골뱅이 국물(1Ts)', '["삼겹살","파채","월계수잎","맛술","설탕","고춧가루","간장","고추장","다진 마늘","레몬즙","골뱅이 국물"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','043a9631-bb6e-42e6-9673-4943457502fb','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','06e6f3e7-0293-469d-a338-11a610f3e71b','84104c49-0af4-4323-a56b-b67002a422d9','f175019d-5a93-4cd4-aabc-e7e79445f15a','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb','fc6e31ce-388e-45cd-956b-b238b9134eb1','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"양파는 도톰하게 모양대로 썰고, 대파는 2등분하고, 마늘은 꼭지를 제거하고, 알배추는 깨끗하게 씻는다.","imageUrl":null},{"step":2,"text":"통조림 골뱅이는 체에 밭쳐 국물을 거르고, 끓는 물에 30초간 데쳐 건진 뒤 찬물에 헹군다.","imageUrl":null},{"step":3,"text":"냄비에 양파, 대파를 깔고, 통마늘, 삼겹살, 월계수잎, 맛술을 넣어 센 불로 끓인다.","imageUrl":null},{"step":4,"text":"채즙이 나오면 약한 불로 줄여 45분간 고기를 삶는다.","imageUrl":null},{"step":5,"text":"파채에 데친 골뱅이와 양념장을 넣어 골고루 버무린다.","imageUrl":null},{"step":6,"text":"삶은 수육은 한 김 식힌 뒤 한입 크기로 썰고, 알배추, 골뱅이무침을 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr946U', 504.8, 12.6, 30.4, 37, 709.8),
  ('3680', '살레마이슈', '후식', ' 바나나 60g, 양파 24g, 양송이버섯 24g, 감자 24g, 검은콩두유 24g, 달걀 48g, 후추 3g, 다진 마늘 12g, 아몬드가루 36g, 베이킹파우더 3g, 강황가루 6g, 방울토마토 36g, 바질 6g', '["바나나","양파","양송이버섯","감자","검은콩두유","달걀","후추","다진 마늘","아몬드가루","베이킹파우더","강황가루","방울토마토","바질"]'::jsonb, ARRAY['1a4b39f8-b581-46dc-bd7e-289cd6160711','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','20894da1-739d-4d52-b5fe-4943bd3492d5','c7d438a6-34d6-423f-905d-446b839e2f39','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','fc6e31ce-388e-45cd-956b-b238b9134eb1','52ba316f-8e7f-415f-8079-9a9d674c9adf','325279ee-6de6-4d84-96a0-16af87dfdbc6','a7cf6fb8-b34f-4cfe-a4af-d8e000090dcb','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','ba9e5a79-cab3-4af0-942b-0b35fd745150']::uuid[], '[{"step":1,"text":"바나나는 으깨고 양파, 양송이버섯,\r\n감자, 바질은 작게 자른다.\r\n방울토마토는 1/4 크기로 자른다.","imageUrl":null},{"step":2,"text":"볼에 손질한 바나나, 양파, 양송이버섯,\r\n감자, 바질을 넣고 검은콩두유, 달걀,\r\n후추, 다진 마늘을 넣고 섞는다.","imageUrl":null},{"step":3,"text":"볼에 아몬드가루, 베이킹파우더,\r\n강황가루를 체 쳐서 넣고 섞어 반죽을\r\n완성한다.","imageUrl":null},{"step":4,"text":"머핀 틀에 반죽을 2/3 정도 넣고,\r\n손질한 방울토마토 3~4토막을 올린다.","imageUrl":null},{"step":5,"text":"170°C로 예열한 오븐에서 20분 동안\r\n구운 후 꺼낸다.","imageUrl":null},{"step":6,"text":"바질로 장식하여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20251016/20251016020447_1760591087339.jpg', 73.8, 10.5, 2.8, 2.3, 52),
  ('927', '완두콩 스프', '일품', '양파다진것 10g, 샐러리다진것 5g, 베이컨 13g, 완두콩 80g, 육수 120g, 생크림 2g, 소금 적당량, 후추 적당량', '["양파다진것","샐러리다진것","베이컨","완두콩","육수","생크림","소금","후추"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','12d2d4c9-705a-47f1-b628-30e042a970f8','bd88bfed-198e-4891-9430-06660bdeaa9a','5fd34bed-4339-4fcc-9221-f082ce6ac652','a4c37075-c03b-47bb-8aed-5e907620f5d2','af187077-b7f6-4b0e-9e99-f844f6359ac2','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"양파와 셀러리는 다지고, 베이컨은 적당한 크기로 자른다.","imageUrl":null},{"step":2,"text":"팬에 베이컨을 넣고 볶다가 양파, 셀러리를 넣고 색이 나지 않게 볶는다.","imageUrl":null},{"step":3,"text":"야채가 볶아지면 완두콩을 넣고 충분히 볶아준다.","imageUrl":null},{"step":4,"text":"완두콩이 반 정도 익으면 육수를 넣고 푹 끓여준다.","imageUrl":null},{"step":5,"text":"완두콩이 다 익으면 믹서에 간 뒤 체에 걸러낸다.","imageUrl":null},{"step":6,"text":"5를 냄비에 옮기고 기호에 맞게 소금, 후춧가루, 생크림을 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053611_1416213371666.jpg', 169, 20.8, 12.4, 4.7, 117),
  ('928', '유부 만두찜', '반찬', '유부 10g, 미나리 10g, 두부 20g, 닭가슴살 15g, 양파채썬것 15g, 당근채썬것 10g, 건표고버섯 5g, 시금치 10g, 소금적당량, 흰 후춧가루 적당량, 깨소금 1g, 참기름 1g  멸치 육수 3g, 간장 2g, 식초 2g, 설탕 1g', '["유부","미나리","두부","닭가슴살","양파채썬것","당근채썬것","건표고버섯","시금치","소금","흰 후춧가루","깨소금","참기름","간장","식초","설탕"]'::jsonb, ARRAY['dc7b2b73-74de-4fb8-9274-a5967ca444f9','4566cac5-9166-4c0d-906a-bfc7360f8f5b','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','66458b1b-c92f-43fa-8eba-e428892ce88a','9a7f4da6-531b-4478-89ff-d73beafcad1b','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"유부는 윗면을 살짝 잘라 내고 입을 벌려 주머니를 만든 뒤 끓는 물에 데쳐 냉수에 헹구고 미나리는 잎을 떼고 데쳐 냉수에 헹군다.","imageUrl":null},{"step":2,"text":"두부는 면보에 물기를 짠 뒤 곱게 으깨고 닭고기는 껍질을 제거하여 곱게 다진다.","imageUrl":null},{"step":3,"text":"양파와 당근, 불린 표고버섯은 곱게 채썰고 시금치는 끓는 물에 데쳐 물기를 짜고 2cm 길이로 썬다.","imageUrl":null},{"step":4,"text":"볼에 2, 3을 담고 소금, 흰 후춧가루, 깨소금과 참기름을 넣고 양념하여 만두소를 만든다.","imageUrl":null},{"step":5,"text":"준비한 유부주머니에 만두소를 넣고 미나리로 묶어 김 오른 찜통에 10분 정도 찐다.","imageUrl":null},{"step":6,"text":"초간장을 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053613_1416213373259.jpg', 114, 8.7, 9.31, 6.1, 163),
  ('929', '펜네 파스타 샐러드', '반찬', '펜넬파스타 40g, 청피망 10g, 홍피망 10g, 양파 10g, 완두콩 5g, 블랙올리브 2g, 아스파라거스 2g, 토마토콩카세 15g, 파마산치즈 4g, 소금적당량  잣 2g, 올리브오일 2g, 바질 3g, 믹서에 갈아줌', '["펜넬파스타","청피망","홍피망","양파","완두콩","블랙올리브","아스파라거스","토마토콩카세","파마산치즈","소금적당량  잣","올리브오일","바질","믹서에 갈아줌"]'::jsonb, ARRAY['df459e6f-3515-45d5-8c9a-9d37b6249379','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5fd34bed-4339-4fcc-9221-f082ce6ac652','a8462d27-4ef1-4919-ae9b-10c8f8b9545f','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','ba9e5a79-cab3-4af0-942b-0b35fd745150']::uuid[], '[{"step":1,"text":"펜네 파스타를 끓는 소금물에 기름을 약간 넣고 10분정도 삶아 체에 밭쳐 물기를 뺀다.","imageUrl":null},{"step":2,"text":"청피망, 홍피망, 양파는 펜네 파스타 길이로 썰고, 완두콩은 끓는 물에 데쳐서 찬물에 헹군 뒤 물기를 뺀다.","imageUrl":null},{"step":3,"text":"아스파라거스도 펜네 파스타 길이로 썰어 끓는 소금물에 데쳐 찬물에 식힌 뒤 물기를 뺀다.","imageUrl":null},{"step":4,"text":"블랙올리브를 링 형태로 썬다.","imageUrl":null},{"step":5,"text":"볼에 1과 바질 페스토, 소금을 넣고 섞는다.","imageUrl":null},{"step":6,"text":"5와 나머지 야채들을 같이 섞어 접시에 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053614_1416213374492.jpg', 213, 34.2, 7.3, 4.7, 72),
  ('930', '해산물 옥수수 오븐구이', '반찬', '달걀 30g, 새우 5g, 바지락 3g, 도미살 5g, 슬라이스 햄 3g, 실파 2g, 토마토 10g, 애호박 25g, 캔 옥수수 20g, 슬라이스 치즈 8g, 홍고추 1g, 바질 1g, 올리브오일 1g, 마늘다진것 1g, 소금적당량, 후춧가루 적당량', '["달걀","새우","바지락","도미살","슬라이스 햄","실파","토마토","애호박","캔 옥수수","슬라이스 치즈","홍고추","바질","올리브오일","마늘다진것","소금","후춧가루"]'::jsonb, ARRAY['c7d438a6-34d6-423f-905d-446b839e2f39','6f10b4ad-53a2-4a07-ba89-19a6b074373d','b6047d76-6c94-4757-b1d1-9175aea0c84a','4b410642-7bf9-45ad-9055-e7d9a34edaa1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','30b5d53c-d247-4f04-9b50-c0f728e65cf9','ba9e5a79-cab3-4af0-942b-0b35fd745150','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','fc6e31ce-388e-45cd-956b-b238b9134eb1','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"새우는 껍질과 내장을 제거하고 바지락은 살짝 데쳐 입이 열리면 살을 발라낸다.","imageUrl":null},{"step":2,"text":"해산물은 0.5cm 크기로 썰고 실파는 송송 썬다.","imageUrl":null},{"step":3,"text":"토마토는 껍질을 벗겨 햄과 비슷한 크기로 썰고 바질은 굵게 채썬다.","imageUrl":null},{"step":4,"text":"팬에 올리브오일은 두르고 햄, 옥수수를 넣어 볶다가 풀어둔 달걀을 넣고 스크램블을 만든다.","imageUrl":null},{"step":5,"text":"4가 반 정도 익었을 때 해산물, 토마토, 바질을 넣고 홍고추로 장식하고 다 익으면 오븐용 용기에 담는다.","imageUrl":null},{"step":6,"text":"5에 치즈를 0.5cm 넓이로 잘라 격자로 올리고 오븐에서 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053615_1416213375835.jpg', 112, 8.5, 9, 4.7, 211),
  ('931', '향향 볶음밥', '밥', '감자 10g, 오이 10g, 목이버섯 5g, 닭고기 15g, 닭 육수 10g, 밥 50g, 파 9g, 식물성기름 1g, 소금적당량', '["감자","오이","목이버섯","닭고기","닭 육수","밥","파","식물성기름","소금"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','aad7c333-f1f0-46c1-8313-37cc64d689dc','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','a4c37075-c03b-47bb-8aed-5e907620f5d2','ecb35816-34ae-4c4c-867a-e3f84db92755','4b410642-7bf9-45ad-9055-e7d9a34edaa1','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"닭고기를 깍둑썰기한다.","imageUrl":null},{"step":2,"text":"감자, 오이는 깍둑썰기 하고 목이버섯은 물에 불린다.","imageUrl":null},{"step":3,"text":"기름을 두른 팬에 1을 넣고 볶다가 닭 육수를 넣는다.","imageUrl":null},{"step":4,"text":"닭고기가 익으면 감자, 목이버섯을 넣고 끓인 뒤 건진다.","imageUrl":null},{"step":5,"text":"깨끗한 팬에 기름을 두르고 밥과 송송 썬 파를 넣고 볶는다.","imageUrl":null},{"step":6,"text":"5에 오이와 익힌 닭고기, 목이버섯, 소금을 넣어 볶는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053616_1416213376974.jpg', 104, 18.9, 5.6, 1.3, 10),
  ('932', '흑임자 두부국', '국&찌개', '불린 쌀 30g, 으깬 두부 35g, 검은 깨 5g, 물 90g, 소금적당량', '["불린 쌀","으깬 두부","검은 깨","물","소금"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','4566cac5-9166-4c0d-906a-bfc7360f8f5b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','94786475-832c-4f97-aab7-bf6fbbe2236b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"쌀을 씻어 불린 뒤 믹서나 절구에 넣고 곱게 간다.","imageUrl":null},{"step":2,"text":"두부를 곱게 으깬다.","imageUrl":null},{"step":3,"text":"검은깨를 물에 넣어 돌맹이가 없도록 거른다.","imageUrl":null},{"step":4,"text":"3의 물기를 빼고 볶은 뒤 동량의 물을 넣고 곱게 간다.","imageUrl":null},{"step":5,"text":"냄비에 쌀과 두부, 적당량의 물을 넣고 센불에서 끓인다.","imageUrl":null},{"step":6,"text":"불을 줄여 쌀이 퍼지면 2의 검은깨를 넣고 더 끓여 소금으로 간한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053618_1416213378582.jpg', 164, 23.6, 7.1, 4.8, 2),
  ('934', '과일 요구르트 샐러드', '반찬', '멜론 30g, 사과 30g, 바나나 20g, 오렌지 30g, 플레인 요구르트 30g, 레몬주스 5g, 오렌지주스 5g', '["멜론","사과","바나나","오렌지","플레인 요구르트","레몬주스","오렌지주스"]'::jsonb, ARRAY['c85a52b9-c3b4-4a76-951c-bb40edeb3adb','1a4b39f8-b581-46dc-bd7e-289cd6160711','19eb37dc-2b1c-4e89-a931-31a38ae60561','bb41a88a-ea2b-4830-876d-91fe7f640296','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"메론의 껍질을 벗기고 2cm 정도의 주사위모양으로 썬다.","imageUrl":null},{"step":2,"text":"사과는 껍질을 벗기고 메론과 같은 크기로 썬다.","imageUrl":null},{"step":3,"text":"바나나도 껍질을 벗기고 같은 크기로 썬다.","imageUrl":null},{"step":4,"text":"오렌지는 칼로 껍질을 도려내고 속살만 자른다.","imageUrl":null},{"step":5,"text":"플레인 요구르트와 레몬주스, 오렌지주스를 섞어 드레싱을 만든다.","imageUrl":null},{"step":6,"text":"볼에 과일을 한데 섞고 드래싱으로 버무려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053621_1416213381018.jpg', 77, 18.2, 2.6, 0.2, 20),
  ('935', '단호박 스프', '일품', '버터 2g, 마늘 1g, 양파 10g, 샐러리 5g, 생강 1g, 닭육수 100g, 단호박 50g, 고구마 15g, 우유 10g, 라임주스 1g, 생크림 5g, 소금적당량, 후추적당량', '["버터","마늘","양파","샐러리","생강","닭육수","단호박","고구마","우유","라임주스","생크림","소금","후추"]'::jsonb, ARRAY['7aabd532-361f-4240-aa33-6bfa1be4bc4e','fc6e31ce-388e-45cd-956b-b238b9134eb1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','12d2d4c9-705a-47f1-b628-30e042a970f8','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','a4c37075-c03b-47bb-8aed-5e907620f5d2','98d652af-a6d6-440c-9653-e22fc5d47d88','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','e937397f-54e2-49df-997a-f393c58360be','af187077-b7f6-4b0e-9e99-f844f6359ac2','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"냄비에 버터를 녹인 후 마늘, 양파, 셀러리, 생강을 넣고 볶는다.","imageUrl":null},{"step":2,"text":"양파와 셀러리가 부드러워지면 닭육수를 넣는다.","imageUrl":null},{"step":3,"text":"2에 단호박, 고구마를 넣고 단호박이 부드러워질 때까지 약한불로 끓인다.","imageUrl":null},{"step":4,"text":"단호박이 다 익으면 믹서에 부드러운 상태가 되도록 간다.","imageUrl":null},{"step":5,"text":"4를 다시 냄비에 넣고 중간불로 끓인다.","imageUrl":null},{"step":6,"text":"5에 우유, 라임주스, 소금, 후추, 크림을 넣어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053621_1416213381846.jpg', 102, 16, 3.1, 3.8, 46),
  ('937', '새우 완자탕', '국&찌개', '새우 살 40g, 달걀흰자 5g, 전분 4g, 당면불린것 10g, 팽이버섯 10g, 부추 5g, 홍고추 3g, 다시마육수 70g, 국간장 1g, 마늘다진것 2g, 소금적당량, 흰 후춧가루 적당량', '["새우 살","달걀흰자","전분","당면불린것","팽이버섯","부추","홍고추","다시마육수","국간장","마늘다진것","소금","흰 후춧가루"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','c7d438a6-34d6-423f-905d-446b839e2f39','6613d1d9-80a2-4ce4-9d3d-647203197e53','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','058648c3-fd8e-476d-952f-b15dc67f1877','30b5d53c-d247-4f04-9b50-c0f728e65cf9','f175019d-5a93-4cd4-aabc-e7e79445f15a','fc6e31ce-388e-45cd-956b-b238b9134eb1','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"곱게 다진 새우살에 소금, 흰 후춧가루로 밑간한다.","imageUrl":null},{"step":2,"text":"1에 달걀흰자, 전분을 넣어 치댄후 지름 2cm 정도의 완자를 만든다.","imageUrl":null},{"step":3,"text":"불린 당면, 팽이버섯, 부추는 5cm 길이로 자르고 홍고추는 2cm 길이로 채썬다.","imageUrl":null},{"step":4,"text":"냄비에 다시마 육수를 넣어 끓으면 2의 완자를 넣고 불을 줄인다.","imageUrl":null},{"step":5,"text":"완자가 떠오르면 불린 당면, 팽이버섯, 부추, 홍고추 순으로 넣는다.","imageUrl":null},{"step":6,"text":"다진마늘, 국간장, 소금으로 간한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053623_1416213383797.jpg', 87, 9.3, 9.9, 1.1, 205),
  ('938', '생강향의 고구마 크로켓', '후식', '고구마 60g, 생강 2g, 생크림 3g, 버터 2g, 꿀 2g, 밀가루 3g, 달걀물 5g, 빵가루 3g, 튀김기름 8g, 소금적당량, 후추적당량', '["고구마","생강","생크림","버터","꿀","밀가루","달걀물","빵가루","튀김기름","소금","후추"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','af187077-b7f6-4b0e-9e99-f844f6359ac2','7aabd532-361f-4240-aa33-6bfa1be4bc4e','286d1783-cd34-4aae-ac8b-006529ec8bc5','aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','45080597-55fa-42dc-aa65-12d7694e4b7e','a7a59e81-de3d-4893-b56a-b2218732a25b','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"고구마를 삶아 껍질을 제거하고 오븐에 넣어 수분을 제거한다.","imageUrl":null},{"step":2,"text":"생강을 편으로 썰어 생크림과 섞어 생강향이 우러나도록 살짝 끓인 후 체에 거른다.","imageUrl":null},{"step":3,"text":"볼에 1을 넣고 으깬다.","imageUrl":null},{"step":4,"text":"3에 2를 넣고 골고루 섞어준다.","imageUrl":null},{"step":5,"text":"버터, 꿀, 소금, 후추를 넣어 맛을 내고 원하는 모양으로 빚는다.","imageUrl":null},{"step":6,"text":"5에 밀가루, 달걀물, 빵가루 순으로 묻혀 180℃ 기름에 튀긴다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053625_1416213385372.jpg', 205, 25.2, 2.2, 10.9, 49),
  ('939', '알파벳 스프', '일품', '양파 1cm 정사각형 14g, 샐러리 1cm 정사각형 7g, 당근 1cm 정사각형 7g, 마늘다진것 1g, 식용유 1g, 닭육수 150g, 후추적당량, 소금적당량, 월계수잎, 알파벳파스타 20g', '["양파","샐러리","당근","마늘다진것","식용유","닭육수","후추","소금","월계수잎","알파벳파스타"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','12d2d4c9-705a-47f1-b628-30e042a970f8','e38c12a7-43cb-421a-a36e-7ef0d32517fa','fc6e31ce-388e-45cd-956b-b238b9134eb1','a7a59e81-de3d-4893-b56a-b2218732a25b','a4c37075-c03b-47bb-8aed-5e907620f5d2','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','2cf0c12b-f248-4012-8f53-303c730a7b3d','043a9631-bb6e-42e6-9673-4943457502fb']::uuid[], '[{"step":1,"text":"냄비에 기름을 두르고 중간불로 열을 가열한다.","imageUrl":null},{"step":2,"text":"1에 양파, 셀러리, 당근을 넣고 색이 나지 않도록 부드러워 질 때까지 볶는다.","imageUrl":null},{"step":3,"text":"야채가 익을 때 쯤 마늘을 넣고 볶는다.","imageUrl":null},{"step":4,"text":"3에 닭육수, 후추, 월계수잎을 넣고 끓인다.","imageUrl":null},{"step":5,"text":"중간불로 줄이고 35분 정도 은근하게 끓인다.","imageUrl":null},{"step":6,"text":"여기에 알파벳 파스타를 넣고 약 10분간 저어주며 끓인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053626_1416213386512.jpg', 109, 17.4, 4.6, 2.1, 36),
  ('940', '야채 과일 돌구이', '반찬', '단호박 30g, 고구마 30g, 오렌지 30g, 소금적당량', '["단호박","고구마","오렌지","소금"]'::jsonb, ARRAY['98d652af-a6d6-440c-9653-e22fc5d47d88','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','19eb37dc-2b1c-4e89-a931-31a38ae60561','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"냄비 전체에 작은 돌을 깔고 돌이 뜨거워질 때까지 불에 올려놓는다.","imageUrl":null},{"step":2,"text":"단호박, 고구마, 오렌지를 0.5cm 두께로 자른다.","imageUrl":null},{"step":3,"text":"2의 표면에 소금을 살짝 뿌린다.","imageUrl":null},{"step":4,"text":"뜨거워진 돌 위에 3을 올린다.","imageUrl":null},{"step":5,"text":"뚜껑을 닫고 약한 불에서 속이 익을 때 까지 굽는다.","imageUrl":null},{"step":6,"text":"소금, 된장소스, 참깨소스 등 취향에 맞는 소스를 골라 찍어 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053627_1416213387667.jpg', 71, 18.2, 1.2, 0.2, 5),
  ('941', '야채볶음', '반찬', '감자 20g, 양송이버섯 15g, 당근 15g, 건목이버섯 5g, 산마 10g, 참기름 1g, 물전분 6g, 육수 6g, 식용유 2g, 소금적당량', '["감자","양송이버섯","당근","건목이버섯","산마","참기름","물전분","육수","식용유","소금"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','e38c12a7-43cb-421a-a36e-7ef0d32517fa','0c0ade94-cfd8-4104-b44c-40e942cac482','6613d1d9-80a2-4ce4-9d3d-647203197e53','a4c37075-c03b-47bb-8aed-5e907620f5d2','a7a59e81-de3d-4893-b56a-b2218732a25b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"당근과 감자를 2cm 주사위모양으로 자르고 버섯은 4등분한다.","imageUrl":null},{"step":2,"text":"산마를 끓는 물에 데친다.","imageUrl":null},{"step":3,"text":"기름을 두른 팬을 가열한 후 당근, 감자, 데친 마를 넣고 볶은 뒤 육수를 넣는다","imageUrl":null},{"step":4,"text":"육수가 끓으면 양송이버섯과 목이버섯을 넣고 소금으로 간한다.","imageUrl":null},{"step":5,"text":"물 전분을 넣어 농도를 맞춘다.","imageUrl":null},{"step":6,"text":"참기름을 넣어 향을 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053629_1416213389072.jpg', 91, 15.4, 2.4, 3.1, 10),
  ('942', '야채빵', '후식', '밀가루 30g, 베이킹파우더 1g, 버터 2g, 달걀 12g, 설탕 5g, 당근 10g, 양파 10g, 캔옥수수 10g, 완두콩 10g, 우유 10g, 소금적당량', '["밀가루","베이킹파우더","버터","달걀","설탕","당근","양파","캔옥수수","완두콩","우유","소금"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','325279ee-6de6-4d84-96a0-16af87dfdbc6','7aabd532-361f-4240-aa33-6bfa1be4bc4e','c7d438a6-34d6-423f-905d-446b839e2f39','06e6f3e7-0293-469d-a338-11a610f3e71b','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5fd34bed-4339-4fcc-9221-f082ce6ac652','e937397f-54e2-49df-997a-f393c58360be','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"밀가루와 베이킹파우더를 섞어 체에 내린다.","imageUrl":null},{"step":2,"text":"녹인 버터에 달걀, 소금, 설탕을 넣고 1을 넣어 골고루 섞는다.","imageUrl":null},{"step":3,"text":"당근, 양파는 0.5cm 주사위모양으로 썰어 데친다.","imageUrl":null},{"step":4,"text":"옥수수, 완두콩을 물에 헹군다.","imageUrl":null},{"step":5,"text":"2에 당근, 양파, 옥수수, 완두콩, 우유를 넣고 섞는다.","imageUrl":null},{"step":6,"text":"모양 틀에 넣어 김이 오른 찜통에서 10분간 찐다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053630_1416213390212.jpg', 194, 33.7, 6, 3.2, 188),
  ('943', '영양 달걀찜', '반찬', '죽순 5g, 밤 5g, 찐 어묵 5g, 건표고버섯 3g, 은행 5g, 새우 5g, 잣 1g, 달걀 20g, 쑥갓 1g, 멸치 육수 50g, 소금적당량', '["죽순","밤","찐 어묵","건표고버섯","은행","새우","잣","달걀","쑥갓","멸치 육수","소금"]'::jsonb, ARRAY['5e4a7ae8-e12e-48b6-88d5-fc3521d3dce8','66458b1b-c92f-43fa-8eba-e428892ce88a','9c201731-bb59-4929-8996-f11933f4f27a','6f10b4ad-53a2-4a07-ba89-19a6b074373d','bbbbd533-8922-4dac-9e4c-cd93ea710c92','c7d438a6-34d6-423f-905d-446b839e2f39','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"죽순은 빗살을 살려 썰고 밤은 껍질을 벗겨 4등분한다.","imageUrl":null},{"step":2,"text":"찐 어묵은 얇게 썰고 표고버섯은 미지근한 물에 불려 어슷하게 4등분 한다.","imageUrl":null},{"step":3,"text":"볼에 달걀 풀고 달걀 부피의 2.5배의 멸치 육수를 넣고 소금으로 간을 한 뒤 거품기로 잘 풀어 체에 내린다.","imageUrl":null},{"step":4,"text":"끓는 물에 은행, 죽순, 밤, 새우 순으로 데친다.","imageUrl":null},{"step":5,"text":"데쳐 낸 은행은 껍질을 벗기고 새우는 머리와 껍질을 제거한다.","imageUrl":null},{"step":6,"text":"찜 용기에 준비한 속 재료들을 담고 준비한 달걀 물을 부어 찜통에서 약 12분간 찐다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053631_1416213391320.jpg', 76, 7.1, 5.8, 3, 87),
  ('944', '유부 달걀찜', '반찬', '유부 8g, 달걀 30g, 당근 7g, 멸치 육수 50g, 간장 3g, 설탕 2g, 소금적당량', '["유부","달걀","당근","멸치 육수","간장","설탕","소금"]'::jsonb, ARRAY['c7d438a6-34d6-423f-905d-446b839e2f39','e38c12a7-43cb-421a-a36e-7ef0d32517fa','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"유부는 윗면을 잘라 내고 입을 벌려서 주머니를 만든다.","imageUrl":null},{"step":2,"text":"1을 끓는 물에 데친 뒤 냉수에 헹군다.","imageUrl":null},{"step":3,"text":"달걀을 그릇에 풀고 다진 당근과 소금을 넣고 섞는다.","imageUrl":null},{"step":4,"text":"2에 3을 넣어 꼬지로 주름을 잡아 끝부분을 마무리한다.","imageUrl":null},{"step":5,"text":"냄비에 멸치 육수와 간장, 설탕, 소금을 넣는다.","imageUrl":null},{"step":6,"text":"5에 4를 넣어 10분정도 끓인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053632_1416213392616.jpg', 87, 3.9, 6.1, 5.4, 209),
  ('945', '찰 어묵찜', '반찬', '찰어묵 50g, 새우살 20g, 전분 5g 양념 마늘다진것 2g, 참기름 1g, 깨소금 1g, 청주 1g, 소금적당량, 후추 적당량', '["찰어묵","새우살","전분","참기름","깨소금","청주","소금","후추"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','6613d1d9-80a2-4ce4-9d3d-647203197e53','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"찰어묵을 2cm 두께로 썬 후 가운데 칼집을 넣는다.","imageUrl":null},{"step":2,"text":"새우살을 입자있게 다진다.","imageUrl":null},{"step":3,"text":"2에 양념재료를 넣고 잘 버무린다","imageUrl":null},{"step":4,"text":"찰어묵의 칼집 사이에 전분을 묻힌다.","imageUrl":null},{"step":5,"text":"칼집 사이에 3를 끼워 넣는다.","imageUrl":null},{"step":6,"text":"김이 오른 찜통에 10분간 찐다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053634_1416213394771.jpg', 103, 11, 9.4, 2.2, 397),
  ('2989', '유부 우엉 잡채', '반찬', '우엉 20g, 유부 6g, 양파 10g, 당근 10g, 올리브유 5g, 올리고당 6g, 간장 5g, 설탕 0.5g, 참깨 0.5g, 참기름 1g', '["우엉","유부","양파","당근","올리브유","올리고당","간장","설탕","참깨","참기름"]'::jsonb, ARRAY['6b3a8bca-adc3-48f5-813b-6b06630e11dd','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"우엉을 깨끗이 씻어 채 썬다.","imageUrl":null},{"step":2,"text":"양파와 당근을 채 썬다.","imageUrl":null},{"step":3,"text":"간장과 양념들을 넣고 채 썬 우엉을 졸인다.","imageUrl":null},{"step":4,"text":"3이 80% 정도 졸았을 대 채 썬 양파와 당근을 넣는다.","imageUrl":null},{"step":5,"text":"거의 다 졸여지면 채 썬 유부를 넣는다.","imageUrl":null},{"step":6,"text":"참깨를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409035029_1554792629494.jpg', 40.71, 3.02, 1.13, 2.68, 128.73),
  ('2998', '치즈두부샐러드', '반찬', '까망베르치즈 8g, 두부 25g, 새싹채소 5g, 아몬드슬라이스 1g, 유자청 6g, 식초 1g, 레몬즙 2g, 올리브유 3g, 저염간장 2g', '["까망베르치즈","두부","새싹채소","아몬드슬라이스","유자청","식초","레몬즙","올리브유","저염간장"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','52ba316f-8e7f-415f-8079-9a9d674c9adf','ff5b6cbe-7985-4ca2-94ad-5525717cddf1','6c285c60-022a-4a00-b172-87df97f16a2f','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"유자청을 잘게 다진 뒤 저염간장, 식초, 올리브유, 레몬즙을 섞어 드레싱을 만든다.","imageUrl":null},{"step":2,"text":"두부는 2cm 크기로 깍둑썰기 한다.","imageUrl":null},{"step":3,"text":"까망베르치즈도 깍둑썰기 한다.","imageUrl":null},{"step":4,"text":"새싹채소는 세척 후 건져 물기를 제거한다.","imageUrl":null},{"step":5,"text":"그릇에 새싹채소를 담고 두부, 치즈를 얹는다.","imageUrl":null},{"step":6,"text":"드레싱과 아몬드를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050413_1554797053629.jpg', 104.06, 7.87, 6.2, 5.31, 101.08),
  ('3077', '된장숙성저수분수육', '반찬', '앞다리살 돈육(보쌈용) 100g, 양파 40g, 대파 20g,저염된장 4g, 통후추 1g, 월계수잎 1g, 생강가루 2g, 다진마늘 4g', '["앞다리살 돈육","양파","대파","저염된장","통후추","월계수잎","생강가루","다진마늘"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','392236b1-82e9-4e38-bd12-6a53b80bf463','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','043a9631-bb6e-42e6-9673-4943457502fb','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"돼지고기 앞다리 살에 칼집을 낸다.","imageUrl":null},{"step":2,"text":"돼지고기에 된장, 생강가루, 다진마늘, 통후추, 월계수잎을 입혀 숙성시킨다.","imageUrl":null},{"step":3,"text":"파와 대파는 큼지막하게 썰어 준비한다.","imageUrl":null},{"step":4,"text":"냄비 혹은 오븐용기의 밑 부분에 양파와 대파를 놓아준다.","imageUrl":null},{"step":5,"text":"④에 숙성시킨 돼지고기를 올려 약 50분 정도 가열하여 완전히 익혀준다.","imageUrl":null},{"step":6,"text":"0.5cm 두께로 썰어서 제공한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313105128_1584064288421.JPG', 342.6, 17.2, 33.1, 15.7, 178),
  ('3173', '스마일오이피클', '반찬', '오이 80g, 배 50g, 홍피망 5g, 청피망 5g, 노랑파프리카 5g, 식초 3g, 설탕 6g, 물 100ml, 피클링스파이스 1g', '["오이","배","홍피망","청피망","노랑파프리카","식초","설탕","물","피클링스파이스"]'::jsonb, ARRAY['9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','df459e6f-3515-45d5-8c9a-9d37b6249379','5e79d288-1400-4817-bd20-e5e6041821b1','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"오이를 3등분하여 속을 파낸다.","imageUrl":null},{"step":2,"text":"피망 및 파프리카는 U모양으로 휘어지게 썰어준다.","imageUrl":null},{"step":3,"text":"배를 채 썰어 준다.","imageUrl":null},{"step":4,"text":"오이 중앙에 파프리카와 배를 채워 넣는다.","imageUrl":null},{"step":5,"text":"물, 식초, 설탕, 피클링 스파이스를 넣어 피클물을 만든다.","imageUrl":null},{"step":6,"text":"④에 피클물을 넣고 30분 정도 숙성시킨다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054408_1611823448289.JPG', 52.15, 10.83, 1.01, 0.54, 9.69),
  ('3220', '참나물 소보로덮밥', '일품', '건취나물(10g), 건표고버섯(20g), 불린 쌀(80g), 불린 곤약쌀(60g), 다진 돼지고기(20g), 달걀(1개), 참나물(10g), 간장(7g), 참기름(3g), 소금(1g), 식용유(3㎖)', '["건취나물","건표고버섯","불린 쌀","불린 곤약쌀","다진 돼지고기","달걀","참나물","간장","참기름","소금","식용유"]'::jsonb, ARRAY['66458b1b-c92f-43fa-8eba-e428892ce88a','a5bc0b46-0192-496a-b429-d2cb90b2bca9','70e914d4-0d03-4202-8b66-81bd8499aa08','c7d438a6-34d6-423f-905d-446b839e2f39','09065cd3-28cc-4a82-8b3e-5121054c7482','f175019d-5a93-4cd4-aabc-e7e79445f15a','0c0ade94-cfd8-4104-b44c-40e942cac482','2cf0c12b-f248-4012-8f53-303c730a7b3d','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"건취나물과 건표고버섯은 뜨거운 물(200㎖)에 담가 30분간 불린다.","imageUrl":null},{"step":2,"text":"밥솥에 불린 쌀과 곤약쌀, 불린 건취나물, 물(100㎖)을 넣어 취사 버튼을 눌러 밥을 짓는다.","imageUrl":null},{"step":3,"text":"불린 표고버섯은 잘게 다져 중간 불로 달군 팬에 넣고 다진 돼지고기, 간장(5g), 참기름(2g)을 넣어 3분간 볶아 꺼낸다.","imageUrl":null},{"step":4,"text":"중간 불로 달군 다른 팬에 식용유(3㎖)를 두른 뒤 달걀을 넣어 스크램블드에그를 만든다.","imageUrl":null},{"step":5,"text":"끓는 물(300㎖)에 참나물을 넣고 1분간 데쳐 찬물에 헹군 뒤 소금(1g), 간장(2g), 참기름(1g)을 넣어 버무린다.","imageUrl":null},{"step":6,"text":"그릇에 취나물 곤약밥을 담은 뒤 볶은 버섯과 고기, 스크램블드에그, 양념한 참나물을 얹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308052952_1615192192726.jpg', 293.9, 51.5, 9.3, 5.6, 583.6),
  ('3279', '버섯초계탕', '일품', ' 닭(1마리), 양파(1개), 대파(1대), 미나리(½줌), 새송이버섯(3개), 팽이버섯(1봉), 마늘(6쪽), 양송이버섯(4개), 달걀(1개), 전분(0.7Ts), 간장(0.5Ts), 소금(0.3ts), 후춧가루(약간)', '["닭","양파","대파","미나리","새송이버섯","팽이버섯","마늘","양송이버섯","달걀","전분","간장","소금","후춧가루"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','dc7b2b73-74de-4fb8-9274-a5967ca444f9','3f94371a-728f-49ae-8ea9-1a1e87b68048','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','fc6e31ce-388e-45cd-956b-b238b9134eb1','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','c7d438a6-34d6-423f-905d-446b839e2f39','6613d1d9-80a2-4ce4-9d3d-647203197e53','f175019d-5a93-4cd4-aabc-e7e79445f15a','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"닭은 깨끗하게 씻어 준비하고, 양파와 대파는 4등분한다.","imageUrl":null},{"step":2,"text":"새송이버섯은 모양대로 두툼하게 썰고, 팽이버섯은 밑동을 자른 뒤 낱낱이 가르고, 미나리는 한입 크기로 썬다.","imageUrl":null},{"step":3,"text":"냄비에 닭을 넣고 잠길 만큼 물을 붓고, 양파, 대파, 미나리(½분량), 마늘을 넣어 센 불로 올린 뒤 닭이 익을 때까지 끓인다.","imageUrl":null},{"step":4,"text":"닭, 양파, 미나리를 건져내 한 김 식히고, 닭은 살을 발라낸다.","imageUrl":null},{"step":5,"text":"닭고기, 양파, 남은 미나리, 달걀, 전분을 고루 섞어 닭볼을 만든다.","imageUrl":null},{"step":6,"text":"육수에 닭볼, 새송이버섯, 팽이버섯, 양송이버섯, 남은 미나리를 넣고, 양념으로 간한 뒤 한소끔 끓여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9544', 277.3, 31.4, 24.6, 5.9, 178.9),
  ('3287', '사과채소타코', '기타', ' 양상추(2장), 사과(½개), 토르티야(4장), 슈레드 모차렐라치즈(약간), 양파(⅛개), 파프리카(⅛개), 토마토(½개), 할라피뇨 피클(4개), 스리라차 소스(1Ts), 스테비아(0.5Ts), 아보카도(½개), 살사소스(1Ts), 라임즙(1Ts), 무가당 플레인 요거트(2Ts), 마요네즈(1Ts), 다진 마늘(1Ts), 파슬리가루(0.5Ts), 라임즙(1Ts), 후춧가루(약간)', '["양상추","사과","토르티야","슈레드 모차렐라치즈","양파","파프리카","토마토","할라피뇨 피클","스리라차 소스","스테비아","아보카도","살사소스","라임즙","무가당 플레인 요거트","마요네즈","다진 마늘","파슬리가루","후춧가루"]'::jsonb, ARRAY['1389717e-81e4-4350-96d4-d627d851aa10','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','49b48723-2e40-46b0-9588-00f41a6a02c2','906bfef3-a41b-40d3-acda-7d8f23d2bcd2','549c7365-28e9-491f-9040-412558f93a5c','fc6e31ce-388e-45cd-956b-b238b9134eb1','4362c386-a37c-44cd-9254-fafd74712a09','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"양상추는 채 썰고, 사과는 모양대로 얇게 썰고, 양파, 파프리카, 토마토, 할라피뇨 피클은 잘게 다진다.","imageUrl":null},{"step":2,"text":"다진 양파, 파프리카, 토마토, 할라피뇨 피클에 나머지 살사소스 재료를 넣어 고루 섞는다.","imageUrl":null},{"step":3,"text":"아보카도는 씨와 껍질을 제거하고, 골고루 으깬 뒤 나머지 과카몰레 재료와 고루 섞는다.","imageUrl":null},{"step":4,"text":"갈릭요거트소스를 만든다.","imageUrl":null},{"step":5,"text":"약한 불로 달군 마른 팬에 토르티야를 올려 1~2분간 구워 꺼내고, 맥주잔에 감아 모양을 잡는다.","imageUrl":null},{"step":6,"text":"토르티야에 채 썬 양상추, 사과, 슈레드 모차렐라치즈를 올리고 살사소스, 과카몰레, 갈릭요거트소스를 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9afz', 277.9, 41.5, 6.7, 9.5, 845.7),
  ('3681', '코코넛 수플레 치즈케이크', '후식', ' 크림치즈 90g, 무염버터 15g, 코코넛우유 50ml, 달걀노른자 70g,박력 밀가루 5g, 옥수수전분 10g, 달걀흰자 130g, 레몬즙 1g, 알룰로스 가루 20g', '["크림치즈","무염버터","코코넛우유","달걀노른자","박력 밀가루","옥수수전분","달걀흰자","레몬즙","알룰로스 가루"]'::jsonb, ARRAY['b42c6eac-0afb-4d87-8942-ed1a9c294b09','7aabd532-361f-4240-aa33-6bfa1be4bc4e','c7d438a6-34d6-423f-905d-446b839e2f39','6613d1d9-80a2-4ce4-9d3d-647203197e53','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"볼에 크림치즈, 무염버터,\r\n코코넛우유를 넣고 중탕하며 부드럽게\r\n될 때까지 섞는다. 중탕물에서 내려\r\n달걀노른자를 섞는다.","imageUrl":null},{"step":2,"text":"①에 박력 밀가루, 옥수수전분을\r\n체 쳐서 넣고 섞은 후 고운체로\r\n한 번 더 거른다.","imageUrl":null},{"step":3,"text":"달걀흰자에 레몬즙을 넣고 휘핑한다.\r\n알룰로스 가루를 1/3씩 넣으며 섞어\r\n약간 단단한 머랭을 만든다.","imageUrl":null},{"step":4,"text":"②에 머랭을 1/3씩 넣고 섞어 반죽을\r\n만든다. 케이크 틀에 유산지를 깔고\r\n반죽을 넣는다.","imageUrl":null},{"step":5,"text":"큰 팬에 뜨거운 물을 붓고 케이크\r\n틀을 올려 중탕하여 150°C로 예열한\r\n오븐에서 30분 동안 굽는다.","imageUrl":null},{"step":6,"text":"케이크 틀에서 꺼내 유산지를 제거하고\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20251020/20251020062651_1760952411936.jpg', 187.3, 16.2, 7.3, 10.3, 102.2),
  ('3690', '세 가지 맛 공기과자', '후식', ' 검은콩 20g, 단호박 70g, 비트 70g, 달걀흰자 120g, 설탕 10g, 달걀노른자 20g, 박력 밀가루 24g, 허브가루 약간', '["검은콩","단호박","비트","달걀흰자","설탕","달걀노른자","박력 밀가루","허브가루"]'::jsonb, ARRAY['f82b8382-3b65-4839-9f45-524168f3da07','98d652af-a6d6-440c-9653-e22fc5d47d88','524e1b82-1f81-4648-b50c-441404a06786','c7d438a6-34d6-423f-905d-446b839e2f39','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"냄비에 검은콩을 넣고 20분 동안 삶아\r\n체에 거르고 으깨어 검은콩 퓨레를\r\n만든다.","imageUrl":null},{"step":2,"text":"달걀흰자에 설탕을 넣으며 단단한\r\n머랭을 만든다. 달걀노른자,\r\n박력 밀가루를 머랭에 넣고 자르듯이\r\n섞어 머랭 반죽을 만든다.","imageUrl":null},{"step":3,"text":"퓨레에 머랭 반죽을 나누어 섞어 3가지\r\n반죽을 만든다.","imageUrl":null},{"step":4,"text":"종이컵에 각각의 반죽을 2/3 정도\r\n넣고, 전자레인지에 50~55초 동안\r\n굽는다.","imageUrl":null},{"step":5,"text":"10분 동안 식혀 종이컵에서 분리한다","imageUrl":null},{"step":6,"text":"모양을 내어 자른 후 허브가루를\r\n뿌리고 접시에 담아 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023105712_1761184632944.jpg', 41.2, 11.5, 3.1, 0.4, 14.6),
  ('946', '케첩 완자', '반찬', '돼지목살다진것 50g, 청경채 20g, 케첩 10g, 파다진것 5g, 생강다진것 5g, 전분 5g, 소금적당량', '["돼지목살다진것","청경채","케첩","파다진것","생강다진것","전분","소금"]'::jsonb, ARRAY['7ac59c14-e767-4f32-a2e5-d558c1a29dfb','0136fc6a-3a80-4f4c-8057-10bbf34ea572','4b410642-7bf9-45ad-9055-e7d9a34edaa1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','6613d1d9-80a2-4ce4-9d3d-647203197e53','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"그릇에 다진고기, 파, 생강, 소금, 물 전분을 넣어 골고루 버무린 뒤 케첩을 넣는다.","imageUrl":null},{"step":2,"text":"1을 한 방향으로 치댄 뒤 고기에 양념이 베도록 둔다.","imageUrl":null},{"step":3,"text":"청경채는 1cm 정사각형 모양으로 썬다.","imageUrl":null},{"step":4,"text":"2에 끈기가 생기도록 다시 치대준 뒤 지름 1.5cm의 완자 모양으로 빚는다.","imageUrl":null},{"step":5,"text":"팬에 물을 넣고 끓으면 완자를 넣어 익힌다.","imageUrl":null},{"step":6,"text":"청경채를 넣고 살짝 끓인 뒤 소금으로 간을 하고 소스가 약간 남도록 더 끓인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053636_1416213396022.jpg', 142, 13.8, 10.8, 4.9, 156),
  ('947', '홍시 생밤 무침', '후식', '홍시 40g, 바나나 40g, 생밤 10g, 대추 5g, 호두 5g', '["홍시","바나나","생밤","대추","호두"]'::jsonb, ARRAY['2db5cf59-b4ac-4d7b-8e13-68d143e5f34a','1a4b39f8-b581-46dc-bd7e-289cd6160711','b371c5d2-f12b-47ee-9a87-26efd09db09d','7651578f-1206-499d-a04c-15f034d4cae2']::uuid[], '[{"step":1,"text":"홍시는 껍질을 제거하여 으깬다.","imageUrl":null},{"step":2,"text":"바나나는 체에 내린다.","imageUrl":null},{"step":3,"text":"1과 2를 잘 섞어준다.","imageUrl":null},{"step":4,"text":"생밤은 납작납작하게 썬다.","imageUrl":null},{"step":5,"text":"대추는 돌려 깎아 씨를 제거하고 채 썬다.","imageUrl":null},{"step":6,"text":"3과 4, 5를 잘 무쳐 그릇에 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053637_1416213397131.jpg', 118, 22.3, 2.1, 3.7, 6),
  ('948', '고구마 경단', '후식', '고구마 50g, 카스텔라 20g, 우유 5g, 버터 2g, 꿀 3g, 건포도 20g, 소금 적당량', '["고구마","카스텔라","우유","버터","꿀","건포도","소금"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','e937397f-54e2-49df-997a-f393c58360be','7aabd532-361f-4240-aa33-6bfa1be4bc4e','286d1783-cd34-4aae-ac8b-006529ec8bc5','1c1e5578-1128-45a4-bcaf-aae79de3639e','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"고구마를 찜통에 찐다.","imageUrl":null},{"step":2,"text":"고구마의 껍질을 벗기고 체에 곱게 내린다.","imageUrl":null},{"step":3,"text":"카스텔라는 윗면의 갈색 부분을 잘라내고 믹서에 곱게 갈아 가루로 만든다.","imageUrl":null},{"step":4,"text":"2에 우유와 버터, 꿀, 소금을 넣고 섞어 반죽한다.","imageUrl":null},{"step":5,"text":"3의 반죽 속에 건포도를 1~2개 넣고 경단을 만든다.","imageUrl":null},{"step":6,"text":"경단에 카스텔라 가루를 묻힌다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053638_1416213398255.jpg', 209, 44, 2.7, 3.5, 51),
  ('949', '두부 깻잎 과자', '후식', '두부 30g, 깻잎 10g, 밀가루박력분 10g, 베이킹파우더 2g, 설탕 10g, 달걀 20g, 검은깨 3g, 소금적당량', '["두부","깻잎","밀가루박력분","베이킹파우더","설탕","달걀","검은깨","소금"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','325279ee-6de6-4d84-96a0-16af87dfdbc6','06e6f3e7-0293-469d-a338-11a610f3e71b','c7d438a6-34d6-423f-905d-446b839e2f39','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"두부는 면보를 이용해 물기를 꼭 짠 후 곱게 으깬다.","imageUrl":null},{"step":2,"text":"밀가루와 베이킹파우더를 섞어 체에 내린다.","imageUrl":null},{"step":3,"text":"으깬 두부를 볼에 담고 설탕, 달걀, 검은깨를 넣고 거품기로 잘 저어준다.","imageUrl":null},{"step":4,"text":"3에 채 썬 깻잎을 넣은 뒤 2의 밀가루를 넣어 반죽한다.","imageUrl":null},{"step":5,"text":"도마에 밀가루를 살짝 뿌리고 4를 밀대로 2mm 두께로 민 뒤 너비 1cm, 길이 4cm의 직사각형으로 자른다.","imageUrl":null},{"step":6,"text":"자른 반죽을 오븐팬에 올려 180℃로 예열된 오븐에 10분간 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053639_1416213399348.jpg', 150, 20.6, 7.1, 4.9, 190),
  ('950', '두부양갱', '후식', '치자 2g, 백련초가루 1g, 두부 30g, 한천 2g, 설탕 10g, 물 40g', '["치자","백련초가루","두부","한천","설탕","물"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"치자를 따뜻한 물에 담궈 색을 우려내고, 백련초가루는 물에 푼다.","imageUrl":null},{"step":2,"text":"두부는 면보에 물기를 짠 뒤 칼로 으깬다.","imageUrl":null},{"step":3,"text":"두 개의 냄비에 한천을 필요량 만큼 넣고 1을 각각 넣고 30분 정도 불린다.","imageUrl":null},{"step":4,"text":"3에 으깬 두부를 반씩 나누어 넣고 설탕을 넣은 뒤 골고루 섞는다.","imageUrl":null},{"step":5,"text":"4를 모양 틀에 넣고 냉장고에서 굳힌다.","imageUrl":null},{"step":6,"text":"양갱이 굳으면 틀 째 미지근한 물에 담궈 뒤집어 뺸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053640_1416213400394.jpg', 67, 11.9, 2.8, 1.7, 2.5),
  ('951', '멸치 누룽지과자', '후식', '밥 70g, 잔멸치 20g, 통깨 5g, 설탕 5g', '["밥","잔멸치","통깨","설탕"]'::jsonb, ARRAY['ecb35816-34ae-4c4c-867a-e3f84db92755','dd2eee03-8bbf-44ff-8a7f-ed1443986711','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"잔멸치는 잡티를 제거하고 기름을 두르지 않은 팬에서 살짝 볶는다.","imageUrl":null},{"step":2,"text":"고슬고슬하게 지은 밥에 1과 통깨, 설탕을 넣고 골고루 섞는다.","imageUrl":null},{"step":3,"text":"사각 틀에 2를 넣고 랩을 씌워 밀대로 평평하게 민다.","imageUrl":null},{"step":4,"text":"3을 바람이 잘 통하는 곳에서 건조 시킨다.","imageUrl":null},{"step":5,"text":"175℃로 예열된 오븐에 4를 넣고 밥이 바삭해질 때 까지 굽는다.","imageUrl":null},{"step":6,"text":"먹기 좋은 크기로 부숴 접시에 담고 설탕을 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053641_1416213401737.jpg', 191, 29.4, 11.6, 4, 177),
  ('952', '복숭아 화채', '후식', '오미자 5g, 천도복숭아 30g, 배 10g, 설탕 10g, 물 45g, 잣 1g 설탕시럼 설탕과 물을 동량으로 하여 중불에서 서서히 녹인다. 기호에 맞게 만든다.', '["오미자","천도복숭아","배","설탕","물","잣"]'::jsonb, ARRAY['45780aea-56ef-4a8b-875a-65e3e61c4a78','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b','bbbbd533-8922-4dac-9e4c-cd93ea710c92']::uuid[], '[{"step":1,"text":"오미자에 7배의 물에 8시간 담궈 맛과 색이 우러나도록 한다.","imageUrl":null},{"step":2,"text":"천도복숭아는 사방 0.5cm의 주사위모양으로 썰어 설탕을 뿌려 30분 정도 절인다.","imageUrl":null},{"step":3,"text":"배를 모양 틀로 찍어 0.3cm 두께로 썰어 설탕에 절인다.","imageUrl":null},{"step":4,"text":"오미자 국물을 면보에 거르고 시럽으로 단맛을 맞춘다.","imageUrl":null},{"step":5,"text":"4에 복숭아와 배를 넣는다.","imageUrl":null},{"step":6,"text":"5에 잣과 얼음을 띄운다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053642_1416213402814.jpg', 73, 16.7, 1.3, 1.2, 2),
  ('953', '사과 포도주스 조림', '후식', '사과 60g, 포도주스 60g, 계피가루 2g, 아이스크림 30g', '["사과","포도주스","계피가루","아이스크림"]'::jsonb, ARRAY['c85a52b9-c3b4-4a76-951c-bb40edeb3adb','483ecbd5-47a4-4fb5-bfee-852bded6c1dd','5205f393-c02b-4b09-a2d6-42629f7401b9']::uuid[], '[{"step":1,"text":"사과씨를 통째로 제거한다.","imageUrl":null},{"step":2,"text":"1을 2cm 두께로 썬다.","imageUrl":null},{"step":3,"text":"냄비에 사과와 포도주스를 넣고 중불에서 서서히 졸인다.","imageUrl":null},{"step":4,"text":"졸여진 사과를 냉장고에 넣어 시원하게 한다.","imageUrl":null},{"step":5,"text":"접시에 사과를 담고 계피가루를 뿌린다.","imageUrl":null},{"step":6,"text":"5에 아이스크림을 떠서 위에 얹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053643_1416213403845.jpg', 135, 25.1, 1.8, 4.2, 25),
  ('954', '홍시 쉐이크', '후식', '냉동홍시 70g, 오미자 5g, 물 35g, 레몬즙 4g, 꿀 5g, 민트 1g', '["냉동홍시","오미자","물","레몬즙","꿀","민트"]'::jsonb, ARRAY['2db5cf59-b4ac-4d7b-8e13-68d143e5f34a','45780aea-56ef-4a8b-875a-65e3e61c4a78','94786475-832c-4f97-aab7-bf6fbbe2236b','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','286d1783-cd34-4aae-ac8b-006529ec8bc5','eb4621c9-6ade-40ba-966c-32edd1754669']::uuid[], '[{"step":1,"text":"냉동 홍시의 껍질을 벗기고 씨를 뺀다.","imageUrl":null},{"step":2,"text":"1을 잘게 자른다.","imageUrl":null},{"step":3,"text":"오미자를 7배의 물에 8시간 이상 우려 맛과 색이 우러나오도록 한다.","imageUrl":null},{"step":4,"text":"믹서에 홍시, 오미자물, 꿀, 레몬즙을 넣어 함께 갈아준다.","imageUrl":null},{"step":5,"text":"4를 컵에 담는다.","imageUrl":null},{"step":6,"text":"민트로 장식한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053645_1416213405140.jpg', 70, 18.3, 1.1, 0.6, 5),
  ('956', '김치떡', '후식', '메밀가루 20g, 찹쌀가루 20g, 밀가루 20g, 물 20g, 소금적당량  김치 20g, 오징어 30g  설탕 5g, 깨소금 1g, 파다진것 4g, 마늘다진것 3g, 참기름 1g', '["메밀가루","찹쌀가루","밀가루","물","소금적당량  김치","오징어","깨소금","파다진것","마늘다진것","참기름"]'::jsonb, ARRAY['4cb11562-015f-4ab5-969f-0ea8483a0b42','aab3b0b9-d346-4697-a1c8-1b1530153788','94786475-832c-4f97-aab7-bf6fbbe2236b','4d148f68-08e0-4599-8953-595db492bf23','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"메밀가루, 밀가루, 찹쌀가루에 소금을 넣어 체에 내린 뒤 끓는 물을 넣어 익반죽한다.","imageUrl":null},{"step":2,"text":"김치는 송송 썰고 오징어는 껍질을 벗겨 굵게 다진다.","imageUrl":null},{"step":3,"text":"가열된 팬에 기름을 두르고 김치를 볶은 다음 오징어를 넣고 볶아 식힌다.","imageUrl":null},{"step":4,"text":"반죽을 떼어 10cm 둥근 모양으로 빚은 다음 가운데에 3을 넣고 반달모양으로 접어 모양을 만든다.","imageUrl":null},{"step":5,"text":"김이 오른 찜통에 면보를 깔고 14분간 찐 다음 5분 정도 뜸을 들인다.","imageUrl":null},{"step":6,"text":"한 김 식힌 뒤 접시에 담아낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053647_1416213407139.jpg', 302, 53.4, 13.7, 3.4, 293),
  ('958', '누룽지 피자', '후식', '잡곡밥흑미 검은콩 50g, 피자치즈 20g, 양파 10g, 청 피망 8g, 홍 피망 8g, 양송이 10g, 햄 5g, 캔옥수수 10g, 실파 5g 마늘다진것 2g, 양파다진것 5g, 쇠고기다진것 5g, 토마토케첩 8g, 설탕 3g, 간장 1g, 소금적당량, 후춧가루 적당량', '["잡곡밥흑미 검은콩","피자치즈","양파","청 피망","홍 피망","양송이","햄","캔옥수수","실파","양파다진것","쇠고기다진것","토마토케첩","설탕","간장","소금","후춧가루"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','df459e6f-3515-45d5-8c9a-9d37b6249379','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','4b410642-7bf9-45ad-9055-e7d9a34edaa1','1c49d1f4-5781-474d-818d-bd7002a4dc0b','0136fc6a-3a80-4f4c-8057-10bbf34ea572','06e6f3e7-0293-469d-a338-11a610f3e71b','f175019d-5a93-4cd4-aabc-e7e79445f15a','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"잡곡밥에 소량의 물을 넣고 밥알을 풀어준다.","imageUrl":null},{"step":2,"text":"기름을 두르지 않은 팬에 1을 0.4cm두께로 노릇하게 양면을 굽는다.","imageUrl":null},{"step":3,"text":"양파와 청, 홍피망, 햄은 적당한 크기로 썰고 캔 옥수수는 물기를 뺀다.","imageUrl":null},{"step":4,"text":"냄비에 식용유를 두르고 다진 마늘과 다진 양파, 다진 소고기를 넣고 볶은 뒤 토마토 케첩과 물을 약간 넣어 졸이면서 설탕, 간장, 후춧가루로 간한다.","imageUrl":null},{"step":5,"text":"누룽지에 4를 골고루 펴 바르고 그 위에 토핑 재료, 피자치즈, 송송 썬 실파를 뿌린다.","imageUrl":null},{"step":6,"text":"5번을 예열된 오븐에 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053649_1416213409310.jpg', 280, 57.4, 10.9, 2.6, 350),
  ('959', '단호박 새우찜', '반찬', '단호박작은것 125g, 잔새우살다진것 20g, 두부 20g, 건표고버섯 10g, 청피망다진것 10g, 홍피망다진것 10g, 실파 5g, 밀가루 8g, 마늘 3g, 깨소금 1g, 참기름 1g, 소금 1g, 흰후춧가루 1g', '["단호박작은것","잔새우살다진것","두부","건표고버섯","청피망다진것","홍피망다진것","실파","밀가루","마늘","깨소금","참기름","소금","흰후춧가루"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','66458b1b-c92f-43fa-8eba-e428892ce88a','df459e6f-3515-45d5-8c9a-9d37b6249379','4b410642-7bf9-45ad-9055-e7d9a34edaa1','aab3b0b9-d346-4697-a1c8-1b1530153788','fc6e31ce-388e-45cd-956b-b238b9134eb1','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"단호박은 표면을 깨끗하게 씻어 물기를 제거하고 꼭지 부분의 윗면을 자르고 수저로 속을 파낸 후 소금을 뿌려 놓는다.","imageUrl":null},{"step":2,"text":"새우살은 다지고 두부는 면보로 싸서 물기를 제거하고 곱게 으깨고 불린 건표고버섯과 청, 홍피망은 곱게 다지고 실파는 송송 썬다.","imageUrl":null},{"step":3,"text":"2의 재료를 한 데 섞고 소금, 다진 마늘, 깨소금, 참기름, 흰 후춧가루를 넣고 양념하여 소를 만든다.","imageUrl":null},{"step":4,"text":"1의 내부에 수분을 제거한다.","imageUrl":null},{"step":5,"text":"4의 안쪽에 밀가루를 살짝 뿌리고 밀가루가 골고루 잘 묻도록 한다.","imageUrl":null},{"step":6,"text":"준비된 소를 채운 후 잘라둔 꼭지 부분의 뚜껑을 덮어 김 오른 찜통에 20분가량 찐 뒤 4~6등분 하여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053650_1416213410481.jpg', 202, 38.6, 11.1, 3.5, 395),
  ('960', '두부 샌드위치', '반찬', '두부 80g, 키위 20g, 오렌지 20g, 토마토 20g, 바나나 20g, 사과 20g, 꿀 10g, 소금적당량, 식용유 5g', '["두부","키위","오렌지","토마토","바나나","사과","꿀","소금","식용유"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','e748d9a5-9c62-4d33-918a-b1b8e9a1f00b','19eb37dc-2b1c-4e89-a931-31a38ae60561','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','1a4b39f8-b581-46dc-bd7e-289cd6160711','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','286d1783-cd34-4aae-ac8b-006529ec8bc5','2cf0c12b-f248-4012-8f53-303c730a7b3d','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"두부는 3cm 주사위모양으로 썰고 소금을 뿌려 간을 한다.","imageUrl":null},{"step":2,"text":"과일은 5mm 주사위모양으로 썬 뒤 꿀을 넣고 버무린다.","imageUrl":null},{"step":3,"text":"기름을 두른 팬에 1을 넣고 5면을 노릇하게 지진 뒤 종이타월로 기름기를 제거한다.","imageUrl":null},{"step":4,"text":"3의 지지지 않은 한 쪽 면을 숟가락을 이용해 뚫리지 않게 조심스럼게 파낸다.","imageUrl":null},{"step":5,"text":"속을 파낸 두부에 2를 채워 넣는다.","imageUrl":null},{"step":6,"text":"민트로 장식한다","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053651_1416213411605.jpg', 190, 22.3, 8.3, 9.6, 8),
  ('961', '라이스페이퍼 새우롤', '반찬', '새우 20g, 홍피망 5g, 팽이버섯 5g, 숙주 15g, 무순 3g, 상추 5g, 차이브 5g, 쌀국수가는것 15g, 라이스페이퍼 20g 양파 5g, 마늘 1g, 홍고추 1g, 청고추 1g, 물전분 약간, 물 약간, 식초 3g, 설탕 1g, 고추기름 약간', '["새우","홍피망","팽이버섯","숙주","무순","상추","차이브","쌀국수가는것","라이스페이퍼","마늘","홍고추","청고추","물전분","물","식초","설탕","고추기름"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','df459e6f-3515-45d5-8c9a-9d37b6249379','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','2647e451-e8f5-4fce-91bd-8beabb2384d8','f09d1d41-602a-441c-a7bc-520311490ceb','1389717e-81e4-4350-96d4-d627d851aa10','241e49d7-4aa4-4411-8ded-350a16b41222','fc6e31ce-388e-45cd-956b-b238b9134eb1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','6613d1d9-80a2-4ce4-9d3d-647203197e53','94786475-832c-4f97-aab7-bf6fbbe2236b','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','3a2bfe83-465c-4aaf-bde6-1c34303b15b7']::uuid[], '[{"step":1,"text":"새우는 끓는 물에 대친 뒤 찬물에 담궈 식히고 껍질을 벗긴다.","imageUrl":null},{"step":2,"text":"홍피망은 얇게 채 썰고 팽이버섯은 밑동을 잘라 준비하고 숙주는 거두절미하여 끓는 물에 데친 뒤 찬물에 식혀서 물기를 빼고 상추는 채 썬다.","imageUrl":null},{"step":3,"text":"쌀국수를 물에 불렸다가 끓는 물에 데친 뒤 찬물에 식혀 물기를 제거한다.","imageUrl":null},{"step":4,"text":"따뜻한 물에 라이스페이퍼를 담궜다가 꺼내 면보 위에 놓고 물기를 살짝 제거하고 1, 2, 3을 올리고 조심스럽게 말아준다.","imageUrl":null},{"step":5,"text":"마늘은 다지고 양파, 홍고추, 청고추는 0.3mm로 잘게 썬다.","imageUrl":null},{"step":6,"text":"팬에 고추기름을 두르고 다진 마늘을 볶다가 양파를 넣고 청, 홍고추를 넣어 살짝 볶은 뒤 물, 식초, 설탕을 넣고 물전분으로 농도를 맞춘다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053652_1416213412573.jpg', 141.6, 22.9, 7.2, 2.4, 86),
  ('962', '레몬, 파슬리 빵가루를 입힌 도미', '반찬', '도미 40g, 마늘다진것 2g, 빵가루 10g, 버터 1g, 레몬주스 3g, 레몬제스트 2g, 파슬리다진것 2g, 소금적당량, 후추적당량', '["도미","마늘다진것","빵가루","버터","레몬주스","레몬제스트","파슬리다진것","소금","후추"]'::jsonb, ARRAY['fc6e31ce-388e-45cd-956b-b238b9134eb1','45080597-55fa-42dc-aa65-12d7694e4b7e','7aabd532-361f-4240-aa33-6bfa1be4bc4e','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','4362c386-a37c-44cd-9254-fafd74712a09','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"도미에는 소금과 후추로 밑간을 하고 마늘, 파슬리는 다진다.","imageUrl":null},{"step":2,"text":"버터를 두른 팬에 다진 마늘을 넣고 마늘 향을 낸 버터물을 만든다.","imageUrl":null},{"step":3,"text":"2에 빵가루를 섞어 믹싱볼로 옮겨 담는다.","imageUrl":null},{"step":4,"text":"3에 다진 파슬리, 레몬주스, 레몬제스트, 소금, 후추를 넣고 고무주걱으로 잘 섞는다.","imageUrl":null},{"step":5,"text":"도미를 양념하고 도미위에 4을 얹는다.","imageUrl":null},{"step":6,"text":"5를 오븐에 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053653_1416213413557.jpg', 88, 8.4, 10, 1.7, 62),
  ('964', '롤피자', '후식', '밀가루중력분 80g, 이스트 2g, 따뜻한물 20g, 소금 1g, 올리브오일 1g, 청피망 10g, 홍피망 10g, 베이컨 5g, 양파 10g, 양송이 5g, 토마토소스 5g, 모짜렐라 치즈 12g, 바질 1g, 오레가노 1g, 파마산치즈 2g', '["밀가루중력분","이스트","따뜻한물","소금","올리브오일","청피망","홍피망","베이컨","양파","양송이","토마토소스","모짜렐라 치즈","바질","오레가노","파마산치즈"]'::jsonb, ARRAY['325279ee-6de6-4d84-96a0-16af87dfdbc6','2cf0c12b-f248-4012-8f53-303c730a7b3d','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','df459e6f-3515-45d5-8c9a-9d37b6249379','bd88bfed-198e-4891-9430-06660bdeaa9a','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','76e95535-f965-4685-a7a6-55ae26aa202c','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','ba9e5a79-cab3-4af0-942b-0b35fd745150','cdbae946-7ca4-4f8d-8a3c-5bb295961ad6']::uuid[], '[{"step":1,"text":"볼에 밀가루를 담고 가운데에 웅덩이를 만들어 따뜻한 물과 이스트를 넣어 녹인 후 소금을 넣고 밀가루를 조금씩 섞으며 반죽을 한다.","imageUrl":null},{"step":2,"text":"반죽이 하나로 뭉쳐지면 랩으로 싸서 따뜻한 곳에서 30분 정도 발효시킨다.","imageUrl":null},{"step":3,"text":"발효된 반죽을 밀대를 이용하여 넓게 편다.","imageUrl":null},{"step":4,"text":"청, 홍피망은 꼭지부분을 썰어내고 링 모양으로 썰어 심지를 제거하고 베이컨, 양파, 양송이는 슬라이스 한다.","imageUrl":null},{"step":5,"text":"3을 오븐용 팬에 옮긴 뒤 토마토소스를 바르고 준비된 재료들과 피자치즈를 올린다.","imageUrl":null},{"step":6,"text":"반죽을 말아서 윗부분에 칼집을 넣은 뒤 175℃로 예열된 오븐에 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053655_1416213415836.jpg', 374, 63.8, 13.9, 5, 524),
  ('2991', '닭곰탕', '국&찌개', ' 닭 정육(90g), 대파(10g), 무(70g), 양파(20g), 홍고추(5g), 마늘(3g), 청양고추(5g)
, 닭뼈(200g), 다시마(3g), 대파(5g), 마늘(2g), 물(600g)
, 후추(5g)', '["닭 정육","대파","무","양파","홍고추","마늘","청양고추","닭뼈","다시마","물","후추"]'::jsonb, ARRAY['4b410642-7bf9-45ad-9055-e7d9a34edaa1','f80c9a7d-1510-44e2-a82b-28b9f684e191','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','30b5d53c-d247-4f04-9b50-c0f728e65cf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','94786475-832c-4f97-aab7-bf6fbbe2236b','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"닭정육과 닭뼈를 깨끗이 씻어 물, 마늘, 대파, 다시마를 넣고 육수를 끓인다.","imageUrl":null},{"step":2,"text":"닭 정육이 익으면 건져 잘게 찢는다.","imageUrl":null},{"step":3,"text":"무는 나박썰기하고 대파와 홍고추, 청양고추는 어슷썰기 하고 양파와 마늘은 다진다.","imageUrl":null},{"step":4,"text":"육수가 우러나면 체에 육수를 걸러낸다.","imageUrl":null},{"step":5,"text":"냄비에 마늘을 볶다가 닭고기를 넣고 함께 볶은 뒤 육수와 손질한 채소를 넣어 푹 끓인다.","imageUrl":null},{"step":6,"text":"후추로 간을 해 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306031431_1678083271333.jpg', 46.5, 2.5, 7.6, 0.7, 63.5),
  ('3079', '미나리버섯고기말이&산채소스', '반찬', '돈등심 80g, 새송이버섯 24g, 미나리 18g, 후추 0.3g, 찹쌀가루 15g, 참나물 5g, 취나물 5g, 올리브오일 10g, 땅콩 2g, 파마산치즈 1g, 마늘 1g', '["돈등심","새송이버섯","미나리","후추","찹쌀가루","참나물","취나물","올리브오일","땅콩","파마산치즈","마늘"]'::jsonb, ARRAY['3f94371a-728f-49ae-8ea9-1a1e87b68048','dc7b2b73-74de-4fb8-9274-a5967ca444f9','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','4cb11562-015f-4ab5-969f-0ea8483a0b42','09065cd3-28cc-4a82-8b3e-5121054c7482','50e01736-309e-4164-8982-c5239f6dc17f','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"돈등심은 널찍하게 성형한다.","imageUrl":null},{"step":2,"text":"새송이 버섯은 길게 채썰고, 미나리도 비슷한 사이즈로 썰어 준다.","imageUrl":null},{"step":3,"text":"고기에 미나리, 새송이를 감싸 말아 찹쌀가루를 묻혀 굽는다.","imageUrl":null},{"step":4,"text":"참나물, 취나물, 올리브오일, 땅콩, 마늘, 후추를 믹서에 갈아 소스를 만든다.","imageUrl":null},{"step":5,"text":"소스에 파마산 치즈를 섞어준다.","imageUrl":null},{"step":6,"text":"구워진 고기에 소스를 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313010600_1584072360556.jpg', 287.6, 8.7, 31.6, 14.1, 83.6),
  ('3174', '오이파프리카새콤무침', '반찬', '오이 10g, 파프리카(빨강/노랑) 각 5g, 식초 2g, 설탕 2g', '["오이","파프리카 각","식초","설탕"]'::jsonb, ARRAY['9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"오이는 굵은 소금으로 문질러 깨끗이 씻는다.","imageUrl":null},{"step":2,"text":"오이를 적당한 두께로 썰고 4등분 한다.","imageUrl":null},{"step":3,"text":"파프리카는 깨끗이 씻은 후 씨를 제거한다.","imageUrl":null},{"step":4,"text":"파프리카를 적당한 크기로 썬다.","imageUrl":null},{"step":5,"text":"식초, 설탕, 물을 섞어 단촛물을 만든다.","imageUrl":null},{"step":6,"text":"단촛물에 오이, 파프리카를 버무린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128054738_1611823658692.JPG', 11.45, 2.59, 0.18, 0.04, 1.05),
  ('3177', '양상추샐러드 & 과일드레싱', '반찬', ' 양상추(60g), 당근(10g), 적양배추(10g), 치커리(5g)
, 사과(20g), 파인애플(15g), 레몬즙(1g)', '["양상추","당근","적양배추","치커리","사과","파인애플","레몬즙"]'::jsonb, ARRAY['1389717e-81e4-4350-96d4-d627d851aa10','e38c12a7-43cb-421a-a36e-7ef0d32517fa','fd4254d4-2691-47e1-9367-c2b820ef8d00','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','c97290bd-7146-45bc-8e7f-28390e7a95b0','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"양상추는 깨끗이 씻어 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":2,"text":"당근과 적양배추는 곱게 채 썰고, 치커리는 잘게 썬다.","imageUrl":null},{"step":3,"text":"사과는 껍질과 심을 제거한 뒤 한입 크기로 썬다.","imageUrl":null},{"step":4,"text":"파인애플은 껍질과 심을 제거한 뒤 한입 크기로 썬다.","imageUrl":null},{"step":5,"text":"손질한 과일과 레몬즙을 믹서에 넣어 곱게 갈아 드레싱을 만든다.","imageUrl":null},{"step":6,"text":"양상추와 당근, 적양배추를 접시에 깔고 드레싱을 곁들여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230309/20230309093629_1678322189909.jpg', 57.4, 9.9, 1.9, 1.1, 33.8),
  ('3181', '시금치들깨무침', '반찬', '시금치 70g, 파 5g, 마늘 5g, 들깨가루 15g, 통깨 5g, 들기름 5g, 소금(데치는용) 5g', '["시금치","파","마늘","들깨가루","통깨","들기름","소금"]'::jsonb, ARRAY['9a7f4da6-531b-4478-89ff-d73beafcad1b','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','184687ba-0cba-4fec-bb21-33fe300c2073','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','f5534afd-2a26-4493-8ec1-fd680dcb3bef','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"파, 마늘은 다진다.","imageUrl":null},{"step":2,"text":"냄비에 물과 소금을 넣고 끓인다.","imageUrl":null},{"step":3,"text":"세척한 시금치를 데친다.","imageUrl":null},{"step":4,"text":"데친 시금치는 찬물에 헹구어 물기를 짠 다음 먹기 좋게 썬다.","imageUrl":null},{"step":5,"text":"시금치에 들깨가루, 파, 마늘, 통깨, 들기름을 넣고 무친다.","imageUrl":null},{"step":6,"text":"접시에 담아서 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129102439_1611883479294.jpg', 159.24, 12.03, 10.05, 7.88, 32.68),
  ('3281', '채소롤초밥', '밥', ' 가지(1개), 오이(1개), 밥(400g), 소금(0.4ts), 다시마가루(2Ts), 매실식초(2ts), 참기름(2Ts), 참깨(2Ts)', '["가지","오이","밥","소금","다시마가루","매실식초","참기름","참깨"]'::jsonb, ARRAY['3e12cf79-2cde-4309-9f7c-4eccce3fde28','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','ecb35816-34ae-4c4c-867a-e3f84db92755','2cf0c12b-f248-4012-8f53-303c730a7b3d','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"가지와 오이는 세로로 얇게 썬다.","imageUrl":null},{"step":2,"text":"얇게 썬 오이는 소금(0.2ts)에 10분간 절인 뒤 물기를 꼭 짠다.","imageUrl":null},{"step":3,"text":"얇게 썬 가지는 약한 불로 달군 마른 팬에 올려 앞뒤로 노릇하게 구워 꺼낸다.","imageUrl":null},{"step":4,"text":"밥에 남은 양념을 넣어 고루 섞는다.","imageUrl":null},{"step":5,"text":"소금에 절인 오이와 구운 가지 위에 밥을 한입 크기로 뭉쳐 올린다.","imageUrl":null},{"step":6,"text":"돌돌 말아 그릇에 담아 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr97hb', 384.1, 77.2, 7.5, 5.1, 267.4),
  ('3682', '초코바나나 두부크림빵', '후식', ' 박력 쌀가루 56g, 강력 밀가루 140g, 무가당 코코아가루① 8g, 드라이 이스트 16g, 소금 4g, 설탕 8g, 물 115ml, 바닐라 에센스 30g, 달걀 16g, 무염버터 22g, 바나나 98g, 두부 33g, 무가당 코코아가루② 12g, 알룰로스 30g, 달걀물 약간, 무염버터 약간', '["박력 쌀가루","강력 밀가루","무가당 코코아가루①","드라이 이스트","소금","설탕","물","바닐라 에센스","달걀","무염버터","바나나","두부","무가당 코코아가루②","알룰로스","달걀물"]'::jsonb, ARRAY['2cf0c12b-f248-4012-8f53-303c730a7b3d','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b','c7d438a6-34d6-423f-905d-446b839e2f39','7aabd532-361f-4240-aa33-6bfa1be4bc4e','1a4b39f8-b581-46dc-bd7e-289cd6160711','4566cac5-9166-4c0d-906a-bfc7360f8f5b','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"볼에 박력 쌀가루, 강력 밀가루, 무가당\r\n코코아가루①, 드라이 이스트, 소금,\r\n설탕, 물, 바닐라 에센스, 달걀을 넣고\r\n섞다가 무염버터를 넣으며\r\n한 덩어리가 될 때까지 반죽한 후\r\n상온에서 30분 동안 1차 발효한다.","imageUrl":null},{"step":2,"text":"믹서에 바나나, 물기를 제거한 두부,\r\n무가당 코코아가루②, 알룰로스를 넣고\r\n큰 덩어리가 없어질 정도로 살짝 갈아\r\n두부크림을 만든다.","imageUrl":null},{"step":3,"text":"반죽을 40g씩 분할하여 둥굴리기한 후\r\n상온에서 15분 동안 중간 발효한다.","imageUrl":null},{"step":4,"text":"반죽을 성형하여\r\n오븐 팬에 올리고 30°C에서\r\n20분 동안 2차 발효한다.","imageUrl":null},{"step":5,"text":"달걀물을 바르고 175°C로 예열한\r\n오븐에 12분 동안 구운 후 꺼내\r\n완전히 식힌다.","imageUrl":null},{"step":6,"text":"두부크림을 짤주머니에 담아 40g씩\r\n빵 속에 채우고 무염버터를 발라\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20251021/20251021023032_1761024632600.jpg', 246.5, 30.3, 8.3, 10.2, 138.1),
  ('965', '미니 떡갈비', '반찬', '쇠고기샄코기 80g, 새송이버섯 40g, 밀가루 4g, 잣가루 1g,  간장 5g, 배즙 5g, 양파즙 5g, 꿀 4g, 다진 파 5g, 다진 마늘 3g, 깨소금 1g, 참기름 1g, 후춧가루 1g', '["쇠고기샄코기","새송이버섯","밀가루","잣가루","간장","배즙","양파즙","꿀","다진 파","다진 마늘","깨소금","참기름","후춧가루"]'::jsonb, ARRAY['3f94371a-728f-49ae-8ea9-1a1e87b68048','aab3b0b9-d346-4697-a1c8-1b1530153788','f175019d-5a93-4cd4-aabc-e7e79445f15a','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','286d1783-cd34-4aae-ac8b-006529ec8bc5','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"소고기는 곱게 다진다.","imageUrl":null},{"step":2,"text":"다진 소고기에 떡갈비 양념을 넣고 골고루 치대 양념한다.","imageUrl":null},{"step":3,"text":"새송이버섯은 폭 1.5cm, 길이 6cm로 썰어 밀가루를 묻힌다.","imageUrl":null},{"step":4,"text":"3에 2를 버섯 위, 아래로 1cm를 남기고 감싸듯이 부쳐 떡갈비를 만든다.","imageUrl":null},{"step":5,"text":"팬에 앞뒤로 타지 않도록 굽는다.","imageUrl":null},{"step":6,"text":"잣가루를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053656_1416213416929.jpg', 145, 13.5, 15, 3.9, 308),
  ('966', '배추 달걀볶음', '반찬', '배추 50g, 달걀 30g, 돼지고기 20g, 파 3g, 생강다진것 2g, 간장 2g, 목이버섯 10g, 닭육수 10g, 물전분 10g, 식용유 3g, 소금적당량', '["배추","달걀","돼지고기","파","생강다진것","간장","목이버섯","닭육수","물전분","식용유","소금"]'::jsonb, ARRAY['e116f85b-0eaa-40cb-8107-df5ec8486ad4','c7d438a6-34d6-423f-905d-446b839e2f39','70e914d4-0d03-4202-8b66-81bd8499aa08','4b410642-7bf9-45ad-9055-e7d9a34edaa1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','f175019d-5a93-4cd4-aabc-e7e79445f15a','aad7c333-f1f0-46c1-8313-37cc64d689dc','a4c37075-c03b-47bb-8aed-5e907620f5d2','6613d1d9-80a2-4ce4-9d3d-647203197e53','a7a59e81-de3d-4893-b56a-b2218732a25b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"배추는 잎을 떼서 크게 썬 다음 3cm 길이로 결대로 찢는다.","imageUrl":null},{"step":2,"text":"기름을 넣어 가열 된 팬에 배추를 넣고 살짝 볶아 낸 후 수분을 제거한다.","imageUrl":null},{"step":3,"text":"달걀을 풀어 팬에 익힌다.","imageUrl":null},{"step":4,"text":"채 썬 돼지고기를 팬에 볶고 파, 다진 생강, 간장을 넣고 다시 볶는다.","imageUrl":null},{"step":5,"text":"4에 목이버섯, 배추, 달걀을 넣고 잘 섞는다.","imageUrl":null},{"step":6,"text":"5에 육수, 소금, 물전분을 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053658_1416213418057.jpg', 1311, 7.3, 8.3, 7.5, 188),
  ('967', '사과와 양파를 곁들인 돼지등심 요리', '반찬', '돼지등심 100g, 오레가노마른것 1g, 바질마른것 1g, 올리브오일 1g, 양파 15g, 사과 20g, 소금적당량, 통후추부순것 2g', '["돼지등심","오레가노마른것","바질마른것","올리브오일","양파","사과","소금","통후추부순것"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','cdbae946-7ca4-4f8d-8a3c-5bb295961ad6','ba9e5a79-cab3-4af0-942b-0b35fd745150','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"돼지등심은 4cm 정도 두께로 썬다.","imageUrl":null},{"step":2,"text":"볼에 건오레가노, 건바질, 소금, 통후추 간 것을 섞어 허브 믹스를 만들어 1에 골고루 묻힌다.","imageUrl":null},{"step":3,"text":"팬을 가열하여 올리브오일을 두르고 등심의 양면이 갈색이 되게 구운 뒤 알루미늄 호일에 싸서 오븐에서 완전히 익힌다.","imageUrl":null},{"step":4,"text":"양파는 슬라이스하고, 사과는 껍질과 씨를 제거한 후 얇게 슬라이스 한다.","imageUrl":null},{"step":5,"text":"또 다른 팬에 기름을 두르고 고기가 완전히 익을 동안 양파와 사과를 옅은 갈색이 나도록 볶아준다.","imageUrl":null},{"step":6,"text":"고기가 다 익었으면 꺼내서 적당한 두께로 썰고 볶은 양파와 사과를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053658_1416213418883.jpg', 294, 6, 17.9, 21, 36),
  ('969', '새우 속을 채운 리치와 감자튀김', '반찬', '새우 60g, 달걀흰자 10g, 실파 5g, 물밤다진것 15g, 소금적당량, 후추적당량, 리치캔 35g, 감자 30g, 전분 3g, 튀김기름 10g  올ㄹ브오일 1g, 다진 양파 3g, 다진생강 1g, 다진마늘 1g, 고추기름 0.5g, 식초 3g, 설탕 1.5g, 소금적당량, 후추적당량, 전분 1g, 다진 레몬껍질 약간', '["새우","달걀흰자","실파","물밤다진것","소금","후추","리치캔","감자","전분","튀김기름","다진 양파","다진생강","다진마늘","고추기름","식초","설탕","다진 레몬껍질"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','c7d438a6-34d6-423f-905d-446b839e2f39','4b410642-7bf9-45ad-9055-e7d9a34edaa1','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','20894da1-739d-4d52-b5fe-4943bd3492d5','6613d1d9-80a2-4ce4-9d3d-647203197e53','a7a59e81-de3d-4893-b56a-b2218732a25b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','3a2bfe83-465c-4aaf-bde6-1c34303b15b7','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"새우는 잘게 다지고 흰자, 소금, 후추와 함께 섞어서 간이 배도록 한다.","imageUrl":null},{"step":2,"text":"다진 물밤과 실파를 1과 섞어준 뒤 종이타월을 이용해서 물기를 제거한 리치의 속의 채운다.","imageUrl":null},{"step":3,"text":"속이 채워진 리치에 전분을 묻혀 기름에 튀긴다.","imageUrl":null},{"step":4,"text":"가열된 팬에 올리브오일을 두르고 양파, 마늘, 생강 다진 것을 살짝 볶는다.","imageUrl":null},{"step":5,"text":"4에 물, 고추기름, 설탕, 소금, 후춧가루를 넣고 간을 한 뒤 물전분으로 농도를 맞춘다.","imageUrl":null},{"step":6,"text":"감자는 껍질을 벗겨 채칼로 얇게 슬라이스 한 뒤 물에 담궈 전분을 빼고 튀겨 접시에 깔고 3, 4를 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053700_1416213420967.jpg', 258, 24.5, 14.7, 11.5, 196),
  ('970', '생선살 완자 찹쌀 찜', '반찬', '찹쌀 30g, 치자 5g, 시금치 10g, 당근 10g, 흰살생선 100g  달걀흰자 15g, 생강즙 2g, 소금적당량, 흰후춧가루 적당량, 전분 3g', '["찹쌀","치자","시금치","당근","흰살생선","생강즙","소금","흰후춧가루","전분"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','9a7f4da6-531b-4478-89ff-d73beafcad1b','e38c12a7-43cb-421a-a36e-7ef0d32517fa','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6613d1d9-80a2-4ce4-9d3d-647203197e53']::uuid[], '[{"step":1,"text":"찹쌀을 깨끗이 씻어 40분 가량 치차 물에 불린 뒤 물기를 빼고 소금을 약간 넣어 버무리고 마른 면보로 옮겨 수분을 빼면서 반 정도 으깬다.","imageUrl":null},{"step":2,"text":"시금치는 소금물에 데쳐 냉수에 헹군 뒤 물기를 짜서 다지고 당근도 잘게 다진다.","imageUrl":null},{"step":3,"text":"흰 살 생선은 면보로 물기를 꼭 짠 다음 곱게 다지고 끈기가 생기도록 치대면서 생강즙, 소금, 후춧가루를 넣는다.","imageUrl":null},{"step":4,"text":"3에 달걀 흰자, 전분을 첨가하여 계속 치대 끈기가 생기도록 한 뒤 다져놓은 시금치와 당근을 넣어 섞는다.","imageUrl":null},{"step":5,"text":"4를 조금씩 떼어 생선 완자를 만든 뒤 1을 묻힌다.","imageUrl":null},{"step":6,"text":"찜통에 젖은 면보를 깔고 생선 완자가 서로 붙지 않도록 놓고 20분 정도 찐다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053702_1416213422390.jpg', 213, 30, 20.1, 0.7, 263),
  ('972', '서양식 씨리얼(뮤즐리)', '일품', '오트밀 15g, 꿀 5g, 플레인 요거트 18g, 아몬드 5g, 사과 8g, 건포도 4g, 우유 30g, 계피가루적당량, 바나나 10g, 키위 10g', '["오트밀","꿀","플레인 요거트","아몬드","사과","건포도","우유","계피가루","바나나","키위"]'::jsonb, ARRAY['286d1783-cd34-4aae-ac8b-006529ec8bc5','bb41a88a-ea2b-4830-876d-91fe7f640296','52ba316f-8e7f-415f-8079-9a9d674c9adf','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','1c1e5578-1128-45a4-bcaf-aae79de3639e','e937397f-54e2-49df-997a-f393c58360be','5205f393-c02b-4b09-a2d6-42629f7401b9','1a4b39f8-b581-46dc-bd7e-289cd6160711','e748d9a5-9c62-4d33-918a-b1b8e9a1f00b']::uuid[], '[{"step":1,"text":"아몬드는 기름 두르지 않은 팬에 옅은 갈색이 나도록 볶는다.","imageUrl":null},{"step":2,"text":"사과는 껍질을 제거하고 주사위모양으로 썬다.","imageUrl":null},{"step":3,"text":"바나나와 키위는 껍질을 제거하고 사과와 같은 크기로 썬다.","imageUrl":null},{"step":4,"text":"볼에 꿀, 플레인 요거트, 우유를 넣고 잘 섞는다.","imageUrl":null},{"step":5,"text":"깨끗한 볼에 오트밀을 담고 4를 넣어 잘 섞어준다.","imageUrl":null},{"step":6,"text":"5에 준비된 과일과 아몬드, 건포도를 올리고 기호에 따라 계피가루를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053704_1416213424592.jpg', 159, 25.8, 5.2, 4.8, 27),
  ('973', '수퍼 브리또', '반찬', '양파 10g, 할라피뇨 3g, 쇠고기갈은것 10g, 토마토콩카세 10g, 양상추 10g, 올리브오일 1g, 또띠아8인치 30g, 아보카도 6g, 사워크림 3g, 소금적당량, 후춧가루 적당량강낭콩 40g, 베이컨 2g, 마늘 1g, 양파 10g, 바질마른것 약간  배 3g, 오렌지 3g, 레몬주스 2g, 파프리카 가루 1g', '["양파","할라피뇨","쇠고기갈은것","토마토콩카세","양상추","올리브오일","또띠아","아보카도","사워크림","소금","후춧가루 적당량강낭콩","베이컨","마늘","바질마른것 약간  배","오렌지","레몬주스","파프리카 가루"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','1389717e-81e4-4350-96d4-d627d851aa10','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','7ccfd335-1d3f-4e14-95b3-bd85ed08b72a','906bfef3-a41b-40d3-acda-7d8f23d2bcd2','1cab0c39-b27a-4e4e-b125-fd5216fe8b24','2cf0c12b-f248-4012-8f53-303c730a7b3d','bd88bfed-198e-4891-9430-06660bdeaa9a','fc6e31ce-388e-45cd-956b-b238b9134eb1','19eb37dc-2b1c-4e89-a931-31a38ae60561','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','5e79d288-1400-4817-bd20-e5e6041821b1']::uuid[], '[{"step":1,"text":"양파, 할라피뇨는 잘게 다지고 토마토는 끓는 물에 데쳐 껍질과 씨를 제거하고 잘게 썰어 볶다가 간 소고기를 넣고 소금, 후추로 간한다.","imageUrl":null},{"step":2,"text":"베이컨, 마늘, 양파는 잘게 썰고 강낭콩은 체에 받쳐 물기를 제거한다.","imageUrl":null},{"step":3,"text":"팬에 베이컨을 볶아 기름을 제거하고 2의 마늘, 양파를 볶다가 강낭콩을 넣고 건바질 조금, 소금, 후추로 간을 한 뒤 믹서에 갈아 퓨레로 만든다.","imageUrl":null},{"step":4,"text":"배, 오렌지를 1cm 주사위모양으로 썰고 레몬주스, 파프리카 가루와 섞어 살사를 만든다.","imageUrl":null},{"step":5,"text":"기름 없는 팬에 또띠아를 살짝 구운 뒤 강낭콩 퓨레를 얇게 바르고 볶은 소기기, 채 썬 양상추, 아보카도, 베이컨, 토마토, 사워크림을 넣고 만다.","imageUrl":null},{"step":6,"text":"5에 배, 오렌지 살사를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053705_1416213425545.jpg', 253, 40.5, 9.4, 6.4, 110),
  ('974', '아보카도 달걀 샌드위치', '일품', '달걀 20g, 마요네즈 1g, 디존 머스타드 1g, 레몬주스 2g, 식빵 35g, 아보카도 6g, 워터크레스 1g, 소금 약간, 후추 약간', '["달걀","마요네즈","디존 머스타드","레몬주스","식빵","아보카도","워터크레스","소금","후추"]'::jsonb, ARRAY['c7d438a6-34d6-423f-905d-446b839e2f39','549c7365-28e9-491f-9040-412558f93a5c','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','a18f6f83-06b8-473c-88b3-c2c8f2a7d0fc','906bfef3-a41b-40d3-acda-7d8f23d2bcd2','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"달걀을 완숙으로 삶아 찬물에 담궈 식혀 껍질을 벗긴 뒤 볼에 넣어 포크로 거칠게 으깬다.","imageUrl":null},{"step":2,"text":"으깬 달걀에 머스타드, 레몬주스, 소금, 후춧가루, 마요네즈를 섞는다.","imageUrl":null},{"step":3,"text":"아보카도는 껍질을 제거하고 얇게 슬라이스 한다.","imageUrl":null},{"step":4,"text":"식빵은 노릇하게 양면을 굽는다.","imageUrl":null},{"step":5,"text":"4에 아보카도를 얹고 그 위에 달걀 샐러드를 얹어 식빵으로 덮는다.","imageUrl":null},{"step":6,"text":"샌드위치의 가장자리 부분은 잘라내고 원하는 적당한 크기로 자른다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053706_1416213426888.jpg', 153, 20.3, 5.9, 4.9, 272),
  ('975', '알록달록 시금치 당근 수제비', '반찬', '시금치 10g, 당근 15g, 밀가루 50g, 물 10g, 감자 10g, 애호박 15g, 실파 5g, 멸치육수 200g, 다진 마늘 2g, 간장 2g, 소금 1g', '["시금치","당근","밀가루","물","감자","애호박","실파","멸치육수","다진 마늘","간장","소금"]'::jsonb, ARRAY['9a7f4da6-531b-4478-89ff-d73beafcad1b','e38c12a7-43cb-421a-a36e-7ef0d32517fa','aab3b0b9-d346-4697-a1c8-1b1530153788','94786475-832c-4f97-aab7-bf6fbbe2236b','20894da1-739d-4d52-b5fe-4943bd3492d5','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"시금치와 당근은 각각 믹서에 물을 넣고 간다.","imageUrl":null},{"step":2,"text":"밀가루는 반으로 나눠 시금치 즙과 당근 즙을 넣고 소금을 넣어 각각 반죽 한다.","imageUrl":null},{"step":3,"text":"2의 반죽을 직경 1.5cm 정도의 동그란 경단모양으로 빚는다.","imageUrl":null},{"step":4,"text":"감자와 애호박은 1.5cm 주사위모양으로 자르고 실파는 2cm 길이로 썬다.","imageUrl":null},{"step":5,"text":"멸치 육수에 감자, 수제비 경단, 애호박, 다진마늘, 실파 순서로 넣고 끓인다.","imageUrl":null},{"step":6,"text":"5에 간장과 소금으로 간한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053708_1416213428059.jpg', 236, 42.3, 9.7, 2.1, 484),
  ('977', '인도식만두구이(사모사)', '일품', '양파다진것 15g, 마늘다진것 2g, 생강다진것 1g, 청고추다진것 1g, 새우다진것 25g, 버터 1g, 레몬주수 1g, 생선육수 3g, 카레가루 2g, 토마토페이스트 3g, 달걀물 5g, 춘권피 20g, 올리브오일 1g', '["양파다진것","마늘다진것","생강다진것","청고추다진것","새우다진것","버터","레몬주수","생선육수","카레가루","토마토페이스트","달걀물","춘권피","올리브오일"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','30b5d53c-d247-4f04-9b50-c0f728e65cf9','6f10b4ad-53a2-4a07-ba89-19a6b074373d','7aabd532-361f-4240-aa33-6bfa1be4bc4e','495b9f1e-aa3b-4506-9bb8-feb0a493901e','76e95535-f965-4685-a7a6-55ae26aa202c','c7d438a6-34d6-423f-905d-446b839e2f39','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc']::uuid[], '[{"step":1,"text":"양파, 마늘, 생강, 고추, 새우를 다진다.","imageUrl":null},{"step":2,"text":"버터를 두른 팬에 양파, 생강, 마늘, 고추, 카레가루 순으로 볶는다.","imageUrl":null},{"step":3,"text":"2에 토마토페이스트, 레몬즙, 새우를 넣고 볶는다.","imageUrl":null},{"step":4,"text":"3에 육수를 약간 붓고 약한 불로 끓이면서 수분을 증발시킨 뒤 볼에 담아 식힌다.","imageUrl":null},{"step":5,"text":"춘권피에 4를 적당히 넣고 끝부분에 달걀물을 발라 붙여 완성한다.","imageUrl":null},{"step":6,"text":"겉면에 올리브 오일을 약간 발라 오븐 팬에 놓고 170℃ 오븐에서 바삭하게 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053710_1416213430154.jpg', 156, 19.9, 7.8, 4.8, 213),
  ('979', '중국식 바비큐 폭립', '반찬', '돼지갈비(바비큐용) 120g  양파작게자른것 20g, 마늘다진것 4g, 식용유 1g, 레드와인식초 2g, 황설탕 2g, 꿀 5g, 데미글라스 10g, 토마토케첩 2g, 머스타드 2g, 우스터소스 2g, 케이엔페퍼약간, 소금적당량, 후추적당량', '["돼지갈비","마늘다진것","식용유","레드와인식초","황설탕","꿀","데미글라스","토마토케첩","머스타드","우스터소스","케이엔페퍼","소금","후추"]'::jsonb, ARRAY['fc6e31ce-388e-45cd-956b-b238b9134eb1','a7a59e81-de3d-4893-b56a-b2218732a25b','06e6f3e7-0293-469d-a338-11a610f3e71b','286d1783-cd34-4aae-ac8b-006529ec8bc5','0136fc6a-3a80-4f4c-8057-10bbf34ea572','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"소스재료를 볼에 넣고 잘 섞는다.","imageUrl":null},{"step":2,"text":"소스를 돼지갈비에 골고루 바른 뒤 6시간 이상 재운다.","imageUrl":null},{"step":3,"text":"재운 돼지갈비를 호일로 감싼다.","imageUrl":null},{"step":4,"text":"3을 170℃의 오븐에서 30분간 굽는다.","imageUrl":null},{"step":5,"text":"구운 돼지갈비의 호일을 벗긴다.","imageUrl":null},{"step":6,"text":"5의 갈비가 부드러워 질 때까지 약 30분간 소스를 골고루 발라가며 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053712_1416213432496.jpg', 311, 13.5, 22.8, 18, 352),
  ('2953', '제주도 빙떡, 귤간장소스', '반찬', '메밀가루 50g, 무 30g, 후추 2g, 다시마 2g, 다진 마늘 5g, 다진 파 5g, 저염간장 5g, 통깨 2g, 귤 즙 10g, 참기름 2g', '["메밀가루","무","후추","다시마","다진 마늘","다진 파","저염간장","통깨","귤 즙","참기름"]'::jsonb, ARRAY['f80c9a7d-1510-44e2-a82b-28b9f684e191','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','f175019d-5a93-4cd4-aabc-e7e79445f15a','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"메밀가루에 물을 섞어 메밀 반죽을 만든다.","imageUrl":null},{"step":2,"text":"무를 채 썰어 다시마 육수에 삶는다.","imageUrl":null},{"step":3,"text":"다진 파, 마늘을 볶은 뒤 무와 통깨, 참기름과 섞어 버무린다.","imageUrl":null},{"step":4,"text":"전병을 부친 뒤 무를 넣어 만다.","imageUrl":null},{"step":5,"text":"귤 즙을 조린 뒤 저염간장을 넣고 섞는다.","imageUrl":null},{"step":6,"text":"접시에 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190405/20190405055351_1554454431397.jpg', 94.02, 20, 1.33, 0.97, 9.56),
  ('2992', '퓨전떡갈비', '반찬', '소고기 40g, 돼지고기 6g, 양파 15g, 배 10g, 마늘 5g, 생강 2g, 저염간장 3g, 찹쌀가루 5g, 참기름 2g, 참깨 5g', '["소고기","돼지고기","양파","배","마늘","생강","저염간장","찹쌀가루","참기름","참깨"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','70e914d4-0d03-4202-8b66-81bd8499aa08','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','f175019d-5a93-4cd4-aabc-e7e79445f15a','4cb11562-015f-4ab5-969f-0ea8483a0b42','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"고기는 곱게 다지고 야채는 껍질을 제거한다.","imageUrl":null},{"step":2,"text":"배는 갈아 즙을 만들고 양파는 다진 뒤 기름을 두르지 않은 팬에 살짝 볶는다.","imageUrl":null},{"step":3,"text":"마늘과 생강을 곱게 다져 배즙과 섞은 뒤 다진 고기에 넣어 치댄다.","imageUrl":null},{"step":4,"text":"떡갈비 반죽에 저염간장, 참기름을 이용해 밑간을 하고 찹쌀가루를 넣어 찰기를 준다.","imageUrl":null},{"step":5,"text":"둥근 모양으로 빚은 뒤 중간을 살짝 눌러 기름을 두른 팬에 굽는다.","imageUrl":null},{"step":6,"text":"170℃ 오븐에 3분 정도 구워 속까지 익힌다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409042347_1554794627002.jpg', 195.85, 24.74, 12.58, 5.18, 265.63),
  ('2999', '마늘칩 감자샐러드', '반찬', '감자 50g, 마늘 5g, 양파 5g, 마요네즈 10g, 플레인요거트 5g, 머스터드 1g, 설탕 2g, 파슬리 1g', '["감자","마늘","양파","마요네즈","플레인요거트","머스터드","설탕","파슬리"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','fc6e31ce-388e-45cd-956b-b238b9134eb1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','549c7365-28e9-491f-9040-412558f93a5c','bb41a88a-ea2b-4830-876d-91fe7f640296','5b59cfae-1277-48af-99a6-833687e2da0b','06e6f3e7-0293-469d-a338-11a610f3e71b','4362c386-a37c-44cd-9254-fafd74712a09']::uuid[], '[{"step":1,"text":"감자는 깨끗이 씻어 껍질째 한입 크기로 깍둑썰기 한 뒤 삶는다.","imageUrl":null},{"step":2,"text":"마늘은 얇게 편으로 썬다.","imageUrl":null},{"step":3,"text":"양파는 굵게 다진다.","imageUrl":null},{"step":4,"text":"팬에 식용유를 두르고 다진양파를 볶은 뒤 마늘은 바삭하게 굽는다.","imageUrl":null},{"step":5,"text":"마요네즈, 머스터드, 플레인요거트, 설탕을 섞어 드레싱을 만든다.","imageUrl":null},{"step":6,"text":"감자와 볶은 양파, 드레싱을 골고루 버무리고 마늘칩과 파슬리를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409050910_1554797350561.jpg', 80.12, 10.18, 1.19, 3.85, 51.78),
  ('3082', '시래기닭조림', '반찬', ' 닭고기(120g), 무(30g), 당근(20g), 양파(10g), 홍고추(1g), 청고추(1g), 무청시래기(삶은 것, 80g)
, 다진마늘(2g), 후추(1g), 저염간장(5g), 설탕(3g), 물엿(5g)', '["닭고기","무","당근","양파","홍고추","청고추","무청시래기","다진마늘","후추","저염간장","설탕","물엿"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','f80c9a7d-1510-44e2-a82b-28b9f684e191','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','30b5d53c-d247-4f04-9b50-c0f728e65cf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"닭고기는 부위별로 토막 내어 끓는 물에 살짝 데친다.","imageUrl":null},{"step":2,"text":"데친 닭고기에 양념 재료를 섞어 30분 이상 재운다.","imageUrl":null},{"step":3,"text":"무, 당근, 양파는 사각 썰고, 고추는 송송 썬다.","imageUrl":null},{"step":4,"text":"무청시래기는 끓는 물에 한 번 더 살짝 데치고, 6cm 길이로 썬다.","imageUrl":null},{"step":5,"text":"냄비에 물(30g)과 닭고기, 시래기를 넣고, 청홍고추를 제외한 손질한 채소를 넣어 조린다.","imageUrl":null},{"step":6,"text":"홍고추와 청고추를 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230307/20230307043730_1678174650348.jpg', 210.1, 12.5, 19.3, 9.2, 198.3),
  ('3084', '두부튀김&무소스', '반찬', '두부 70g, 계란 20g, 깻잎 2.5g, 옥수수전분 10g, 식용유 10g, 혼다랑어가쓰오부시 1g, 무 10g, 레몬쥬스 2g, 2배 양조식초 1.5g, 저염간장 3g, 미향 6g, 설탕 1g', '["두부","계란","깻잎","옥수수전분","식용유","혼다랑어가쓰오부시","무","레몬쥬스","저염간장","미향","설탕"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','c7d438a6-34d6-423f-905d-446b839e2f39','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','6613d1d9-80a2-4ce4-9d3d-647203197e53','a7a59e81-de3d-4893-b56a-b2218732a25b','f80c9a7d-1510-44e2-a82b-28b9f684e191','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"두부는 2cm의 정사각형으로 썰어 전분과 계란물을 무쳐 기름에 튀긴다.","imageUrl":null},{"step":2,"text":"무는 믹서기나 강판에 갈아준다.","imageUrl":null},{"step":3,"text":"끓는 물에 가쓰오부시를 살짝 넣었다 빼내어 국물을 우려낸다.","imageUrl":null},{"step":4,"text":"무와 가쓰오부시 국물에 설탕, 미향, 레몬즙, 식초, 저염간장을 넣고 섞어준다.","imageUrl":null},{"step":5,"text":"깻잎은 곱게 채를 쳐준다.","imageUrl":null},{"step":6,"text":"접시에 두부와 깻잎을 담고, 소스를 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023659_1584077819229.JPG', 138.1, 10.8, 9.1, 6.5, 132.8),
  ('3086', '오징어튀김&딸기쨈', '반찬', '오징어 35g, 밀가루 70g, 물 50g, 계란 32.5g 후추 0.1g, 식용유 500g, 딸기쨈 5g', '["오징어","밀가루","물","계란","식용유","딸기쨈"]'::jsonb, ARRAY['4d148f68-08e0-4599-8953-595db492bf23','aab3b0b9-d346-4697-a1c8-1b1530153788','94786475-832c-4f97-aab7-bf6fbbe2236b','c7d438a6-34d6-423f-905d-446b839e2f39','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"오징어를 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":2,"text":"오징어를 살짝 데친 후 물기를 제거한다.","imageUrl":null},{"step":3,"text":"밀가루에 물, 계란, 후추를 넣어 튀김반죽을 만든다.","imageUrl":null},{"step":4,"text":"오징어에 튀김 반죽을 묻혀 식용유에 튀긴다.","imageUrl":null},{"step":5,"text":"키친타올에 올려 기름을 제거한다.","imageUrl":null},{"step":6,"text":"딸기잼과 같이 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313052539_1584087939467.JPG', 591.6, 39.6, 17, 40.6, 135.9),
  ('3175', '감귤콩샐러드', '반찬', '감귤 20g, 완두콩 8g, 수수 4g, 율무 10g, 병아리콩 20g, 유자청 10g, 치커리 6g, 올리브오일 10g', '["감귤","완두콩","수수","율무","병아리콩","유자청","치커리","올리브오일"]'::jsonb, ARRAY['bbf5a336-7a76-423e-a6a3-7f79147e5218','5fd34bed-4339-4fcc-9221-f082ce6ac652','f82b8382-3b65-4839-9f45-524168f3da07','ff5b6cbe-7985-4ca2-94ad-5525717cddf1','1389717e-81e4-4350-96d4-d627d851aa10','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc']::uuid[], '[{"step":1,"text":"감귤은 껍질을 제거하고 알을 분리하여 반을 갈라 준다.","imageUrl":null},{"step":2,"text":"치커리는 한입크기로 썰어 준비한다.","imageUrl":null},{"step":3,"text":"완두콩, 수수, 율무, 병아리콩은 하루 전에 물에 불린 후 삶아준다.","imageUrl":null},{"step":4,"text":"삶은 콩은 체에 받쳐 물기를 제거한다.","imageUrl":null},{"step":5,"text":"손질한 재료를 모두 섞는다.","imageUrl":null},{"step":6,"text":"올리브오일과 유자청을 넣어 버무린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055101_1611823861687.jpg', 145.7, 17.73, 3.54, 6.74, 13.62),
  ('3190', '바질향이 향긋한 고구마 찰 바케트', '기타', ' 강력분 675g, 소금 6g, 생이스트 10g, 물 375ml(바게트반죽용),  파인소프트 T 300g, 파인소프트 C 50g, 강력분 50g, 소금 8g, 분유 8g, 아몬드 분말 74g, 드라이 이스트(골드) 10g, 무염버터 54g, 달걀 50g(1개), 물 200ml(찰반죽용)
 크림치즈 200g, 바질 페스토 30g, 노른자 20g, 고구마 다이스 100g', '["강력분","소금","생이스트","물","파인소프트 T","파인소프트 C","분유","아몬드 분말","드라이 이스트","무염버터","달걀","크림치즈","바질 페스토","노른자","고구마 다이스"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b','7aabd532-361f-4240-aa33-6bfa1be4bc4e','c7d438a6-34d6-423f-905d-446b839e2f39','b42c6eac-0afb-4d87-8942-ed1a9c294b09']::uuid[], '[{"step":1,"text":"반죽을 모두 섞어 30분 발효 후 punch 후 40분 발효한다.\r\n★punch는 가스를 빼는 과정을 얘기해요.","imageUrl":null},{"step":2,"text":"150g으로 분할 후 중간발효 20분을 한다.","imageUrl":null},{"step":3,"text":"찰 반죽 80g 분할 후 밀대로 얇게 펴서 크림치즈와 바질페스토를 섞은 속재료를 짜고 삶아 낸 고구마 다이스를 촘촘한 간격으로 올린 후 말아준다.","imageUrl":null},{"step":4,"text":"중간발효를 마친 바게트 반죽은 최대한 기공을 살려 조심히 펴 준다. 펴준 반죽 위에 찰 반죽을 놓고 가볍게 환목모양으로 말아준다.","imageUrl":null},{"step":5,"text":"반죽에 물을 뿌린 후 덧 가루를 묻혀 1시간 동안 2차 발효한다.","imageUrl":null},{"step":6,"text":"빵이 터지지 않게 꾸쁘는 사선으로 세 번 내고 , 195℃의 컨벡션 오븐에 16분 스팀 8초 설정을 하여 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129042524_1611905124726.jpg', 286, 47.11, 7.97, 7.34, 2.07),
  ('3222', '두유 크림 현미리소토', '일품', '손질된 고등어(60g), 양파(10g), 마늘(6g), 양송이버섯(1개), 청양고추(2g), 깻잎(1g), 불린 현미(150g), 검은콩 두유(200㎖), 달걀노른자(1개), 다시마(2g), 간장(5g), 레몬즙(8g)', '["손질된 고등어","양파","마늘","양송이버섯","청양고추","깻잎","불린 현미","검은콩 두유","달걀노른자","다시마","간장","레몬즙"]'::jsonb, ARRAY['f7f9c0c6-98d6-45b9-bbbe-26b57a62ee2e','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','30b5d53c-d247-4f04-9b50-c0f728e65cf9','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','c7d438a6-34d6-423f-905d-446b839e2f39','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','f175019d-5a93-4cd4-aabc-e7e79445f15a','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"냄비에 물(500㎖)과 다시마(2g)를 넣어 3분간 끓이고 다시마는 건져 육수를 만든다.","imageUrl":null},{"step":2,"text":"고등어는 에어프라이어에 넣어 180℃에서 10~15분간 굽는다.","imageUrl":null},{"step":3,"text":"양파와 마늘, 양송이버섯, 청양고추는 잘게 다지고, 깻잎은 얇게 채 썬다.","imageUrl":null},{"step":4,"text":"중간 불로 달군 팬에 식용유를 두른 뒤 다진 양파와 마늘, 양송이버섯, 간장을 넣어 2분간 볶은 뒤 불린 현미를 넣어 2분간 볶는다.","imageUrl":null},{"step":5,"text":"다시마 육수(250㎖)를 2~3번에 나눠 넣어 현미를 익히다가 검은콩 두유를 넣어 졸이고 레몬즙과 다진 청양고추를 넣어 고루 섞는다.","imageUrl":null},{"step":6,"text":"그릇에 현미 리소토를 담고 고등어구이 → 채 썬 깻잎 → 달걀노른자 순으로 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210308/20210308054626_1615193186794.jpg', 847.4, 113.1, 28.4, 31.3, 712.2),
  ('3283', '당근새우 카나페', '후식', ' 칵테일새우(2마리), 사과(½개), 양파(⅓개), 당근(¼개), 바게트(2조각), 다진 파슬리(0.5Ts), 블루베리(6알), 애플민트잎(6장), 당근(⅓개), 양파(⅓개), 레몬(⅓개), 후춧가루(3t), 레몬즙(6Ts), 식초(0.6Ts), 올리브유(1Ts)', '["칵테일새우","사과","양파","당근","바게트","다진 파슬리","블루베리","애플민트잎","레몬","후춧가루","레몬즙","식초","올리브유"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','4362c386-a37c-44cd-9254-fafd74712a09','203b7165-14df-4cb6-b165-e4dadf9a3079','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','6c285c60-022a-4a00-b172-87df97f16a2f','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc']::uuid[], '[{"step":1,"text":"물(3컵)에 육수 재료와 칵테일새우를 넣어 새우가 익을 때까지 데친 뒤 건진다.","imageUrl":null},{"step":2,"text":"사과와 양파는 잘게 다지고, 당근은 길게 썬다.","imageUrl":null},{"step":3,"text":"다진 사과와 양파, 채 썬 당근, 후춧가루, 레몬즙, 식초, 올리브유를 넣어 고루 섞는다.","imageUrl":null},{"step":4,"text":"바게트 위에 버무린 재료를 올린다.","imageUrl":null},{"step":5,"text":"데친 새우를 올리고, 다진 파슬리와 후춧가루를 뿌린 뒤 블루베리를 올린다.","imageUrl":null},{"step":6,"text":"애플민트를 올려 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr98Eq', 349.6, 50, 19.8, 7.8, 701.4),
  ('3290', '아보카도 수란샐러드', '반찬', ' 상추(3장), 레몬(½개), 아보카도(1개), 토마토(1개), 달걀(1개), 파프리카(빨강, 노랑 각 ½개), 소금(0.2ts), 식초(0.5ts), 소금(0.3ts), 후춧가루(약간), 바질가루(0.5t), 오레가노가루(0.5t), 올리브유(1Ts), 레몬즙(1Ts)', '["상추","레몬","아보카도","토마토","달걀","파프리카","소금","식초","후춧가루","바질가루","오레가노가루","올리브유","레몬즙"]'::jsonb, ARRAY['1389717e-81e4-4350-96d4-d627d851aa10','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','906bfef3-a41b-40d3-acda-7d8f23d2bcd2','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','c7d438a6-34d6-423f-905d-446b839e2f39','5e79d288-1400-4817-bd20-e5e6041821b1','2cf0c12b-f248-4012-8f53-303c730a7b3d','6c285c60-022a-4a00-b172-87df97f16a2f','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','ba9e5a79-cab3-4af0-942b-0b35fd745150','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc']::uuid[], '[{"step":1,"text":"상추는 깨끗하게 씻어 한입 크기로 뜯고, 레몬은 모양대로 얇게 썰고, 아보카도는 씨와 껍질을 제거한 뒤 한입 크기로 썬다.","imageUrl":null},{"step":2,"text":"파프리카는 씨를 제거한 뒤 한입 크기로 썰고, 토마토는 한입 크기로 썬다.","imageUrl":null},{"step":3,"text":"끓는 소금물(물4컵+소금0.2ts)에 식초를 넣은 뒤 달걀을 넣고 수란을 만든다.","imageUrl":null},{"step":4,"text":"드레싱을 만든다.","imageUrl":null},{"step":5,"text":"그릇에 손질한 채소를 담고 수란과 얇게 썬 레몬을 올려 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr9BMv', 172.1, 17.7, 4.2, 9.4, 88.2),
  ('980', '참깨 오렌지 쇠고기', '반찬', '쇠고기사태 100g, 전분 2g, 간장 2g, 오렌지주스 10g, 굴소스 2g, 꿀 3g, 참깨 1g, 식용유 1g, 생강 1g, 오렌지 20g, 파인애플 28g', '["쇠고기사태","전분","간장","오렌지주스","굴소스","꿀","참깨","식용유","생강","오렌지","파인애플"]'::jsonb, ARRAY['6613d1d9-80a2-4ce4-9d3d-647203197e53','f175019d-5a93-4cd4-aabc-e7e79445f15a','19eb37dc-2b1c-4e89-a931-31a38ae60561','d7e0d83c-010c-4b63-9ba4-fcd9af7cbac1','286d1783-cd34-4aae-ac8b-006529ec8bc5','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','a7a59e81-de3d-4893-b56a-b2218732a25b','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','c97290bd-7146-45bc-8e7f-28390e7a95b0']::uuid[], '[{"step":1,"text":"소고기는 길이 6cm, 넓이 2cm, 두께 0.5cm 정도의 직사각형 모양으로 썬 뒤 전분과 간장을 섞어 재운다.","imageUrl":null},{"step":2,"text":"생강은 다지고 오렌지는 껍질을 벗겨 속만 잘라내고 파인애플은 껍질과 속심을 제거하고 0.5cm 크기의 주사위모양으로 자른다.","imageUrl":null},{"step":3,"text":"오렌지주스, 굴소스, 꿀, 전분을 섞어 소스를 만든다.","imageUrl":null},{"step":4,"text":"기름을 두르지 않은 팬에 깨를 볶은 뒤 식히고 팬에 기름을 두르고 재운 소고기를 앞뒤로 골고루 익힌다.","imageUrl":null},{"step":5,"text":"4에 소스를 넣고 저어주면서 끓여 농도가 나기 시작하면 오렌지와 파인애플을 넣고 살짝 익힌다.","imageUrl":null},{"step":6,"text":"접시에 5를 담고 제공하기 직전에 깨를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053713_1416213433793.jpg', 183, 9.8, 21.1, 6.2, 269),
  ('981', '치킨 버거 스테이크', '일품', '닭가슴살 80g, 빵가루 5g, 차이브 2g, 바질 1g, 파슬리 1g, 소금적당량, 후추적당량양파다진것 10g, 버터적당량, 양송이 30g, 빵가루 5g, 생크림 적당량', '["닭가슴살","빵가루","차이브","바질","파슬리","소금","후추적당량양파다진것","버터","양송이","생크림"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','45080597-55fa-42dc-aa65-12d7694e4b7e','ba9e5a79-cab3-4af0-942b-0b35fd745150','4362c386-a37c-44cd-9254-fafd74712a09','2cf0c12b-f248-4012-8f53-303c730a7b3d','7aabd532-361f-4240-aa33-6bfa1be4bc4e','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','af187077-b7f6-4b0e-9e99-f844f6359ac2']::uuid[], '[{"step":1,"text":"양파는 곱게 다지고 양송이는 0.5cm로 슬라이스 한다.","imageUrl":null},{"step":2,"text":"팬에 버터를 넣고 녹으면 양파를 볶다가 양송이를 넣어 볶는다.","imageUrl":null},{"step":3,"text":"생크림, 소금, 후추로 간을 하고 양송이에서 물이 빠져나오면 빵가루를 넣어 되직하게 농도를 맞춘 뒤 그릇에 옮겨 식힌다.","imageUrl":null},{"step":4,"text":"차이브, 오레가노, 바질, 파슬리를 잘게 다진다.","imageUrl":null},{"step":5,"text":"간 닭고기와 3, 4를 볼에 넣고 섞어 치대 찰지게 만든 뒤 지름 10cm 정도의 원형 모양이나 럭비공 모양으로 만든다.","imageUrl":null},{"step":6,"text":"팬에 기름을 두른 뒤 치킨 스테이크를 익혀주거나 팬에서 색만 내고 오븐에서 익힌다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053715_1416213435185.jpg', 128, 9.5, 21.5, 0.7, 89),
  ('982', '토마토소스 달걀볶음', '반찬', '달걀 35g, 파 4g, 토마토소스 10g, 설탕 8g, 소금 적당량, 식물성기름 2g, 참기름 1g', '["달걀","파","토마토소스","설탕","소금","식물성기름","참기름"]'::jsonb, ARRAY['c7d438a6-34d6-423f-905d-446b839e2f39','4b410642-7bf9-45ad-9055-e7d9a34edaa1','76e95535-f965-4685-a7a6-55ae26aa202c','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"볼에 달걀을 푼다.","imageUrl":null},{"step":2,"text":"달군 팬에 1을 볶아 스크램블을 만든다.","imageUrl":null},{"step":3,"text":"파를 송송 썬다.","imageUrl":null},{"step":4,"text":"기름을 두른 팬에 3을 먼저 볶아 향을 낸 뒤 토마토소스를 넣고 볶는다.","imageUrl":null},{"step":5,"text":"4에 설탕, 소금, 2를 넣고 섞는다.","imageUrl":null},{"step":6,"text":"참기름을 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053716_1416213436761.jpg', 111, 10.2, 4.4, 5.9, 107),
  ('985', '낫토 시래기 라이스전', '후식', '밥 40g, 양파다진것 10g, 당근다진것 5g, 낫토 15g, 시래기불린것 10g, 카레가루 3g, 파다진것 2g, 밀가루 5g, 달걀 10g, 식용유 적당량, 소금 적당량, 후춧가루 적당량', '["밥","양파다진것","당근다진것","낫토","시래기불린것","카레가루","파다진것","밀가루","달걀","식용유","소금","후춧가루"]'::jsonb, ARRAY['ecb35816-34ae-4c4c-867a-e3f84db92755','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','495b9f1e-aa3b-4506-9bb8-feb0a493901e','4b410642-7bf9-45ad-9055-e7d9a34edaa1','aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','a7a59e81-de3d-4893-b56a-b2218732a25b','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"양파와 당근은 잘게 다진다.","imageUrl":null},{"step":2,"text":"시래기는 불려 물기를 꼭 짜낸다.","imageUrl":null},{"step":3,"text":"2번의 시래기를 곱게 다진다.","imageUrl":null},{"step":4,"text":"뜨거운 밥에 1, 3을 넣는다.","imageUrl":null},{"step":5,"text":"4에 낫토, 카레가루, 다진 파를 넣고 골고루 섞는다.","imageUrl":null},{"step":6,"text":"5에 소금, 후춧가루로 간한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053720_1416213440499.jpg', 138, 22.9, 6.3, 2.9, 163),
  ('986', '나스와 샐러드', '반찬', '달걀 20g, 완두콩 5g, 오이 10g, 토마토 20g, 레드어니언 10g, 로메인 10g, 홍고추 2g, 블랙올리브 2g, 바질 1g, 캔참치 20g,, 올리브오일 2g, 레드와인식초 2g, 디존 머스타드 1g, 마늘 1g, 설탕적당량', '["달걀","완두콩","오이","토마토","레드어니언","로메인","홍고추","블랙올리브","바질","캔참치","올리브오일","레드와인식초","디존 머스타드","마늘","설탕"]'::jsonb, ARRAY['c7d438a6-34d6-423f-905d-446b839e2f39','5fd34bed-4339-4fcc-9221-f082ce6ac652','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','30b5d53c-d247-4f04-9b50-c0f728e65cf9','ba9e5a79-cab3-4af0-942b-0b35fd745150','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','fc6e31ce-388e-45cd-956b-b238b9134eb1','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"달걀은 완숙으로 삶아 껍질을 벗긴 뒤 세로로 4등분하고 완두콩은 끓는 물에 삶아 찬물에 헹군 뒤 물기를 제거한다.","imageUrl":null},{"step":2,"text":"오이는 1cm 주사위모양으로 썰고 양파는 링으로 슬라이스 하고 로메인은 먹기 좋게 뜯어 찬물에 담군다.","imageUrl":null},{"step":3,"text":"토마토는 달걀과 같은 모양으로 자르고 홍고추는 어슷하게 썰고 참치는 덩어리가 있게 기름기를 뺀다.","imageUrl":null},{"step":4,"text":"바질은 슬라이스하고 마늘은 다진다.","imageUrl":null},{"step":5,"text":"볼에 올리브오일과 레드와인식초, 머스타드, 설탕, 다진마늘을 섞어 드레싱을 만든다.","imageUrl":null},{"step":6,"text":"다른 볼에 준비해둔 야채들과 달걀, 참치를 넣고 드래싱을 끼얹어 버무린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053721_1416213441420.jpg', 92, 5.1, 8.1, 41, 79),
  ('987', '다시마전', '반찬', '다시마 30g, 영양부추 3g, 청고추다진것 3g, 홍고추다진것 3g, 새우살다진것 10g, 밀가루 10g, 물 8g, 소금적당량멸치액젓 2g, 물 3g, 설탕 2g, 깨소금 2g, 고춧가루 1g, 실파 2g', '["다시마","영양부추","청고추다진것","홍고추다진것","새우살다진것","밀가루","물","소금적당량멸치액젓","설탕","깨소금","고춧가루","실파"]'::jsonb, ARRAY['84032a7e-ec18-44d5-ab30-c7b960ca5ca9','058648c3-fd8e-476d-952f-b15dc67f1877','30b5d53c-d247-4f04-9b50-c0f728e65cf9','6f10b4ad-53a2-4a07-ba89-19a6b074373d','aab3b0b9-d346-4697-a1c8-1b1530153788','94786475-832c-4f97-aab7-bf6fbbe2236b','06e6f3e7-0293-469d-a338-11a610f3e71b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','84104c49-0af4-4323-a56b-b67002a422d9','4b410642-7bf9-45ad-9055-e7d9a34edaa1']::uuid[], '[{"step":1,"text":"냄비에 다시마가 잠길 정도의 물을 붓고 중불에서 삶아 10여분 두었다가 건져 찬물에 휑군 뒤 18cm 크기로 자른다.","imageUrl":null},{"step":2,"text":"청, 홍고추는 씨를 빼 잘게 다지고 부추와 새우 살도 다진다.","imageUrl":null},{"step":3,"text":"밀가루에 물과 소금을 넣고 반죽을 한 뒤 다진 채소들을 넣고 골고루 섞는다.","imageUrl":null},{"step":4,"text":"3에 다시마를 넣어 반죽 물을 입히고 팬에 기름을 둘러 노릇하게 지진다.","imageUrl":null},{"step":5,"text":"다시마전이 한 김 식은 후 돌돌 말아 자를 수 있도록 꼬치로 고정시킨다.","imageUrl":null},{"step":6,"text":"5를 4cm 정도 길이로 자르고 멸치액젓소스를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053722_1416213442466.jpg', 79, 13.2, 4.3, 1.6, 311),
  ('988', '모듬옥수수', '반찬', '옥수수 35g, 잣 3g, 청피망 25g, 당근 25g, 닭고기 35g, 식용유 1g, 물전분 6g, 소금 적당량', '["옥수수","잣","청피망","당근","닭고기","식용유","물전분","소금"]'::jsonb, ARRAY['75ae0b33-6449-4b14-a6b8-bebe016d5b33','bbbbd533-8922-4dac-9e4c-cd93ea710c92','df459e6f-3515-45d5-8c9a-9d37b6249379','e38c12a7-43cb-421a-a36e-7ef0d32517fa','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','a7a59e81-de3d-4893-b56a-b2218732a25b','6613d1d9-80a2-4ce4-9d3d-647203197e53','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"청피망, 당근, 닭고기를 옥수수알 크기로 썬다.","imageUrl":null},{"step":2,"text":"팬에 닭고기를 볶는다.","imageUrl":null},{"step":3,"text":"2에 당근을 넣고 볶는다.","imageUrl":null},{"step":4,"text":"3에 잣, 청피망, 옥수수를 넣고 볶는다.","imageUrl":null},{"step":5,"text":"4에 간을 한다.","imageUrl":null},{"step":6,"text":"물전분으로 농도를 맞춘다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053723_1416213443714.jpg', 127, 15, 9.9, 3.6, 109),
  ('989', '버섯 들깨탕', '국&찌개', '느타리버섯 15g, 생표고버섯 15g, 팽이버섯 15g, 새송이벗서 15g, 우엉 15g, 조랭이떡 15g, 들깨 8g, 물 50g, 들기름 2g, 소금적당량', '["느타리버섯","생표고버섯","팽이버섯","새송이벗서","우엉","조랭이떡","들깨","물","들기름","소금"]'::jsonb, ARRAY['7c91e298-5ace-4242-8619-cdcc80587cd7','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','6b3a8bca-adc3-48f5-813b-6b06630e11dd','94786475-832c-4f97-aab7-bf6fbbe2236b','f5534afd-2a26-4493-8ec1-fd680dcb3bef','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"끓는 물에 데친 느타리 버섯을 손으로 찢고 생 표고버섯은 데쳐서 물기를 짠 뒤 채썬다.","imageUrl":null},{"step":2,"text":"팽이버섯은 밑동을 제거한 뒤 반으로 자르고 새송이버섯은 팽이버섯 크기로 자른다.","imageUrl":null},{"step":3,"text":"조랭이떡은 물에 휑구고 우엉은 껍질을 벗겨 길이로 3등분 하여 어슷하게 썬 뒤 냉수에 여러번 휑구고 물기를 뺀다.","imageUrl":null},{"step":4,"text":"들깨는 분무기를 이용하여 물을 조금씩 넣으면서 곱게 갈아 체에 밭쳐 들깨 물을 준비하고 찌꺼기는 버린다.","imageUrl":null},{"step":5,"text":"냄비에 들기름을 두르고 우엉을 볶은 뒤 들깨 물을 부어 끓이다가 조랭이 떡을 넣고 끓인다.","imageUrl":null},{"step":6,"text":"5의 떡이 둥둥 떠오르면 버섯을 넣고 한소끔 끓인 뒤 소금으로 간을 한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053724_1416213444900.jpg', 124, 17.3, 3.9, 5.3, 32),
  ('990', '산마드래싱과 실곤약 샐러드', '반찬', '그린비타민 8g, 치커리 8g, 배 15g, 포도주스 10g, 훈제오리가슴살 30g, 실곤약 20g  산마 10g, 우유 10g, 레몬주스 3g, 오렌지주스 3g, 호두 3g, 소금 적당량', '["그린비타민","치커리","배","포도주스","훈제오리가슴살","실곤약","우유","레몬주스","오렌지주스","호두","소금"]'::jsonb, ARRAY['1389717e-81e4-4350-96d4-d627d851aa10','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','483ecbd5-47a4-4fb5-bfee-852bded6c1dd','54a52322-b4df-4354-a7a5-2a7b0c41f7bd','e937397f-54e2-49df-997a-f393c58360be','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','19eb37dc-2b1c-4e89-a931-31a38ae60561','7651578f-1206-499d-a04c-15f034d4cae2','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"비타민과 치커리는 한입 크기로 적당히 뜯어 찬물에 담궈 두었다가 먹기 전에 물기를 제거한다.","imageUrl":null},{"step":2,"text":"믹서에 산마와 우유, 레몬주스, 오렌지주스, 호두, 소금을 넣고 곱게 갈아 드래싱을 만든다.","imageUrl":null},{"step":3,"text":"배는 껍질을 제거하고 4등분 한 뒤 씨를 제거하고 4~5mm 정도의 두께로 슬라이스한다.","imageUrl":null},{"step":4,"text":"팬에 포도주스를 붓고 슬라이스한 배를 넣어 배가 포도색이 되도록 졸인다.","imageUrl":null},{"step":5,"text":"훈제오리가슴살을 얇게 슬라이스 한다.","imageUrl":null},{"step":6,"text":"접시에 5와 4, 실곤약, 야채들을 보기 좋게 담고 드래싱을 끼얹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053726_1416213446198.jpg', 97, 7.2, 7, 4.9, 36),
  ('991', '산호두부', '반찬', '두부 35g, 돼지고기다진것 15g, 당근다진것 10g, 고추기름 2g, 완두콩 10g, 파 5g, 생강 3g, 물전분 10g, 소금 적당량', '["두부","돼지고기다진것","당근다진것","고추기름","완두콩","파","생강","물전분","소금"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','70e914d4-0d03-4202-8b66-81bd8499aa08','e38c12a7-43cb-421a-a36e-7ef0d32517fa','3a2bfe83-465c-4aaf-bde6-1c34303b15b7','5fd34bed-4339-4fcc-9221-f082ce6ac652','4b410642-7bf9-45ad-9055-e7d9a34edaa1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','6613d1d9-80a2-4ce4-9d3d-647203197e53','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"두부를 1cm 주사위모양으로 자른다.","imageUrl":null},{"step":2,"text":"1을 뜨거운 물에 넣었다가 꺼내 물기를 제거한다.","imageUrl":null},{"step":3,"text":"당근과 돼지고기를 잘게 다진다.","imageUrl":null},{"step":4,"text":"팬에 고추기름을 두른 뒤 3을 넣고 볶는다.","imageUrl":null},{"step":5,"text":"파, 다진생강, 물, 완두콩, 소금, 두부를 넣고 간이 들도록 졸인다.","imageUrl":null},{"step":6,"text":"물 전분을 넣어 소스의 농도를 맞춘다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053727_1416213447278.jpg', 89.4, 8.5, 7, 3.4, 55),
  ('992', '섭산삼', '후식', '더덕 40g, 젖은 찹쌀가루 30g, 가루녹차 2g, 백년초 가루 2g, 설탕 1g, 꿀 5g, 소금 적당량, 튀김기름 8g', '["더덕","젖은 찹쌀가루","가루녹차","백년초 가루","설탕","꿀","소금","튀김기름"]'::jsonb, ARRAY['641252bb-9268-421d-8b9a-314bcbc0c522','06e6f3e7-0293-469d-a338-11a610f3e71b','286d1783-cd34-4aae-ac8b-006529ec8bc5','2cf0c12b-f248-4012-8f53-303c730a7b3d','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"더덕은 껍질을 벗기고 0.3cm 두께로 편 썰어 소금물에 담궈 쓴 맛을 뺀 뒤 면보에 옮겨 밀대로 밀거나 두들겨 얇게 편다.","imageUrl":null},{"step":2,"text":"찹쌀가루는 소금을 넣고 혼합하여 체에 내린다.","imageUrl":null},{"step":3,"text":"2를 3등분 하여 가루녹차와 백년초가루를 각각 섞는다.","imageUrl":null},{"step":4,"text":"3에 더덕을 각각 넣고 앞, 뒤로 꼭꼭 눌러 찹쌀가루를 묻힌다.","imageUrl":null},{"step":5,"text":"170℃의 기름에 2번 튀긴 뒤 기름을 빼고 뜨거울 때 설탕을 약간 뿌린다.","imageUrl":null},{"step":6,"text":"꿀을 곁들여 찍어 먹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053728_1416213448480.jpg', 233, 26.9, 4.7, 8.2, 4),
  ('993', '시금치 돼지고기 볶음', '반찬', '돼지고기살코기 40g, 물전분 10g, 소금 적당량, 시금치 25g, 부추 10g, 간장 5g, 파 5g, 생강 3g, 식용유 2g', '["돼지고기살코기","물전분","소금","시금치","부추","간장","파","생강","식용유"]'::jsonb, ARRAY['6613d1d9-80a2-4ce4-9d3d-647203197e53','2cf0c12b-f248-4012-8f53-303c730a7b3d','9a7f4da6-531b-4478-89ff-d73beafcad1b','058648c3-fd8e-476d-952f-b15dc67f1877','f175019d-5a93-4cd4-aabc-e7e79445f15a','4b410642-7bf9-45ad-9055-e7d9a34edaa1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"돼지고기는 채 썬 뒤 소금, 물전분을 넣고 양념한다.","imageUrl":null},{"step":2,"text":"양념한 고기를 기름 두른 팬에 볶으면서 달라붙지 않도록 저어준다.","imageUrl":null},{"step":3,"text":"시금치와 부추를 4~5cm 가량으로 썬다.","imageUrl":null},{"step":4,"text":"가열된 팬에 기름을 두르고 파, 생강, 팔각을 넣어 향을 낸다.","imageUrl":null},{"step":5,"text":"4에 2와 간장을 넣고 볶는다.","imageUrl":null},{"step":6,"text":"물 전분을 넣어 농도를 맞춘 뒤 마직막으로 부추, 시금치를 넣는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053729_1416213449527.jpg', 105, 7.4, 9.2, 4.5, 284),
  ('994', '발사믹과 로즈마리로 향을 낸 오븐구이 야채', '반찬', '단호박 40g, 당근 40g, 비트 40g, 고구마 40g, 꿀 8g, 발사믹식초 30g, 로즈마리 2g, 소금적당량, 후추 적당량', '["단호박","당근","비트","고구마","꿀","발사믹식초","로즈마리","소금","후추"]'::jsonb, ARRAY['98d652af-a6d6-440c-9653-e22fc5d47d88','e38c12a7-43cb-421a-a36e-7ef0d32517fa','524e1b82-1f81-4648-b50c-441404a06786','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','286d1783-cd34-4aae-ac8b-006529ec8bc5','6c285c60-022a-4a00-b172-87df97f16a2f','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"단호박, 비트, 고구마, 당근은 껍질을 벗긴다.","imageUrl":null},{"step":2,"text":"1을 자연스럽게 2~2.5cm 두께로 썬다.","imageUrl":null},{"step":3,"text":"볼에 2와 발사믹 식초, 꿀, 로즈마리 잎을 넣고 버무린다.","imageUrl":null},{"step":4,"text":"소금, 후추로 간을 한다.","imageUrl":null},{"step":5,"text":"150℃의 예열된 오븐에서 익을 때까지 굽는다.","imageUrl":null},{"step":6,"text":"중간에 뒤집어 주어 고루 익히도록 한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053730_1416213450573.jpg', 136, 34.3, 1.9, 0.6, 52),
  ('995', '종이에 싸서 구운 도미(파필로테)', '반찬', '도미살 65g, 소금 적당량, 후추 적당량, 샐러리 채친것 3g, 당근 채친것 3g, 대파채친것 3g, 양파채친것 6g, 피망채친것 5g, 브러컬리 5g, 레몬제스트 1g, 팽이버섯 3g, 버터 2g, 유산지  버터 2g, 파마산치즈 1g, 통후추 약간, 오레가노 0.2g, 마늘 0.3g, 양파 0.5g', '["도미살","소금","후추","샐러리 채친것","당근 채친것","대파채친것","양파채친것","피망채친것","브러컬리","레몬제스트","팽이버섯","버터","유산지  버터","파마산치즈","통후추","오레가노","마늘","양파"]'::jsonb, ARRAY['2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','7aabd532-361f-4240-aa33-6bfa1be4bc4e','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','cdbae946-7ca4-4f8d-8a3c-5bb295961ad6','fc6e31ce-388e-45cd-956b-b238b9134eb1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742']::uuid[], '[{"step":1,"text":"도미살에 소금, 후추로 밑간한다.","imageUrl":null},{"step":2,"text":"셀러리, 당근, 대파, 양파, 피망은 채 썰고 브로컬리는 작은 송이로 자르고 레몬 껍질은 얇게 제스트하고 팽이버섯은 밑동을 자른다.","imageUrl":null},{"step":3,"text":"유산지는 반을 접었다가 편 뒤 안쪽에 부드러운 버터를 바른다.","imageUrl":null},{"step":4,"text":"4의 버터를 바른 한 쪽 면에 셀러리, 당근, 대파, 팽이버섯, 양파, 피망, 레몬 제스트를 준비된 분량의 반 정도 놓고 밑간한 도미살을 올린다.","imageUrl":null},{"step":5,"text":"다시 남은 야채들을 도미위에 올리고 유산지의 한 면으로 야채를 덮어주고, 모서리의 뚫린 곳을 접어 봉해준다.","imageUrl":null},{"step":6,"text":"160℃로 예열된 오븐에서 익혀준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053731_1416213451353.jpg', 104, 2.2, 13.8, 4.5, 51),
  ('2993', '무염 겉절이', '반찬', '알배추 50g, 적양파 15g, 대파 5g, 풋고추 3g, 마늘 5g, 무청 3g, 고춧가루 5g, 매실액 2g, 식초 5g, 사과 10g', '["알배추","적양파","대파","풋고추","마늘","무청","고춧가루","매실액","식초","사과"]'::jsonb, ARRAY['e116f85b-0eaa-40cb-8107-df5ec8486ad4','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','84104c49-0af4-4323-a56b-b67002a422d9','02fd7135-0ec3-49ec-82e3-390536ab2cf5','6c285c60-022a-4a00-b172-87df97f16a2f','c85a52b9-c3b4-4a76-951c-bb40edeb3adb']::uuid[], '[{"step":1,"text":"알배추는 세척 후 먹기 좋은 크기로 잘라 물에 담군다.","imageUrl":null},{"step":2,"text":"대파와 풋고추는 어슷썰고 양파는 굵게 채 썬다.","imageUrl":null},{"step":3,"text":"마늘은 곱게 다지고 사과는 믹서에 간다.","imageUrl":null},{"step":4,"text":"사과즙, 다진마늘, 고춧가루, 매실액, 식초를 섞어 겉절이 양념을 만든다.","imageUrl":null},{"step":5,"text":"물에 담궈뒀던 알배추를 건져 물기를 뺀 뒤 넓은 볼에 담는다.","imageUrl":null},{"step":6,"text":"알배추와 양파, 대파, 풋고추, 무청을 겉절이 양념에 골고루 버무린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409042946_1554794986601.jpg', 11.96, 2.53, 0.45, 0.01, 1.67),
  ('3083', '닭가슴살호두크로켓', '반찬', '닭가슴살 80g, 두부 20g, 양파 12.5g, 대파 5g, 호두 5g, 땅콩 2.5g, 마늘 2g, 생강 0.5g, 후추 0.3g, 설탕 3.8g, 식초 2.5g, 계란 65g(1.5개), 쌀가루 7g, 빵가루 25g, 순무 24g, 두유 45ml, 홀그레인 2.5g, 땅콩버터 5g, 레몬 7g, 파슬리 0.5g', '["닭가슴살","두부","양파","대파","호두","땅콩","마늘","생강","후추","설탕","식초","계란","쌀가루","빵가루","순무","두유","홀그레인","땅콩버터","레몬","파슬리"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','4566cac5-9166-4c0d-906a-bfc7360f8f5b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','7651578f-1206-499d-a04c-15f034d4cae2','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','c7d438a6-34d6-423f-905d-446b839e2f39','4cb11562-015f-4ab5-969f-0ea8483a0b42','45080597-55fa-42dc-aa65-12d7694e4b7e','a4e9789c-3090-43d8-ab14-e4e168f8b910','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','4362c386-a37c-44cd-9254-fafd74712a09']::uuid[], '[{"step":1,"text":"양파, 대파, 호두, 닭가슴살은 잘게 다진다.","imageUrl":null},{"step":2,"text":"①에 물기를 제거한 두부와 생강, 마늘, 후추를 섞어 반죽한다.","imageUrl":null},{"step":3,"text":"반죽을 쌀가루, 계란물, 빵가루 순으로 묻히고 튀겨 크로켓을 만든다.","imageUrl":null},{"step":4,"text":"믹서에 두부, 두유를 넣고 갈아 두부 마요네즈를 만든다.","imageUrl":null},{"step":5,"text":"순무와 양파는 다지고, 계란은 삶아 다져 준비한다.","imageUrl":null},{"step":6,"text":"두부 마요네즈에 ⑤의 재료와 설탕, 레몬, 식초, 땅콩버터, 후추, 홀그레인, 파슬리가루를 넣어 타르소스를 만든다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313023223_1584077543747.jpg', 623.5, 50.8, 43.8, 27.2, 312.9),
  ('3176', '누룽지상추샐러드&유자드레싱', '반찬', '누룽지 5g, 로메인상추 7.5g, 파프리카(빨간색/노란색) 12.5g, 유자청 7.5g, 식용유 500g, 올리브유 3.5g, 레몬즙 1g, 식초 1g, 후추 0.1g', '["누룽지","로메인상추","파프리카","유자청","식용유","올리브유","레몬즙","식초","후추"]'::jsonb, ARRAY['01e8d2cd-f98c-4ae3-a198-8b001bbf688e','5e79d288-1400-4817-bd20-e5e6041821b1','ff5b6cbe-7985-4ca2-94ad-5525717cddf1','a7a59e81-de3d-4893-b56a-b2218732a25b','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','6c285c60-022a-4a00-b172-87df97f16a2f','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"로메인 상추를 한 입 크기로 썬다.","imageUrl":null},{"step":2,"text":"파프리카는 사방 0.3cm 크기로 썬다.","imageUrl":null},{"step":3,"text":"누룽지를 튀긴 후 으깬다.","imageUrl":null},{"step":4,"text":"유자청, 레몬즙, 올리브유, 식초, 후추를 섞어 드레싱을 만든다.","imageUrl":null},{"step":5,"text":"로메인 상추 위에 파프리카와 튀긴 누룽지를 고명으로 올린다.","imageUrl":null},{"step":6,"text":"드레싱을 얹어 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210128/20210128055656_1611824216006.jpg', 105.56, 19.51, 0.67, 2.75, 8.32),
  ('3194', '견과류 미숫가루 빵', '기타', ' 강력분60g, 박력분 30g, 미숫가루 150g, 이스트 4g, 소금 5g, 달걀 50g(1개) , 버터 30g, 아몬드20g, 해바라기씨 30g, 호박씨 10g, 건포도 20g 
(아몬드우유) 아몬드 30g, 우유 180g 
(토핑) 버터10g, 아몬드 슬라이스10g, 미숫가루10g', '["강력분","박력분","미숫가루","이스트","소금","달걀","버터","아몬드","해바라기씨","호박씨","건포도","우유","아몬드 슬라이스"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','0b0eef9f-2fa0-4eb5-b1c4-5fc82d28a393','325279ee-6de6-4d84-96a0-16af87dfdbc6','2cf0c12b-f248-4012-8f53-303c730a7b3d','c7d438a6-34d6-423f-905d-446b839e2f39','7aabd532-361f-4240-aa33-6bfa1be4bc4e','52ba316f-8e7f-415f-8079-9a9d674c9adf','3d359f85-dafb-4490-a263-752f436e698b','1c1e5578-1128-45a4-bcaf-aae79de3639e','e937397f-54e2-49df-997a-f393c58360be']::uuid[], '[{"step":1,"text":"(아몬드우유) 믹서기에 아몬드와 우유를 갈아 아몬드 우유를 만든다.","imageUrl":null},{"step":2,"text":"밀가루, 미숫가루, 이스트, 소금, 달걀, 아몬드 우유를 넣어 손으로 반죽하다가 아몬드, 해바라기씨, 호박씨 넣고 반죽한다.","imageUrl":null},{"step":3,"text":"②이 한 덩어리가 되면 무염버터를 넣어 반죽을 하고 마지막으로 건포도를 넣어 섞는다.","imageUrl":null},{"step":4,"text":"\"크기가 2.5배가 될 때까지 1차 발효하고 반죽을 접어 공기를 빼고 3등분으로 나눠 둥글리기 후 10분 정도 중간 발효한다.\r\n★반죽이 달라붙으면 덧가루를 뿌리면서 작업하면 수월해요.\"","imageUrl":null},{"step":5,"text":"발효가 끝나면 다시 둥글리기를 해주고 반죽의 매끄러운 면이 위로 가도록 팬닝 후 40~50분 2차 발효 시킨다.","imageUrl":null},{"step":6,"text":"\"180℃ 오븐에서 20~25분 동안 구워서 완성시킨 뒤 위에 버터를 바르고 아몬드 슬라이스와 미숫가루로 토핑한다.\r\n★ 버터는 살짝 녹여 사용하세요.\"","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129052423_1611908663012.jpg', 353, 44.89, 12.56, 13.64, 5.64),
  ('3223', '돼지 함초 덮밥', '일품', '양파(10g), 쪽파(3g), 레몬(3g), 무순(20개), 멸치(7~8마리), 건함초(3g), 다시마(5g), 밥(210g), 꽈리고추(5개), 돼지고기(등심, 120g), 수란(1개), 김가루(2g), 고추냉이(2g), 마늘(3쪽), 생강(1톨), 건고추(3개), 팔각(1개), 참기름(1T), 후춧가루(⅓Ts), 식용유(20ml)', '["양파","쪽파","레몬","무순","멸치","건함초","다시마","밥","꽈리고추","돼지고기","수란","김가루","고추냉이","마늘","생강","건고추","팔각","참기름","후춧가루","식용유"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','f09d1d41-602a-441c-a7bc-520311490ceb','dd2eee03-8bbf-44ff-8a7f-ed1443986711','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','ecb35816-34ae-4c4c-867a-e3f84db92755','30b5d53c-d247-4f04-9b50-c0f728e65cf9','70e914d4-0d03-4202-8b66-81bd8499aa08','09229cbc-4574-4002-b726-68c37345bbe9','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','0c0ade94-cfd8-4104-b44c-40e942cac482','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"양파는 채 썰고, 쪽파는 송송 썰고, 레몬은 슬라이스하고, 마늘은 으깨고, 생강은 납작 썰고, 건고추는 굵게 부순다.","imageUrl":null},{"step":2,"text":"중간 불로 달군 마른 팬에 멸치를 넣어 3분간 볶아 수분을 날린 뒤 건함초, 다시마와 함께 믹서에 넣어 곱게 간다.","imageUrl":null},{"step":3,"text":"중간 불로 달군 팬에 식용유(20㎖)와 손질한 향신료를 넣고 3분간 볶아 향유를 만든다.","imageUrl":null},{"step":4,"text":"향유에 참기름과 후춧가루, 곱게 간 멸치가루를 넣어 섞은 뒤 밥에 넣어 고루 섞는다.","imageUrl":null},{"step":5,"text":"중간 불로 달군 팬에 남겨둔 향유(10g)를 두르고 꽈리고추와 돼지고기를 넣어 9분간 구운 뒤 돼지고기는 얇게 한입 크기로 썬다.","imageUrl":null},{"step":6,"text":"그릇에 비빔밥, 구운 돼지고기와 꽈리고추, 손질한 양파, 쪽파, 레몬, 김가루, 고추냉이, 무순, 수란을 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310093936_1615336776669.jpg', 816.8, 83.6, 43.3, 34.4, 498.9),
  ('3284', '닭가슴살 채소쌈', '일품', ' 양상추(3장), 양파(¼개), 토마토(중간 크기 1개), 청양고추(2개), 할라피뇨 피클(10개), 닭가슴살(270g), 단호박(1개), 라이스페이퍼(7장), 플레인 요거트(1컵), 마늘(3~4쪽), 대파(½대), 후춧가루(0.5ts), 카레가루(1Ts)', '["양상추","양파","토마토","청양고추","할라피뇨 피클","닭가슴살","단호박","라이스페이퍼","플레인 요거트","마늘","대파","후춧가루","카레가루"]'::jsonb, ARRAY['1389717e-81e4-4350-96d4-d627d851aa10','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','30b5d53c-d247-4f04-9b50-c0f728e65cf9','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','98d652af-a6d6-440c-9653-e22fc5d47d88','241e49d7-4aa4-4411-8ded-350a16b41222','bb41a88a-ea2b-4830-876d-91fe7f640296','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','495b9f1e-aa3b-4506-9bb8-feb0a493901e']::uuid[], '[{"step":1,"text":"양상추는 채 썰고, 양파와 토마토는 작게 한입 크기로 썰고, 청양고추와 할라피뇨 피클은 잘게 다진다.","imageUrl":null},{"step":2,"text":"냄비에 물(10컵), 닭가슴살, 닭가슴살 삶는 재료와 후춧가루(0.3ts)를 넣어 7분 정도 삶은 뒤 건져 얇게 찢는다.","imageUrl":null},{"step":3,"text":"호박은 4조각으로 잘라 씨를 제거하고, 찜기에 물(1컵)을 넣어 쪄내고, 껍질을 벗긴 뒤 물(1컵)을 부어가며 으깬다.","imageUrl":null},{"step":4,"text":"약한 불로 달군 팬에 으깬 단호박, 닭가슴살, 다진 청양고추, 카레가루, 후춧가루(0.2ts)를 넣어 수분이 날아갈 때까지 볶는다.","imageUrl":null},{"step":5,"text":"팬에 식용유(2컵)를 부은 뒤 중간 불로 예열하고, 라이스페이퍼를 넣어 튀긴 뒤 바로 건져낸다.","imageUrl":null},{"step":6,"text":"튀긴 라이스페이퍼에 단호박 볶음과 손질한 채소, 플레인 요거트를 올려 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr98WE', 266.3, 22.1, 23.7, 9.2, 349.1),
  ('3687', '콩감태유자 스콘', '후식', ' 삶은 병아리콩① 175g, 두유 210g, 코코넛오일 70g, 유자필 56g, 쌀가루 280g, 아몬드가루 105g, 감태가루 3.5g, 유자앙금 105g, 삶은 병아리콩② 50g', '["삶은 병아리콩①","두유","코코넛오일","유자필","쌀가루","아몬드가루","감태가루","유자앙금","삶은 병아리콩②"]'::jsonb, ARRAY['a4e9789c-3090-43d8-ab14-e4e168f8b910','4cb11562-015f-4ab5-969f-0ea8483a0b42','52ba316f-8e7f-415f-8079-9a9d674c9adf']::uuid[], '[{"step":1,"text":"믹서에 삶은 병아리콩①, 두유,\r\n코코넛오일을 넣고 곱게 간다.","imageUrl":null},{"step":2,"text":"볼에 담고 유자필을 넣어 섞는다.","imageUrl":null},{"step":3,"text":"쌀가루, 아몬드가루, 감태가루를 체 쳐서\r\n넣고 섞어 반죽을 만든다.","imageUrl":null},{"step":4,"text":"반죽은 10~12cm 크기의\r\n원형으로 성형하고,\r\n유자앙금과 삶은 병아리콩②를 섞어\r\n반죽 위에 올린다","imageUrl":null},{"step":5,"text":"4~5등분으로 자르고 오븐 팬에\r\n올린다.","imageUrl":null},{"step":6,"text":"175°C로 예열한 오븐에 170°C에서\r\n20분 동안 구워 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023093851_1761179931161.jpg', 228.3, 32.4, 6.4, 8.1, 29.7),
  ('997', '호두 사과 샐러드', '후식', '사과 60g, 샐러리 5g, 마요네즈 4g, 레몬주스 1g, 식초 1g, 호두 5g, 건포도 4g, 소금적당량', '["사과","샐러리","마요네즈","레몬주스","식초","호두","건포도","소금"]'::jsonb, ARRAY['c85a52b9-c3b4-4a76-951c-bb40edeb3adb','12d2d4c9-705a-47f1-b628-30e042a970f8','549c7365-28e9-491f-9040-412558f93a5c','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','6c285c60-022a-4a00-b172-87df97f16a2f','7651578f-1206-499d-a04c-15f034d4cae2','1c1e5578-1128-45a4-bcaf-aae79de3639e','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"사과는 4등분하고 씨를 제거한다.","imageUrl":null},{"step":2,"text":"1을 다시 4등분 한다.","imageUrl":null},{"step":3,"text":"셀러리는 껍질을 제거하고 슬라이스 한다.","imageUrl":null},{"step":4,"text":"마요네즈, 레몬주스, 식초, 소금을 섞어 드래싱을 만든다.","imageUrl":null},{"step":5,"text":"볼에 사과, 셀러리, 호두, 건포도를 넣는다.","imageUrl":null},{"step":6,"text":"5에 만들어 놓은 드래싱을 넣어 고루 섞는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053733_1416213453570.jpg', 110, 13.7, 1.2, 6.5, 31),
  ('998', '고구마란', '후식', '고구마 70g, 꿀 10g, 계피가루 2g, 대추 5g, 호박씨 5g', '["고구마","꿀","계피가루","대추","호박씨"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','286d1783-cd34-4aae-ac8b-006529ec8bc5','5205f393-c02b-4b09-a2d6-42629f7401b9','b371c5d2-f12b-47ee-9a87-26efd09db09d','3d359f85-dafb-4490-a263-752f436e698b']::uuid[], '[{"step":1,"text":"고구마는 껍질을 벗긴 후 큼직하게 썰어 찜통에 찐다.","imageUrl":null},{"step":2,"text":"다 쪄진 고구마를 체에 곱게 내린다.","imageUrl":null},{"step":3,"text":"2에 꿀과 계피가루를 넣어 섞는다.","imageUrl":null},{"step":4,"text":"대추는 씨를 제거한 뒤 0.5mm  마름모꼴로 자른다.","imageUrl":null},{"step":5,"text":"고구마를 조금씩 떼어 둥글게 빚는다.","imageUrl":null},{"step":6,"text":"호박씨와 썰어둔 대추로 꼭지를 만든다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053734_1416213454820.jpg', 166, 36.6, 2.9, 2.7, 13),
  ('999', '과일 파이', '후식', '오렌지 25g, 사과 25g, 설탕 15g, 물전분 4g, 버터 1g, 식빵 30g', '["오렌지","사과","설탕","물전분","버터","식빵"]'::jsonb, ARRAY['19eb37dc-2b1c-4e89-a931-31a38ae60561','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','06e6f3e7-0293-469d-a338-11a610f3e71b','6613d1d9-80a2-4ce4-9d3d-647203197e53','7aabd532-361f-4240-aa33-6bfa1be4bc4e','a18f6f83-06b8-473c-88b3-c2c8f2a7d0fc']::uuid[], '[{"step":1,"text":"오렌지는 껍질을 벗긴 뒤 잘게 썰고 사과는 껍질 째 깨끗하게 씻어서 잘게 썬다.","imageUrl":null},{"step":2,"text":"냄비에 오렌지와 사과를 각각 넣고 설탕을 넣어 중간 불에서 타지 않도록 졸인다.","imageUrl":null},{"step":3,"text":"졸이는 도중에 과일에서 나온 물로 질척해지면 물전분을 넣어 농도를 맞춘 뒤 차게 식힌다.","imageUrl":null},{"step":4,"text":"식빵은 가장자리를 잘라낸 다음 밀대로 납작하게 밀어 버터를 바른다.","imageUrl":null},{"step":5,"text":"졸인 과일을 얹고 돌돌 만 다음 양끝을 포크로 눌러 붙인다.","imageUrl":null},{"step":6,"text":"식빵의 표면에 버터를 얇게 바르고 170℃로 예열된 오븐에 넣어 노릇하게 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053735_1416213455900.jpg', 182, 38.7, 2.8, 2.4, 29),
  ('1000', '수삼당근정과', '후식', '당근 50g, 수삼 30g, 꿀 20g, 물 10g, 계피가루 2g', '["당근","수삼","꿀","물","계피가루"]'::jsonb, ARRAY['e38c12a7-43cb-421a-a36e-7ef0d32517fa','9f4dacdc-b7a6-43f9-ab9b-6a3b28042318','286d1783-cd34-4aae-ac8b-006529ec8bc5','94786475-832c-4f97-aab7-bf6fbbe2236b','5205f393-c02b-4b09-a2d6-42629f7401b9']::uuid[], '[{"step":1,"text":"당근과 수삼을 깨끗하게 씻는다.","imageUrl":null},{"step":2,"text":"1을 믹서에 넣고 곱게 간다.","imageUrl":null},{"step":3,"text":"냄비에 2를 붓고 꿀을 넣어 졸인다.","imageUrl":null},{"step":4,"text":"계피가루를 섞는다.","imageUrl":null},{"step":5,"text":"빵이나 크래커를 준비한다.","imageUrl":null},{"step":6,"text":"5의 위에 수삼 당근 정과를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053736_1416213456837.jpg', 110, 28.3, 2.1, 0.2, 23),
  ('1001', '식혜 팥빙수', '후식', '팥 10g, 찹쌀가루 15g, 쑥가루 5g, 물 10g, 식혜 110g, 소금 적당량', '["팥","찹쌀가루","쑥가루","물","식혜","소금"]'::jsonb, ARRAY['95fb950a-afb7-4a7f-a6b5-9b912d0e6462','4cb11562-015f-4ab5-969f-0ea8483a0b42','94786475-832c-4f97-aab7-bf6fbbe2236b','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"팥을 깨끗하게 씻어 물을 부어 끓인 뒤 물을 버리고 다시 찬물을 부어 삶는다.","imageUrl":null},{"step":2,"text":"부드럽게 삶아진 팥의 물기를 제거한 후 으깬다.","imageUrl":null},{"step":3,"text":"찹쌀가루를 둘로 나누어 하나는 쑥가루를 넣고 하나는 맨 찹쌀가루에 뜨거운 물로 익반죽 하여 경단을 만든 뒤 끓는 물에 익힌다.","imageUrl":null},{"step":4,"text":"익힌 경단을 바로 차가운 얼음물에 담궈 식힌다.","imageUrl":null},{"step":5,"text":"식혜에 으깬 팥을 넣고 소금 간을 한 뒤 그릇에 담아 냉동실에 얼리면서 1시간 마다 공기가 들어가도록 포크로 저어준다.","imageUrl":null},{"step":6,"text":"샤베트가 부드럽게 얼면 준비한 그릇에 경단과 함께 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053737_1416213457776.jpg', 136, 33, 3.6, 0, 5),
  ('1002', '야채칩', '후식', '연근 20g, 고구마 20g, 감자 20g, 단호박 20g, 당근 20g, 소금적당량', '["연근","고구마","감자","단호박","당근","소금"]'::jsonb, ARRAY['b20f623d-e722-42af-9bd1-7c11b5e15aa6','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','20894da1-739d-4d52-b5fe-4943bd3492d5','98d652af-a6d6-440c-9653-e22fc5d47d88','e38c12a7-43cb-421a-a36e-7ef0d32517fa','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"준비된 야채들을 깨끗이 씻는다.","imageUrl":null},{"step":2,"text":"연근, 고구마, 감자, 단호박, 당근은 0.2cm 두께로 썬다.","imageUrl":null},{"step":3,"text":"연근, 고구마, 감자는 물에 담궈 둔다.","imageUrl":null},{"step":4,"text":"오븐 팬에 썰어 놓은 재료를 넣고 소량의 소금을 뿌린다.","imageUrl":null},{"step":5,"text":"130~150℃로 예열한 오븐에 4를 굽는다.","imageUrl":null},{"step":6,"text":"구워진 야채칩을 식혀 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053738_1416213458618.jpg', 72, 17.7, 1.8, 0, 17),
  ('1003', '잡곡강정', '후식', '검은콩튀밥 10g, 쌀튀밥 10g, 메닐튀밥 10g, 물엿 6g, 설탕 6g, 물 3g', '["검은콩튀밥","쌀튀밥","메닐튀밥","물엿","설탕","물"]'::jsonb, ARRAY['cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"검은콩, 쌀, 메밀의 튀밥을 준비한다.","imageUrl":null},{"step":2,"text":"물엿에 설탕, 물을 넣고 약한불에서 투명하게 녹인다.","imageUrl":null},{"step":3,"text":"오목한 팬에 2를 넣는다.","imageUrl":null},{"step":4,"text":"3의 팬에 1을 넣고 시럽에서 실이 생길 때 까지 불 위에서 젓는다.","imageUrl":null},{"step":5,"text":"강정이 굳기 전에 타원형 모양으로 빚거나 밀대로 밀어 편다.","imageUrl":null},{"step":6,"text":"밀어 편 강정을 마름모 모양으로 자른다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053739_1416213459635.jpg', 153, 29.2, 5.5, 2.4, 10),
  ('1004', '잣 호두 강정', '후식', '잣 3g, 호두 3g, 대추 3g, 통깨 5g  물엿 3g, 설탕 2g', '["잣","호두","대추","통깨","설탕"]'::jsonb, ARRAY['bbbbd533-8922-4dac-9e4c-cd93ea710c92','7651578f-1206-499d-a04c-15f034d4cae2','b371c5d2-f12b-47ee-9a87-26efd09db09d','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"잣은 고깔을 떼어낸 뒤 젖은 행주로 문질러 먼지를 닦는다.","imageUrl":null},{"step":2,"text":"호두는 미지근한 물에 불려 껍질을 제거한다.","imageUrl":null},{"step":3,"text":"대추는 얇게 돌려 깎아 곱게 다진다.","imageUrl":null},{"step":4,"text":"물엿과 설탕을 냄비에 담고 물을 조금 넣은 뒤 약한불에서 투명한 시럽으로 만든다.","imageUrl":null},{"step":5,"text":"잣, 호두, 통깨에 다진 대추와 시럽을 넣고 덩어리지게 섞는다.","imageUrl":null},{"step":6,"text":"살짝 뜨거울 때 손으로 동그랗게 뭉쳐준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053740_1416213460828.jpg', 94, 7.9, 2.1, 6.8, 1),
  ('1005', '현미 크레이프', '후식', '현미가루 10g, 밀가루 20g, 우유 30g, 참기름적당량, 소금적당량 팥 15g, 설탕 10g  당근 20g, 설탕 10g, 물 5g', '["현미가루","밀가루","우유","참기름","소금적당량 팥","설탕","물"]'::jsonb, ARRAY['aab3b0b9-d346-4697-a1c8-1b1530153788','e937397f-54e2-49df-997a-f393c58360be','0c0ade94-cfd8-4104-b44c-40e942cac482','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"팥을 깨끗하게 씻어 끓인 뒤 물을 따라 버리고 다시 물을 부어 팥이 무르게 삶는다.","imageUrl":null},{"step":2,"text":"당근을 1cm 주사위 모양으로 자른다.","imageUrl":null},{"step":3,"text":"1, 2에 각각 설탕을 넣고 졸인다.","imageUrl":null},{"step":4,"text":"볼에 현미가루, 밀가루, 우유를 넣고 덩어리가 생기지 않도록 잘 갠 뒤 30분간 둔다.","imageUrl":null},{"step":5,"text":"가열된 팬에 참기름을 두르고 약한 불에서 4를 한 국자 정도 떠서 둥글게 부친 뒤 식힌다.","imageUrl":null},{"step":6,"text":"크레이프를 펴고 각각 팥소와 당근조림을 각각 얹은 후 둥글게 만다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053741_1416213461876.jpg', 259, 56.2, 7, 0.7, 42),
  ('1006', '감자 주먹밥', '밥', '감자 80g, 밥 80g, 당근다진것 20g, 시금치 20g, 잔멸치 5g, 삶은 달걀 노른자 5g, 검은깨 1g, 흰깨 2g 참기름 2g, 소금적당량, 흰 후춧가루 적당량', '["감자","밥","당근다진것","시금치","잔멸치","삶은 달걀 노른자","검은깨","흰깨","소금","흰 후춧가루"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','ecb35816-34ae-4c4c-867a-e3f84db92755','e38c12a7-43cb-421a-a36e-7ef0d32517fa','9a7f4da6-531b-4478-89ff-d73beafcad1b','dd2eee03-8bbf-44ff-8a7f-ed1443986711','c7d438a6-34d6-423f-905d-446b839e2f39','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"감자를 깨끗하게 씻어 찜통에 찐 뒤 껍질을 벗기고 체에 내린다.","imageUrl":null},{"step":2,"text":"기름 두른 팬에 다진 당근을 볶으면서 소금 간을 하고 시금치는 손질하여 데친 뒤 냉수에 헹궈 물기를 짜고 잘게 다진다.","imageUrl":null},{"step":3,"text":"잔멸치는 팬에 살짝 볶아서 굵직하게 다진다.","imageUrl":null},{"step":4,"text":"볼에 1, 2, 3, 4를 넣고 소금과 흰 후춧가루, 참기름을 넣고 섞는다.","imageUrl":null},{"step":5,"text":"삶은 달걀노른자를 체에 내린다.","imageUrl":null},{"step":6,"text":"4를 원형 또는 삼각형으로 만들어 달걀 노른자와 검은깨, 흰깨에 골고루 굴려 묻힌다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053743_1416213463031.jpg', 240, 41.9, 8.9, 5.6, 67),
  ('1007', '고기완두조림', '반찬', '돼지고기살코기 40g, 완두콩 30g, 물 5g, 육수 10g, 설탕 7g, 소금적당량, 전분 5g, 식용유 3g', '["돼지고기살코기","완두콩","물","육수","설탕","소금","전분","식용유"]'::jsonb, ARRAY['5fd34bed-4339-4fcc-9221-f082ce6ac652','94786475-832c-4f97-aab7-bf6fbbe2236b','a4c37075-c03b-47bb-8aed-5e907620f5d2','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d','6613d1d9-80a2-4ce4-9d3d-647203197e53','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"돼지고기는 손질한 뒤 완두콩 크기로 썬다.","imageUrl":null},{"step":2,"text":"완두콩을 믹서에 곱게 간다.","imageUrl":null},{"step":3,"text":"기름을 두른 팬에 1을 넣고 달라붙지 않게 볶는다.","imageUrl":null},{"step":4,"text":"2에 3과 설탕을 넣고 끓인다.","imageUrl":null},{"step":5,"text":"4에 소금으로 간을 한다.","imageUrl":null},{"step":6,"text":"물전분으로 소스의 농도를 맞춘다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053744_1416213464068.jpg', 183, 18.9, 11.4, 7, 45),
  ('1010', '니고랭', '일품', '달걀물 10g, 식용유 1g, 홍고추 3g, 마늘다진것 1g, 닭가슴살 12g, 새우 12g, 양파 12g, 청경채 20g, 스파게티면 40g, 방울토마토 15g, 버터 적당량 간장 3g, 발사믹식초 1g, 굴소스 2g, 꿀 3g', '["달걀물","식용유","홍고추","마늘다진것","닭가슴살","새우","양파","청경채","스파게티면","방울토마토","버터 적당량 간장","발사믹식초","굴소스","꿀"]'::jsonb, ARRAY['c7d438a6-34d6-423f-905d-446b839e2f39','a7a59e81-de3d-4893-b56a-b2218732a25b','30b5d53c-d247-4f04-9b50-c0f728e65cf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','6f10b4ad-53a2-4a07-ba89-19a6b074373d','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','b85df3ba-e324-47fa-b25d-d5bb552b8590','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','6c285c60-022a-4a00-b172-87df97f16a2f','d7e0d83c-010c-4b63-9ba4-fcd9af7cbac1','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"팬에 기름을 두르고 홍고추와 마늘을 향이 날 때까지 볶는다.","imageUrl":null},{"step":2,"text":"1에 달걀물을 넣고 달걀이 부드럽게 부풀어 오르도록 기다렸다가 반 정도 익었을 때 가볍게 젓는다.","imageUrl":null},{"step":3,"text":"2에 닭고기, 새우, 양파를 넣고 볶는다.","imageUrl":null},{"step":4,"text":"3에 준비된 스파게티면을 넣고 한 번 볶은 뒤 소야소스를 넣고 면에 간이 충분히 베이도록 볶는다.","imageUrl":null},{"step":5,"text":"면이 볶아지면 청경채, 방울토마토를 넣고 살짝 볶는다.","imageUrl":null},{"step":6,"text":"5에 차갑게 한 버터를 넣어 소스에 윤기와 농도가 나도록 한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053747_1416213467375.jpg', 229, 35.9, 11.5, 3.8, 310),
  ('1012', '돼지갈비 볶음', '반찬', '돼지갈비 60g, 굵은소금적당량, 마늘다진것 3g, 생강다진것 2g, 대파 10g, 토마토 25g 간장 5g, 물 10g, 식초 2g, 설탕 3g, 통깨 적당량, 참기름 적당량', '["돼지갈비","굵은소금","마늘다진것","생강다진것","대파","토마토","물","식초","설탕","통깨","참기름"]'::jsonb, ARRAY['2cf0c12b-f248-4012-8f53-303c730a7b3d','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','94786475-832c-4f97-aab7-bf6fbbe2236b','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"돼지갈비는 4cm 길이로 준비하여 기름기를 제거하고 찬물에 담가 핏물을 뺀다.","imageUrl":null},{"step":2,"text":"1에 굵은 소금을 넣고 주물러 갈비를 연하게 한 뒤 소금을 씻어낸다.","imageUrl":null},{"step":3,"text":"돼지갈비에 칼집을 넣은 뒤 대파, 마늘, 생강을 넣고 끓인 물에 데쳐서 헹군다.","imageUrl":null},{"step":4,"text":"냄비에 기름을 두르고 데쳐낸 갈비를 볶다가 양념장을 붓고 뚜껑을 덮어 서서히 익히면서 볶는다.","imageUrl":null},{"step":5,"text":"갈비에 간이 베이면 센불에서 저어주면서 윤기 나게 볶는다.","imageUrl":null},{"step":6,"text":"접시에 얇게 썬 토마토를 깔고 볶아낸 돼지갈비를 담은 뒤 통깨를 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053749_1416213469472.jpg', 151, 6.7, 12.1, 8.3, 293),
  ('1013', '미니 그라탕', '일품', '사과 50g, 참마 25g, 레몬주스 10g, 건포도 5g, 슬라이스아몬드 5g, 설탕 6g 참마 25g, 두유 40g, 물엿 5g, 밀가루 3g, 올리브오일 1g, 소금 적당량', '["사과","참마","레몬주스","건포도","슬라이스아몬드","설탕","두유","물엿","밀가루","올리브오일","소금"]'::jsonb, ARRAY['c85a52b9-c3b4-4a76-951c-bb40edeb3adb','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','1c1e5578-1128-45a4-bcaf-aae79de3639e','52ba316f-8e7f-415f-8079-9a9d674c9adf','06e6f3e7-0293-469d-a338-11a610f3e71b','a4e9789c-3090-43d8-ab14-e4e168f8b910','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','aab3b0b9-d346-4697-a1c8-1b1530153788','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"껍질을 벗기지 않은 사과와 반을 잘라 껍질을 벗긴 참마를 0.7cm 주사위모양으로 썬다.","imageUrl":null},{"step":2,"text":"사과에 레몬주스, 소금을 넣고 부드러워질 때 까지 익힌 뒤 참마를 넣고 살짝 끓인다.","imageUrl":null},{"step":3,"text":"나머지 참마는 껍질을 벗긴 뒤 토막내 두유, 물엿, 밀가루, 올리브오일과 같이 믹서에 간다.","imageUrl":null},{"step":4,"text":"3이 퓨레 상태가 되면 약 불에서 걸쭉하게 졸인다.","imageUrl":null},{"step":5,"text":"2에 건포도를 섞은 뒤 틀에 담고 4를 펴서 얹고 그 위에 슬라이스 아몬드와 설탕을 뿌린다.","imageUrl":null},{"step":6,"text":"200℃로 예열한 오븐에서 표면이 노릇해 질 때 까지 약 10분 간 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053750_1416213470534.jpg', 236, 44.6, 6.3, 5.6, 58),
  ('1014', '밀라노 스타일 포크 커틀렛', '반찬', '돼지등심 60g, 밀가루 4g, 달걀 12g, 빵가루 4.5g, 바질 0.5g, 건타임 0.5g, 버터 0.5g, 식용유 1g, 레몬 5g, 파마산치즈 2g, 소금 적당량, 후추 적당량', '["돼지등심","밀가루","달걀","빵가루","바질","건타임","버터","식용유","레몬","파마산치즈","소금","후추"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','45080597-55fa-42dc-aa65-12d7694e4b7e','ba9e5a79-cab3-4af0-942b-0b35fd745150','7aabd532-361f-4240-aa33-6bfa1be4bc4e','a7a59e81-de3d-4893-b56a-b2218732a25b','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"돼지고기(등심)을 고기망치로 두드려 1cm 정도 두께로 편다.","imageUrl":null},{"step":2,"text":"돼지등심에 소금, 후추로 간을 한다.","imageUrl":null},{"step":3,"text":"파마산치즈, 빵가루, 건바질, 타임을 섞어 허브 빵가루를 만든다.","imageUrl":null},{"step":4,"text":"고기에 밀가루, 달걀물, 허브 빵가루 순으로 묻힌다.","imageUrl":null},{"step":5,"text":"가열한 팬에 기름을 두르고 커틀렛을 익힌다.","imageUrl":null},{"step":6,"text":"커틀렛이 익으면 기름을 빼고 그릇에 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053751_1416213471597.jpg', 229, 7.6, 13.8, 15.1, 98),
  ('1015', '바지락 볶음면', '일품', '바지락살 20g, 칵테일새우 20g, 청고추 5g, 홍고추 5g, 대파 10g, 마늘다진것 3g, 생강다진것 2g, 칼국수면 80g, 식용유 적당량, 물전분 4g멸치육수 50g, 간장 5g, 설탕 5g, 양파즙 5g, 다진 파 5g, 다진 마늘 3g, 참기름 2g, 깨소금 1g, 소금 적당량, 후춧가루 적당량', '["바지락살","칵테일새우","청고추","홍고추","대파","마늘다진것","생강다진것","칼국수면","식용유","물전분","간장","설탕","양파즙","다진 파","다진 마늘","참기름","깨소금","소금","후춧가루"]'::jsonb, ARRAY['b6047d76-6c94-4757-b1d1-9175aea0c84a','6f10b4ad-53a2-4a07-ba89-19a6b074373d','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','a7a59e81-de3d-4893-b56a-b2218732a25b','6613d1d9-80a2-4ce4-9d3d-647203197e53','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"바지락살과 새우는 소금물에 흔들어 씻어 체에 받쳐 물기를 제거한다.","imageUrl":null},{"step":2,"text":"대파, 청, 홍고추는 송송 썰고, 마늘, 생강은 다진다.","imageUrl":null},{"step":3,"text":"끓는 물에 칼국수 면을 삶아 냉수에 헹군 뒤 참기름으로 버무린다.","imageUrl":null},{"step":4,"text":"멸치 육수에 분량의 재료를 넣고 간장 소스를 만든다.","imageUrl":null},{"step":5,"text":"팬에 식용유를 두르고 다진 마늘, 생강, 고추를 넣어 볶다가 센 불에서 바지락살과 새우, 청주를 넣어 볶은 뒤 간장소스를 넣고 끓인다.","imageUrl":null},{"step":6,"text":"5가 반정도 졸면 칼국수 면을 넣어 볶으면서 물전분으로 농도를 맞춘 뒤 송송 썬 파와 참기름을 넣고 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053752_1416213472408.jpg', 235, 36.3, 12.6, 4, 448),
  ('2995', '삼색 꽃 화전', '반찬', '찹쌀가루 60g, 시금치 30g, 치자 5g, 식용꽃 5g, 타임 5g, 설탕 15g, 꿀 20g', '["찹쌀가루","시금치","치자","식용꽃","타임","설탕","꿀"]'::jsonb, ARRAY['4cb11562-015f-4ab5-969f-0ea8483a0b42','9a7f4da6-531b-4478-89ff-d73beafcad1b','06e6f3e7-0293-469d-a338-11a610f3e71b','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"시금치는 데친 뒤 믹서에 곱게 갈고 치자는 따뜻한 물에 불린다.","imageUrl":null},{"step":2,"text":"곱게 간 시금치에 데쳤던 물을 넣고 가열한 뒤 찹쌀가루 절반에 조금씩 부어 익반죽 한다.","imageUrl":null},{"step":3,"text":"남은 절반의 찹쌀가루에 가열한 치자물을 조금씩 부어 익반죽 한다.","imageUrl":null},{"step":4,"text":"30분 간 휴지시킨 뒤 팬에 기름을 두르고 적당한 크기로 빚은 화전을 지진다.","imageUrl":null},{"step":5,"text":"한쪽 면을 익힐 때 위에 꽃을 올린 뒤 뒤집어 살짝만 지진다.","imageUrl":null},{"step":6,"text":"꿀과 설탕, 물을 1:2:3 비율로 섞어 끓여 시럽을 만들어 화전 위에 끼얹고 타임으로 장식한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20190409/20190409044713_1554796033713.jpg', 160.6, 22.36, 2.11, 6.97, 1.31),
  ('3085', '알록달록연근튀김', '반찬', '깐연근 22.18g, 비트 2.12g, 시금치 2.12g, 카레가루 1.52g, 건새우 0.3g, 전분 2.25g, 튀김가루 4.25g, 소금 0.05g, 식물성기름 500ml', '["깐연근","비트","시금치","카레가루","건새우","전분","튀김가루","소금","식물성기름"]'::jsonb, ARRAY['524e1b82-1f81-4648-b50c-441404a06786','9a7f4da6-531b-4478-89ff-d73beafcad1b','495b9f1e-aa3b-4506-9bb8-feb0a493901e','6f10b4ad-53a2-4a07-ba89-19a6b074373d','6613d1d9-80a2-4ce4-9d3d-647203197e53','aab3b0b9-d346-4697-a1c8-1b1530153788','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"연근은 얇게 썰어 찬물에 담가 전분기를 제거한다.","imageUrl":null},{"step":2,"text":"건새우는 곱게 갈아준다.","imageUrl":null},{"step":3,"text":"시금치, 비트는 각각 믹서기에 갈아 즙을 준비한다.","imageUrl":null},{"step":4,"text":"튀김가루에 새우가루와 물을 넣어 반죽을 한다.","imageUrl":null},{"step":5,"text":"반죽에 시금치, 카레, 비트를 각각 넣어 3가지 색의 반죽을 만든다.","imageUrl":null},{"step":6,"text":"연근에 전분가루를 묻히고 튀김옷을 입혀 바삭하게 튀겨낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313045226_1584085946623.JPG', 66.9, 10.2, 1.1, 2.4, 103.4),
  ('3087', '잎채소튀김', '반찬', '깻잎 5g, 상추 6g, 배추 7g, 계란 10g, 튀김가루 10g, 콩기름 5g, 얼음', '["깻잎","상추","배추","계란","튀김가루","콩기름","얼음"]'::jsonb, ARRAY['3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','1389717e-81e4-4350-96d4-d627d851aa10','e116f85b-0eaa-40cb-8107-df5ec8486ad4','c7d438a6-34d6-423f-905d-446b839e2f39','aab3b0b9-d346-4697-a1c8-1b1530153788','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"볼에 튀김가루, 계란 물을 섞어 반죽을 만든 후 얼음을 넣어 차갑게 한다.","imageUrl":null},{"step":2,"text":"깻잎, 상추, 배추는 깨끗하게 씻어 준비한다.","imageUrl":null},{"step":3,"text":"재료를 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":4,"text":"냄비에 콩기름을 부은 후 적당한 온도가 될 때까지 가열한다.","imageUrl":null},{"step":5,"text":"야채에 반죽을 입힌다.","imageUrl":null},{"step":6,"text":"노릇하게 튀긴다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20200313/20200313054031_1584088831750.jpg', 222.6, 10.2, 2.3, 19.2, 70.5),
  ('3179', '포항초사과샐러드', '반찬', '포항초 20g, 사과 5g, 당근 2g, 양파 2g, 파프리카 1g, 레몬즙(또는 식초) 0.2g, 저염간장 0.4g, 설탕 0.2g', '["포항초","사과","당근","양파","파프리카","레몬즙","저염간장","설탕"]'::jsonb, ARRAY['c85a52b9-c3b4-4a76-951c-bb40edeb3adb','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"포항초는 세척하고 3cm 크기로 자른다.","imageUrl":null},{"step":2,"text":"당근은 얇게 채 썰어주고, 사과는 껍질 채로 채 썰어 설탕물에 담가 둔다.","imageUrl":null},{"step":3,"text":"양파와 파프리카는 작은 큐브 모양으로 썬다.","imageUrl":null},{"step":4,"text":"저염간장, 레몬즙, 설탕, 양파, 파프리카를 넣어 오리엔탈 드레싱을 만든다.","imageUrl":null},{"step":5,"text":"포항초에 당근과 사과를 넣어 섞어준다.","imageUrl":null},{"step":6,"text":"샐러드에 오리엔탈 드레싱을 곁들여 제공한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210129/20210129103512_1611884112461.JPG', 10.34, 1.52, 0.77, 0.13, 15.81),
  ('3224', '생선 파피요트', '일품', '양파(⅓개), 파프리카(⅓개), 레몬(1개), 방울토마토(4개), 손질된 흰살생선(½마리), 대하(2마리), 바지락(4개), 월계수잎(3장), 타임(4~5줄기), 소금(2g), 후춧가루(1g), 화이트와인(15g), 올리브유(10g)', '["양파","파프리카","레몬","방울토마토","손질된 흰살생선","대하","바지락","월계수잎","타임","소금","후춧가루","화이트와인","올리브유"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','b6047d76-6c94-4757-b1d1-9175aea0c84a','043a9631-bb6e-42e6-9673-4943457502fb','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','e16eaf50-ebd3-4933-a774-3ce6fc92593f','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc']::uuid[], '[{"step":1,"text":"양파, 파프리카는 채 썰고, 레몬은 얇게 썰고, 방울토마토는 2등분한다.","imageUrl":null},{"step":2,"text":"손질된 흰살생선에 밑간한다.","imageUrl":null},{"step":3,"text":"종이 포일에 채 썬 양파를 깐 뒤 밑간한 생선 → 손질한 파프리카 → 레몬 → 방울토마토 순으로 올린다.","imageUrl":null},{"step":4,"text":"대하, 바지락, 월계수잎, 타임을 올린 뒤 화이트와인과 올리브유를 뿌린다.","imageUrl":null},{"step":5,"text":"종이 포일로 감싸고 200℃로 예열한 오븐에 15~25분간 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20210310/20210310094914_1615337354153.jpg', 162, 9.5, 22.1, 4, 881.6),
  ('3285', '시금치 후무스', '기타', ' 대파(15cm), 시금치(1줌=60g), 불린 병아리콩(½컵), 우유(1컵), 올리브유(0.5Ts), 천일염(0.5Ts), 라임즙(0.3Ts), 백후춧가루(약간), 넛맥가루(약간)', '["대파","시금치","불린 병아리콩","우유","올리브유","천일염","라임즙","백후춧가루","넛맥가루"]'::jsonb, ARRAY['4b410642-7bf9-45ad-9055-e7d9a34edaa1','9a7f4da6-531b-4478-89ff-d73beafcad1b','e937397f-54e2-49df-997a-f393c58360be','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"대파는 송송 썰고, 시금치는 깨끗하게 씻어 물기를 제거한다.","imageUrl":null},{"step":2,"text":"약한 불로 달군 팬에 올리브유를 두른 뒤 불린 병아리콩을 넣고 3분간 볶는다.","imageUrl":null},{"step":3,"text":"물(5컵)을 부어 중간 불로 삶고, 물이 졸아들면 우유를 넣은 뒤 양이 절반이 될 때까지 졸인다.","imageUrl":null},{"step":4,"text":"끓는 소금물(물5컵+천일염0.5Ts)에 시금치를 넣어 5분간 데치고, 찬물에 담가 헹군 뒤 물기를 꼭 짠다.","imageUrl":null},{"step":5,"text":"믹서에 병아리콩조림, 데친 시금치, 라임즙, 백후춧가루, 넛맥가루를 넣어 곱게 갈아 마무리한다.","imageUrl":null}]'::jsonb, 'https://www.foodsafetykorea.go.kr/common/ecmFileView.do?ecm_file_no=1NxSkgr98fz', 195.8, 27.3, 9.4, 5.4, 34.5),
  ('3688', '클로－바', '후식', ' 귀리 100g, 아몬드슬라이스 25g, 피칸 25g, 땅콩버터 25g, 클로렐라가루 7.5g, 알룰로스 50g, 코코넛우유 45ml, 아몬드우유 80ml, 대추채 12.5g, 카카오닙스 25g, 건크랜베리 12.5g, 카카오매스 40g, 다크초콜릿 25g', '["귀리","아몬드슬라이스","피칸","땅콩버터","클로렐라가루","알룰로스","코코넛우유","아몬드우유","대추채","카카오닙스","건크랜베리","카카오매스","다크초콜릿"]'::jsonb, ARRAY['c15a4a69-31ab-450d-943a-2a7bb2230857','52ba316f-8e7f-415f-8079-9a9d674c9adf','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d']::uuid[], '[{"step":1,"text":"프라이팬에 물에 불린 귀리,\r\n아몬드슬라이스, 피칸을 넣고 살짝\r\n볶는다.","imageUrl":null},{"step":2,"text":"볼에 땅콩버터, 클로렐라가루,\r\n알룰로스를 넣고 섞다가 코코넛우유,\r\n아몬드우유를 넣어 고루 섞는다.","imageUrl":null},{"step":3,"text":"볶은 귀리, 아몬드슬라이스, 피칸과\r\n대추채, 카카오닙스, 건크랜베리를 넣고\r\n섞어 크런치 토핑을 만든다.","imageUrl":null},{"step":4,"text":"볼에 카카오매스, 다크초콜릿을\r\n넣고 전자레인지에서 20~25초 동안\r\n녹인다.","imageUrl":null},{"step":5,"text":"팬에 유산지를 깔고 크런치 토핑을\r\n넣고 평평하게 편 후 녹인 초콜릿을\r\n코팅하듯 바른다.","imageUrl":null},{"step":6,"text":"냉동실에 20분 동안 넣어 굳히고\r\n먹기 좋은 크기로 썰어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20251023/20251023095232_1761180752387.jpg', 143.7, 20.5, 3.7, 5.2, 3.3),
  ('743', '매생이조랭이떡국', '국&찌개', '조랭이떡 140g, 매생이 15g, 굴 30g, 파 5g, 다진 마늘 2g, 국멸치 3g, 국간장 1g, 소금 0.2g, 물 300g', '["조랭이떡","매생이","굴","파","다진 마늘","국멸치","국간장","소금","물"]'::jsonb, ARRAY['842f1298-903f-48e9-93bf-41bd90abfa9a','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','dd2eee03-8bbf-44ff-8a7f-ed1443986711','f175019d-5a93-4cd4-aabc-e7e79445f15a','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"냄비에 물 1컵 반과 국멸치를 넣고 끓여 멸치국물 1컵을 낸다.","imageUrl":null},{"step":2,"text":"매생이는 물로 서너 번 헹궈 고운체에 받쳐 물기를 제거한다.","imageUrl":null},{"step":3,"text":"굴에 소금을 넣고 으깨지지 않도록 살살 주무른 후 물로 서너 번 헹궈 체에 받친다.","imageUrl":null},{"step":4,"text":"파는 얇게 어슷썰고, 마늘은 다진다.","imageUrl":null},{"step":5,"text":"멸치국물에 조랭이떡, 매생이, 굴을 넣고 끓인다.","imageUrl":null},{"step":6,"text":"파와 다진 마늘을 넣고 한소끔 끓이고, 국간장과 소금으로 간하여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102002_1416273602643.jpg', 380.8, 77.3, 11.2, 2.1, 637.3),
  ('744', '문어핫바', '후식', '문어 50g, 톳 5g, 감자 20g, 당근 5g, 양파 5g, 우리밀가루 20g, 다진 마늘 2g, 후춧가루 0.1g, 토마토케첩 5g, 허니머스터드소스 5g, 현미유 5g', '["문어","톳","감자","당근","양파","우리밀가루","다진 마늘","후춧가루","토마토케첩","허니머스터드소스","현미유"]'::jsonb, ARRAY['55a34ec2-28ee-407c-8ad5-7462cbe99d55','f3f07b4b-1a27-4a6d-be6d-09e58352e063','20894da1-739d-4d52-b5fe-4943bd3492d5','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','0136fc6a-3a80-4f4c-8057-10bbf34ea572','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"손질한 문어를 데친다.","imageUrl":null},{"step":2,"text":"양파와 감자를 적당한 크기로 자르고 톳과 당근은 잘게 다진다.","imageUrl":null},{"step":3,"text":"데친 문어와 양파, 감자를 믹서기에 넣고 간다.","imageUrl":null},{"step":4,"text":"2와 3에 우리밀가루, 다진 마늘, 후춧가루를 넣고 반죽을 치대 직사각형 모양을 만든다.","imageUrl":null},{"step":5,"text":"팬에 현미유를 두르고 4의 문어를 넣고 지진 후 꼬치에 끼운다.","imageUrl":null},{"step":6,"text":"토마토케첩과 허니머스터드소스를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102003_1416273603782.jpg', 191.5, 22.3, 11, 6.7, 324.6),
  ('745', '매실장아찌와 과매기구이', '반찬', '과메기 60g, 매실장아찌 15g, 양파 5g, 다진 생강 1g, 마늘 1g 고추장 10g, 양파 5g, 다진 마늘 3g, 다진 파 3g, 간장 2g, 매실액 2g, 고춧가루 1g, 물 15g, 통깨 0.1g, 후춧가루 0.1g', '["과메기","매실장아찌","양파","다진 생강","마늘","다진 마늘","다진 파","간장","매실액","고춧가루","물","통깨","후춧가루"]'::jsonb, ARRAY['61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','f175019d-5a93-4cd4-aabc-e7e79445f15a','02fd7135-0ec3-49ec-82e3-390536ab2cf5','84104c49-0af4-4323-a56b-b67002a422d9','94786475-832c-4f97-aab7-bf6fbbe2236b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"과메기는 꼬리를 잘라낸다.","imageUrl":null},{"step":2,"text":"다진 생강과 마늘즙을 내어 손질한 과메기 위에 뿌린다.","imageUrl":null},{"step":3,"text":"고추장, 다진 마늘, 다진 파, 매실액, 고춧가루, 후춧가루, 물을 섞어 양념장을 만든다.","imageUrl":null},{"step":4,"text":"매실장아찌는 채썬다.","imageUrl":null},{"step":5,"text":"팬에 과메기를 놓고 고추장양념을 발라가며 살짝 굽는다.","imageUrl":null},{"step":6,"text":"매실장아찌를 구운 과메기위에 올려 마무리한다.","imageUrl":null}]'::jsonb, NULL, 230.2, 16.7, 13.5, 12.1, 412.7),
  ('747', '자색고구마호떡', '후식', '찹쌀 30g, 자색고구마 20g, 소금 0.2g, 현미유 3g, 물 17g 황설탕 7g, 검정깨 2g, 땅콩 2g, 호두 2g, 찹쌀가루 0.5g, 계피가루 0.2g,', '["찹쌀","자색고구마","소금","현미유","물","검정깨","땅콩","호두","찹쌀가루","계피가루"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','2cf0c12b-f248-4012-8f53-303c730a7b3d','a7a59e81-de3d-4893-b56a-b2218732a25b','94786475-832c-4f97-aab7-bf6fbbe2236b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','7651578f-1206-499d-a04c-15f034d4cae2','4cb11562-015f-4ab5-969f-0ea8483a0b42','5205f393-c02b-4b09-a2d6-42629f7401b9']::uuid[], '[{"step":1,"text":"찹쌀을 3~5시간 불린 후 물기를 제거하고 믹서기에 간다.","imageUrl":null},{"step":2,"text":"고구마는 껍질을 벗기고 작게 썰어 찜통에 넣고 찐 후 으깬다.","imageUrl":null},{"step":3,"text":"검정깨는 믹서기에 갈고, 호두와 땅콩은 굵게 다지고 황설탕과 찹쌀가루를 함께 섞어 호떡소를 만든다.","imageUrl":null},{"step":4,"text":"으깬 고구마에 찹쌀가루를 넣고 반죽을 한다.","imageUrl":null},{"step":5,"text":"4의 반죽을 동그랗게 빚어 3의 호떡소를 넣고 둥글납작하게 만든다.","imageUrl":null},{"step":6,"text":"팬에 현미유를 두르고 호떡을 눌러가며 앞뒤로 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102008_1416273608450.jpg', 229.2, 38.4, 3.7, 6.5, 71.9),
  ('748', '김치밥그라탕', '밥', '밥 180, 배추김치(줄기부분) 30, 양파 20, 생 표고버섯 40, 방울토마토 200, 올리브유 12, 간장 4, 피자치즈(모짜렐라) 30, 다진 실파 5', '["밥","배추김치","양파","생 표고버섯","방울토마토","올리브유","간장","피자치즈","다진 실파"]'::jsonb, ARRAY['ecb35816-34ae-4c4c-867a-e3f84db92755','133f214e-50f4-431d-af36-d97f6c9d4f9b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','f175019d-5a93-4cd4-aabc-e7e79445f15a','4b410642-7bf9-45ad-9055-e7d9a34edaa1']::uuid[], '[{"step":1,"text":"김치, 양파, 버섯은 다진다.","imageUrl":null},{"step":2,"text":"방울토마토는 4등분한다.","imageUrl":null},{"step":3,"text":"팬에 올리브유를 두르고 김치, 양파, 버섯, 토마토를 볶는다.","imageUrl":null},{"step":4,"text":"밥을 넣어 볶은 뒤 간장으로 간한다.","imageUrl":null},{"step":5,"text":"3, 4를 그릇에 담고 피자치즈를 올려 전자렌지에 치즈가 녹을 정도로 익힌다.","imageUrl":null},{"step":6,"text":"실파를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102011_1416273611901.jpg', 515.1, 69.3, 14.5, 18.9, 679.8),
  ('749', '누룽지굴죽', '밥', '굴 50, 누룽지 50, 다시마국물(건다시마 2, 물 450), 부추 10, 간장 3, 참기름 2, 파래김 0.5', '["굴","누룽지","다시마국물","부추","간장","참기름","파래김"]'::jsonb, ARRAY['842f1298-903f-48e9-93bf-41bd90abfa9a','01e8d2cd-f98c-4ae3-a198-8b001bbf688e','a4c37075-c03b-47bb-8aed-5e907620f5d2','058648c3-fd8e-476d-952f-b15dc67f1877','f175019d-5a93-4cd4-aabc-e7e79445f15a','0c0ade94-cfd8-4104-b44c-40e942cac482']::uuid[], '[{"step":1,"text":"굴은 소금물에 흔들어 씻어 굵게 다진다.","imageUrl":null},{"step":2,"text":"부추는 씻어 송송 썬다.","imageUrl":null},{"step":3,"text":"누룽지에 다시마국물을 넣고 2분간 불린 뒤 끓인다.","imageUrl":null},{"step":4,"text":"누룽지가 거의 퍼졌을 때 굴을 넣고 살짝 끓인다.","imageUrl":null},{"step":5,"text":"죽이 퍼지면 부추를 넣고 잠시 끓인다.","imageUrl":null},{"step":6,"text":"그릇에 담고 구운 파래김을 부스러뜨려 얹어낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102012_1416273612744.jpg', 239.3, 47.9, 8.4, 2.9, 337.6),
  ('750', '콩비지완자탕', '국&찌개', '완자: 콩비지 50, 다진 돼지고기(기름기 없는 부위) 25, 깍두기 5, 새우젓 2.5, 계란 5, 감자전분 10, 후추 0.02, 다진 파 4, 다진 마늘 2 국물: 멸치다시마국물(물 300, 건멸치 2.5, 건다시마 2), 청경채 20, 어슷 썬 대파 5, 다진 마늘 1, 국간장 5', '["완자: 콩비지","다진 돼지고기","깍두기","새우젓","계란","감자전분","후추","다진 파","다진 마늘","청경채","어슷 썬 대파","국간장"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','8f2077de-dbd0-4372-a4c2-f987388f16b3','c7d438a6-34d6-423f-905d-446b839e2f39','6613d1d9-80a2-4ce4-9d3d-647203197e53','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"콩비지를 체에 받혀 물기를 제거한다.","imageUrl":null},{"step":2,"text":"깍두기와 새우젓을 잘게 다진다.","imageUrl":null},{"step":3,"text":"1에 다진 돼지고기, 깍두기, 새우젓, 계란, 전분, 후추, 파, 마늘을 넣고 치댄다.","imageUrl":null},{"step":4,"text":"치댄 반죽을 한입 크기로 동그랗게 완자를 빚는다.","imageUrl":null},{"step":5,"text":"냄비에 멸치다시마 국물을 넣고 끓으면 완자를 넣어 거품을 걷어가며 끓인다.","imageUrl":null},{"step":6,"text":"완자가 익어서 떠오르면 청경채, 대파, 마늘을 넣고 살짝 끓여 국간장으로 간하여 불에서 내린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102014_1416273614929.jpg', 154.6, 16.5, 9.7, 5, 699),
  ('751', '돼지갈비구이와 백김치와인조림', '반찬', '주재료: 돼지등갈비 200(갈비살 70), 물 500, 된장 2, 대파 10, 생강 3, 올리브유 4, 후추 0.02, 소금 0.38 김치조림: 백김치 60, 적포도주 40, 맛술 15, 꿀 3', '["주재료: 돼지등갈비","물","된장","대파","생강","올리브유","후추","소금","적포도주","맛술","꿀"]'::jsonb, ARRAY['94786475-832c-4f97-aab7-bf6fbbe2236b','392236b1-82e9-4e38-bd12-6a53b80bf463','4b410642-7bf9-45ad-9055-e7d9a34edaa1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','2cf0c12b-f248-4012-8f53-303c730a7b3d','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','286d1783-cd34-4aae-ac8b-006529ec8bc5']::uuid[], '[{"step":1,"text":"냄비에 물을 넣고 된장을 풀어 대파, 생강을 넣고 끓인다.","imageUrl":null},{"step":2,"text":"물이 끓으면 돼지갈비를 넣고 5분간 삶는다.","imageUrl":null},{"step":3,"text":"백김치는 5cm 길이로 자른다.","imageUrl":null},{"step":4,"text":"적포도주를 냄비에 넣고 불에 올려 알코올을 날려준 뒤 김치, 맛술, 꿀을 넣고 맛이 배도록 졸인다.","imageUrl":null},{"step":5,"text":"삶아 낸 등갈비에 소금을 뿌리고 올리브유를 발라 팬에 구워낸다.","imageUrl":null},{"step":6,"text":"구운 갈비에 백김치 와인조림을 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102015_1416273615804.jpg', 252, 13.1, 13.8, 13.7, 446.7),
  ('752', '오징어오곡밥순대', '반찬', '주재료: 오징어 30, 오곡밥 30, 데친 취나물 10, 간장 3, 다진 마늘 2.5, 후추 0.01, 참기름 1 소스: 데쳐서 다진 취나물 5, 청양고추 2, 간장 1.5, 참기름 1, 설탕 1, 다진 마늘 1, 된장 0.75', '["주재료: 오징어","오곡밥","데친 취나물","간장","다진 마늘","후추","참기름","청양고추","설탕","된장"]'::jsonb, ARRAY['f175019d-5a93-4cd4-aabc-e7e79445f15a','fc6e31ce-388e-45cd-956b-b238b9134eb1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','0c0ade94-cfd8-4104-b44c-40e942cac482','30b5d53c-d247-4f04-9b50-c0f728e65cf9','06e6f3e7-0293-469d-a338-11a610f3e71b','392236b1-82e9-4e38-bd12-6a53b80bf463']::uuid[], '[{"step":1,"text":"오징어는 다리를 떼 내서 내장과 눈을 제거하고, 데친 취나물은 물기를 짜내고 다진다.","imageUrl":null},{"step":2,"text":"오곡밥에 다진 취나물, 간장, 마늘, 후추, 참기름을 넣어 고루 섞는다.","imageUrl":null},{"step":3,"text":"오징어 몸통에 양념한 밥을 넣어 이쑤시개로 끝을 고정시킨다.","imageUrl":null},{"step":4,"text":"김이 오른 찜통에 오징어를 넣고 3분간 쪄낸다.","imageUrl":null},{"step":5,"text":"소스 재료를 섞어 취나물된장소스를 만든다.","imageUrl":null},{"step":6,"text":"쪄낸 오징어순대를 썰어 접시에 담고 소스를 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102016_1416273616990.jpg', 105, 12.5, 7.8, 2.6, 617.2),
  ('753', '코다리 양념구이', '반찬', '주재료: 코다리 50, 누룽지가루 7.5, 콩기름 4, 다진 홍고추 2, 다진 실파 2 양념장: 간장 3, 설탕 1.5, 맛술 1.25, 고운 고추가루 1, 간 양파 5, 다진 마늘 1', '["주재료: 코다리","누룽지가루","콩기름","다진 홍고추","다진 실파","설탕","맛술","고운 고추가루","간 양파","다진 마늘"]'::jsonb, ARRAY['a7a59e81-de3d-4893-b56a-b2218732a25b','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','06e6f3e7-0293-469d-a338-11a610f3e71b','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"코다리는 배를 갈라 길이로 2등분하여 뼈를 제거한다.","imageUrl":null},{"step":2,"text":"손질한 코다리를 반으로 잘라 안쪽에 누룽지 가루를 묻힌다.","imageUrl":null},{"step":3,"text":"분량의 재료를 섞어 양념장을 만든다.","imageUrl":null},{"step":4,"text":"팬에 기름을 두르고 코다리를 굽는다.","imageUrl":null},{"step":5,"text":"코다리에 양념장을 발라 다시 한번 살짝 굽는다.","imageUrl":null},{"step":6,"text":"다진 홍고추와 실파를 뿌려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102018_1416273618224.jpg', 133, 10, 12.1, 5.1, 258.1),
  ('754', '대구버섯구이', '반찬', '주재료: 대구살 60, 소금 0.3, 흰후추 0.02, 찹쌀가루 12, 새송이버섯 40, 마늘 2, 올리브유 6, 베이비채소 5 소스: 마요네즈 4, 와사비 갠 것1, 레몬즙 2, 후추 0.02', '["주재료: 대구살","소금","흰후추","찹쌀가루","새송이버섯","마늘","올리브유","베이비채소","와사비 갠 것","레몬즙","후추"]'::jsonb, ARRAY['2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','4cb11562-015f-4ab5-969f-0ea8483a0b42','3f94371a-728f-49ae-8ea9-1a1e87b68048','fc6e31ce-388e-45cd-956b-b238b9134eb1','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"대구살에 소금, 흰후추를 뿌려 밑간 한 뒤 찹쌀가루를 가볍게 묻힌다. (a)","imageUrl":null},{"step":2,"text":"버섯과 마늘을 얇게 썬다. (b)","imageUrl":null},{"step":3,"text":"팬에 기름을 두르고 마늘을 볶아 향을 낸 뒤 마늘은 따로 건져두고 버섯을 굽는다. (c)","imageUrl":null},{"step":4,"text":"팬에 기름을 두르고 1을 앞뒤로 노릇하게 굽는다. (d)","imageUrl":null},{"step":5,"text":"분량의 재료를 섞어 소스를 만든다.","imageUrl":null},{"step":6,"text":"접시에 대구, 버섯, 마늘을 켜켜이 담아 소스를 뿌리고 베이비채소를 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102019_1416273619379.jpg', 197.9, 14.9, 13.3, 9.5, 237.6),
  ('755', '잔멸치땅콩볶음', '반찬', '땅콩 10, 잔멸치 10, 맛술 2.5, 올리브유 2, 건홍고추 1, 참기름 1, 콩기름 1, 다진 마늘 1, 굴소스 0.3, 두반장 1, 물엿 6, 통깨 0.5', '["땅콩","잔멸치","맛술","올리브유","건홍고추","참기름","콩기름","다진 마늘","굴소스","두반장","물엿","통깨"]'::jsonb, ARRAY['02c78319-0bf6-45e0-8a7b-7546e1e47ba7','dd2eee03-8bbf-44ff-8a7f-ed1443986711','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','0c0ade94-cfd8-4104-b44c-40e942cac482','a7a59e81-de3d-4893-b56a-b2218732a25b','fc6e31ce-388e-45cd-956b-b238b9134eb1','d7e0d83c-010c-4b63-9ba4-fcd9af7cbac1','fb9d40e3-96b9-4a0f-bd38-734bb6ca6b12','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"멸치를 마른팬에 넣고 볶는다.","imageUrl":null},{"step":2,"text":"살짝 볶아낸 멸치에 올리브유와 맛술을 넣고 부드러워질 때까지 볶는다.","imageUrl":null},{"step":3,"text":"땅콩을 찬물에 20분 담갔다 체에 건져 물기를 뺀다.","imageUrl":null},{"step":4,"text":"건고추는 송송 썬다.","imageUrl":null},{"step":5,"text":"팬에 올리브유, 참기름, 콩기름을 섞어 두르고 다진 마늘을 넣어 향을 낸 후 땅콩과 고추를 넣어 볶는다.","imageUrl":null},{"step":6,"text":"볶은 멸치와 굴소스, 두반장, 물엿을 넣고 고루 섞은 다음 통깨를 뿌려낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141118/20141118102020_1416273620679.jpg', 145.6, 7.8, 7.4, 9.8, 352.7),
  ('1016', '밥 샌드위치', '일품', '맛살 50g, 마요네즈 3g, 오이 25g, 밥 120g, 치즈슬라이스 20g, 검은깨 2g, 소금 적당량', '["맛살","마요네즈","오이","밥","치즈슬라이스","검은깨","소금"]'::jsonb, ARRAY['549c7365-28e9-491f-9040-412558f93a5c','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','ecb35816-34ae-4c4c-867a-e3f84db92755','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"맛살을 잘게 다져 마요네즈와 소금을 넣고 버무린다.","imageUrl":null},{"step":2,"text":"오이는 다져서 소금을 뿌려 놓았다가 면보에 짜서 수분을 제거한 뒤 마요네즈에 버무린다.","imageUrl":null},{"step":3,"text":"밥에 소금을 넣어 버무린다.","imageUrl":null},{"step":4,"text":"네모난 플라스틱 통에 랩을 깐다.","imageUrl":null},{"step":5,"text":"4에 밥, 치즈, 밥, 오이나 맛살, 밥 순서로 얹어 꼭꼭 누른다.","imageUrl":null},{"step":6,"text":"랩을 통째로 꺼내 칼로 조심스럽게 썰어 검은깨로 장식한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053753_1416213473486.jpg', 322, 50.6, 14.9, 8.1, 476),
  ('1017', '버섯을 넣은 가지 라자냐', '일품', '돼지고기다진것 12g, 느타리벗서 15g, 표고버섯 10g, 새송이버섯 15g, 가지 15g, 밀가루 6g, 버터 0.5g, 우유 25g, 파마산치즈 3g, 모짜렐라 치즈 7g, 토마토소스 20g, 바질 2g, 오레가노 0.5g, 빵가루 4g', '["돼지고기다진것","느타리벗서","표고버섯","새송이버섯","가지","밀가루","버터","우유","파마산치즈","모짜렐라 치즈","토마토소스","바질","오레가노","빵가루"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','66458b1b-c92f-43fa-8eba-e428892ce88a','3f94371a-728f-49ae-8ea9-1a1e87b68048','3e12cf79-2cde-4309-9f7c-4eccce3fde28','aab3b0b9-d346-4697-a1c8-1b1530153788','7aabd532-361f-4240-aa33-6bfa1be4bc4e','e937397f-54e2-49df-997a-f393c58360be','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','76e95535-f965-4685-a7a6-55ae26aa202c','ba9e5a79-cab3-4af0-942b-0b35fd745150','cdbae946-7ca4-4f8d-8a3c-5bb295961ad6','45080597-55fa-42dc-aa65-12d7694e4b7e']::uuid[], '[{"step":1,"text":"가지에 세로로 칼집을 넣어 소금을 뿌린다.","imageUrl":null},{"step":2,"text":"표고버섯, 느타리버섯은 채 썰고 새송이버섯은 세로로 자른다.","imageUrl":null},{"step":3,"text":"돼지고기를 곱게 다진 뒤 볶는다.","imageUrl":null},{"step":4,"text":"팬에 버터를 넣어 녹으면 밀가루를 넣고 볶아서 루를 만든 뒤 우유를 넣어 화이트소스를 만든다.","imageUrl":null},{"step":5,"text":"오븐용기에 화이트소스를 깔고 그 위에 가지를 올린 뒤 가지 사이에 버섯, 토마토소스, 화이트소스, 버섯을 넣는다.","imageUrl":null},{"step":6,"text":"남은 화이트소스와 치즈, 빵가루 순으로 얹고 180℃로 예열된 오븐에서 윗면이 노릇한 색이 나도록 굽는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053754_1416213474657.jpg', 136, 14.8, 8.1, 5.1, 243),
  ('1019', '생선찜 채소말이', '반찬', '흰살 생선 70g, 죽순 20g, 청피망 15g, 홍피망 15g, 건표고버섯 10g, 전분 5g, 치즈슬라이스 10g, 참기름 적당량, 소금 적당량, 흰후춧가루 적당량 잣 3g, 물 4g, 설탕 3g, 레몬즙 3g, 간장 2g, 소금적당량', '["흰살 생선","죽순","청피망","홍피망","건표고버섯","전분","치즈슬라이스","참기름","소금","흰후춧가루 적당량 잣","물","설탕","레몬즙","간장"]'::jsonb, ARRAY['df459e6f-3515-45d5-8c9a-9d37b6249379','66458b1b-c92f-43fa-8eba-e428892ce88a','6613d1d9-80a2-4ce4-9d3d-647203197e53','0c0ade94-cfd8-4104-b44c-40e942cac482','2cf0c12b-f248-4012-8f53-303c730a7b3d','94786475-832c-4f97-aab7-bf6fbbe2236b','06e6f3e7-0293-469d-a338-11a610f3e71b','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"흰 살 생선을 얇게 포를 떠서 소금과 흰 후춧가루로 밑간을 한 뒤 생선살의 물기를 제거한다.","imageUrl":null},{"step":2,"text":"죽순은 5cm 길이로 채 썬 뒤 끓는 물에 데쳐 소금과 참기름으로 무치고 청, 홍피망은 같은 길이로 채썰어 팬에 볶으면서 소금 간 한다.","imageUrl":null},{"step":3,"text":"건 표고버섯을 불려서 얇게 포를 떠 채 썬 뒤 소금과 참기름으로 무쳐서 볶고 슬라이스 치즈도 같은 길이로 채 썬다.","imageUrl":null},{"step":4,"text":"1의 생선살을 2장씩 겹쳐 놓고 전분을 위에 뿌려 준비한 속 재료를 올려 돌돌 말아준 뒤 겉면에서 전분을 묻혀 찜통에서 8분간 찐다.","imageUrl":null},{"step":5,"text":"믹서에 잣과 물, 설탕, 소금, 레몬즙, 간장을 넣고 뽀얗게 즙이 나도록 소스를 만든다.","imageUrl":null},{"step":6,"text":"완성된 찜에 소스를 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053756_1416213476798.jpg', 163, 1838, 15.5, 3.4, 346),
  ('1020', '쇠고기말이 쌈밥', '밥', '쇠고기살코기 40g, 당근 10g, 오이피클 10g, 양파 15g, 깻잎 10g, 밥 50g, 전분 6g, 식용유 적당량깨소금 2g, 참기름 2g, 소금 적당량 간장 2g, 청주 2g, 참기름 1g, 후춧가루 적당량', '["쇠고기살코기","당근","오이피클","양파","깻잎","밥","전분","식용유 적당량깨소금","참기름","소금 적당량 간장","청주","후춧가루"]'::jsonb, ARRAY['e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','ecb35816-34ae-4c4c-867a-e3f84db92755','6613d1d9-80a2-4ce4-9d3d-647203197e53','0c0ade94-cfd8-4104-b44c-40e942cac482','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"소고기는 살코기로 손바닥 크기로 얇게 저며 양념에 재운다.","imageUrl":null},{"step":2,"text":"당근과 양파는 채 썰어 팬에 볶으면서 소금으로 간한다.","imageUrl":null},{"step":3,"text":"오이피클은 물기를 제거하여 채 썰고 깻잎은 깨끗이 씻어 물기를 뺀다.","imageUrl":null},{"step":4,"text":"밥을 고슬고슬하게 지어 밑간을 하고 준비한 당근과 양파, 오이피클을 넣고 잘 섞어 한 입 크기로 뭉쳐 놓는다.","imageUrl":null},{"step":5,"text":"밑간한 소고기를 넓게 펴고 전분을 뿌린 뒤 깻잎을 깔고 준비한 밥을 올려 싼다.","imageUrl":null},{"step":6,"text":"팬에 식용유를 두르고 말아놓은 쌈밥을 굴려가며 소고기가 익을 때 까지 익힌다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20141117/20141117053757_1416213477943.jpg', 204, 27.5, 11.3, 6, 354)
